}
.nuda-flower-spinner span:nth-child(6) {
  animation: nuda-flower-petal-300 1.8s ease-in-out infinite 0.75s;
  transform: translate(-50%, -50%) rotate(300deg) translateY(-14px);
}

@keyframes nuda-flower-petal-0 {
