@keyframes nuda-dualglow-a { to { transform: rotate(360deg); } }
@keyframes nuda-dualglow-b { to { transform: rotate(360deg); } }

@media (prefers-reduced-motion: reduce) {
  .nuda-dualglow span { animation: none; opacity: 0.6; }
}

