/* Segment Spinner
   Eight segments fading in sequence around a circle (iOS-style).
   Each segment is positioned via an inline transform; opacity is animated.
   Customize: --segspin-color */

.nuda-segspin {
  --segspin-color: #e4ff54;
  position: relative;
