  border-radius: 2px;
  background: var(--segspin-color);
  transform-origin: center;
  animation: nuda-segspin 0.8s linear infinite;
  will-change: opacity;
}

@keyframes nuda-segspin {
  0%   { opacity: 1; }
  100% { opacity: 0.15; }
}

@media (prefers-reduced-motion: reduce) {
