  top: 50%;
  left: 50%;
  width: 7px;
  height: 7px;
  margin: -3.5px;
  border-radius: 50%;
  background: var(--dotscircle-color);
  animation: nuda-dotscircle 1s ease-in-out infinite;
  will-change: transform;
