.nuda-segmented-steps__seg.is-on::after {
  content: '';
  position: absolute;
  inset: 0;
  background: var(--segsteps-color);
  border-radius: 4px;
  transform-origin: left center;
  animation: nuda-segmented-steps 0.4s ease-out both;
