   ──────────────────────────────────────────────────────────── */
.nuda-scramble {
  --nuda-scr-font: monospace;
  --nuda-scr-size: 1.8rem;

  font-family: var(--nuda-scr-font);
  font-size: var(--nuda-scr-size);
  font-weight: 700;
  letter-spacing: 0.05em;
  display: inline-block;
