@media (prefers-reduced-motion: reduce) {
  .nuda-stroke-fill {
    animation: none;
    -webkit-text-fill-color: var(--nuda-sf-clr);
  }
}

/* ── Bouncy Letters ──────────────────────────────────────────
   Customize:
     --nuda-bl-height   : bounce peak height
     --nuda-bl-speed    : bounce cycle duration
     --nuda-bl-stagger  : delay between each letter
   ──────────────────────────────────────────────────────────── */
.nuda-bouncy-letters {
