  btn.classList.add('is-holding');
  timer = setTimeout(() => {
    btn.classList.add('is-confirmed');
    btn.dispatchEvent(new CustomEvent('confirm'));
  }, 1400);
};

const cancel = () => {
  btn.classList.remove('is-holding');
