/* ── OTP Inputs ──────────────────────────────────────────────
   Each box glows and lifts on focus.
   Customize: --nuda-otp-clr for the focus accent.
   ──────────────────────────────────────────────────────────── */
.nuda-otp {
  --nuda-otp-clr: #e4ff54;
  display: inline-flex;
  gap: 10px;
}

.nuda-otp__box {
  width: 46px;
