/* ── Password Meter ──────────────────────────────────────────
   data-strength (0–3) drives both the scaleX fill and the color.
   ──────────────────────────────────────────────────────────── */
.nuda-pwd-meter {
  display: flex;
  flex-direction: column;
  gap: 8px;
  width: 240px;
}

.nuda-pwd-meter__input {
  width: 100%;
  padding: 10px 14px;
  background: #0c0c10;
  color: #fafafa;
  border: 1px solid rgba(255, 255, 255, 0.18);
  border-radius: 10px;
  font-size: 14px;
  outline: none;
  transition: border-color 0.25s ease;
}

.nuda-pwd-meter__input:focus { border-color: #e4ff54; }

.nuda-pwd-meter__track {
  position: relative;
  height: 6px;
  border-radius: 99px;
  background: #2a2a32;
  overflow: hidden;
}

.nuda-pwd-meter__fill {
  position: absolute;
  left: 0;
  top: 0;
  bottom: 0;
  width: 100%;
  border-radius: 99px;
  transform: scaleX(0);
  transform-origin: left;
  background: #ff5e7a;
  transition: transform 0.35s cubic-bezier(0.65, 0, 0.35, 1), background 0.35s ease;
}

.nuda-pwd-meter[data-strength="1"] .nuda-pwd-meter__fill { transform: scaleX(0.34); background: #ff5e7a; }
.nuda-pwd-meter[data-strength="2"] .nuda-pwd-meter__fill { transform: scaleX(0.67); background: #ffb45e; }
.nuda-pwd-meter[data-strength="3"] .nuda-pwd-meter__fill { transform: scaleX(1); background: #e4ff54; }

/* ── Accessibility ──────────────────────────────────────── */
@media (prefers-reduced-motion: reduce) {
  .nuda-pwd-meter__fill,
  .nuda-pwd-meter__input { transition: none; }
}

/* ── Password Meter — vanilla JS ─────────────────────────────
   Scores the password and sets data-strength (0–3) on the wrapper.
   ──────────────────────────────────────────────────────────── */
(function () {
  document.querySelectorAll(".nuda-pwd-meter").forEach(function (meter) {
    var input = meter.querySelector(".nuda-pwd-meter__input");
    if (!input) return;
    input.addEventListener("input", function () {
      var v = input.value;
      var s = 0;
      if (v.length >= 6) s++;
      if (/[A-Z]/.test(v) || /[0-9]/.test(v)) s++;
      if (/[^A-Za-z0-9]/.test(v) && v.length >= 10) s++;
      meter.setAttribute("data-strength", String(s));
    });
  });
})();

/* ── Tilt Card ───────────────────────────────────────────────
   The tilt is JS-driven via CSS custom properties.
   Customize:
     --nuda-tc-bg      : card background
     --nuda-tc-clr     : text color
     --nuda-tc-radius  : corner radius
     --nuda-tc-shadow  : box shadow
   ──────────────────────────────────────────────────────────── */
.nuda-tilt-card {
  --nuda-tc-bg: linear-gradient(135deg, #1e1b4b, #312e81);
  --nuda-tc-clr: #e0e7ff;
  --nuda-tc-radius: 16px;
  --nuda-tc-shadow: 0 8px 32px rgba(0, 0, 0, 0.3);
  --nuda-tc-rx: 0deg;
  --nuda-tc-ry: 0deg;

  width: 280px;
  perspective: 800px;
}

.nuda-tilt-card__content {
  padding: 32px 24px;
  background: var(--nuda-tc-bg);
  border-radius: var(--nuda-tc-radius);
  color: var(--nuda-tc-clr);
  text-align: center;
  box-shadow: var(--nuda-tc-shadow);
  transform: rotateX(var(--nuda-tc-rx)) rotateY(var(--nuda-tc-ry));
  transition: transform 0.15s ease;
  will-change: transform;
}

.nuda-tilt-card__icon {
  font-size: 2rem;
  margin-bottom: 8px;
}

.nuda-tilt-card__title {
  font-size: 1.1rem;
  font-weight: 700;
  margin: 0;
}

.nuda-tilt-card__desc {
  font-size: 0.85rem;
  opacity: 0.7;
  margin: 6px 0 0;
}

/* ── Accessibility ──────────────────────────────────────── */
@media (prefers-reduced-motion: reduce) {
  .nuda-tilt-card__content {
    transition: none;
    transform: none !important;
  }
}

/* ── Tilt Card — vanilla JS ──────────────────────────────────
   Applies 3D tilt via CSS custom properties based on cursor
   position. Respects prefers-reduced-motion.
   ──────────────────────────────────────────────────────────── */
;(function () {
  if (window.matchMedia("(prefers-reduced-motion: reduce)").matches) return;

  var maxTilt = 15; /* degrees */

  document.querySelectorAll(".nuda-tilt-card").forEach(function (card) {
    var content = card.querySelector(".nuda-tilt-card__content");
    if (!content) return;

    card.addEventListener("mousemove", function (e) {
      var rect = card.getBoundingClientRect();
      var x = (e.clientX - rect.left) / rect.width;   /* 0 → 1 */
      var y = (e.clientY - rect.top) / rect.height;    /* 0 → 1 */

      var rotateX = (0.5 - y) * maxTilt;  /* tilt up/down */
      var rotateY = (x - 0.5) * maxTilt;  /* tilt left/right */

      content.style.setProperty("--nuda-tc-rx", rotateX + "deg");
      content.style.setProperty("--nuda-tc-ry", rotateY + "deg");
    });

    card.addEventListener("mouseleave", function () {
      content.style.setProperty("--nuda-tc-rx", "0deg");
      content.style.setProperty("--nuda-tc-ry", "0deg");
    });
  });
})();

/* ── Border Glow ─────────────────────────────────────────────
   Outer wrapper = animated gradient, inner = card body.
   Customize:
     --nuda-bg-gradient  : border gradient
     --nuda-bg-card-bg   : inner card background
     --nuda-bg-clr       : text color
     --nuda-bg-border    : border width (padding on outer)
     --nuda-bg-radius    : corner radius
     --nuda-bg-speed     : animation cycle
   ──────────────────────────────────────────────────────────── */
.nuda-border-glow {
  --nuda-bg-gradient: linear-gradient(135deg, #6366f1, #ec4899, #f59e0b, #6366f1);
  --nuda-bg-card-bg: #0f0f23;
