/* Count Badge
   Number badge with bounce-in animation.
   Customize: --badge-bg, --badge-fg */

.nuda-count-badge {
  --badge-bg: #ef4444;
  --badge-fg: #fff;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-width: 22px;
  height: 22px;
  padding: 0 6px;
  background: var(--badge-bg);
  color: var(--badge-fg);
  font-size: 11px;
  font-weight: 700;
  border-radius: 11px;
  animation: nuda-count-bounce 0.5s cubic-bezier(0.36, 1.4, 0.65, 1) both;
  will-change: transform;
}

.nuda-count-badge--accent {
  --badge-bg: #6366f1;
}

.nuda-count-badge--large {
  min-width: 30px;
  height: 26px;
  padding: 0 8px;
  font-size: 12px;
  border-radius: 13px;
}

@keyframes nuda-count-bounce {
  0% { transform: scale(0) rotate(-12deg); }
  60% { transform: scale(1.2) rotate(4deg); }
  100% { transform: scale(1) rotate(0deg); }
}

@media (prefers-reduced-motion: reduce) {
  .nuda-count-badge { animation: none; }
}

/* Tag Slide
   Tags that slide in from the left.
   Stagger with animation-delay on each tag. */

.nuda-tag-slide {
  display: inline-flex;
  align-items: center;
  padding: 4px 10px;
  background: rgba(255, 255, 255, 0.06);
  border: 1px solid rgba(255, 255, 255, 0.1);
  border-radius: 6px;
  font-size: 12px;
  color: #ccc;
  animation: nuda-tag-slide-in 0.4s cubic-bezier(0.22, 1, 0.36, 1) both;
}

@keyframes nuda-tag-slide-in {
  0% {
    opacity: 0;
    transform: translateX(-16px);
  }
  100% {
    opacity: 1;
    transform: translateX(0);
  }
}

@media (prefers-reduced-motion: reduce) {
  .nuda-tag-slide { animation: none; }
}

/* Shimmer Badge
   Badge with shimmer sweep effect.
   Customize: gradient colors */

.nuda-shimmer-badge {
  display: inline-flex;
  align-items: center;
  padding: 4px 14px;
  background: linear-gradient(135deg, #6366f1, #8b5cf6);
  border-radius: 20px;
  font-size: 12px;
  font-weight: 700;
  letter-spacing: 0.06em;
  color: #fff;
  position: relative;
  overflow: hidden;
}

.nuda-shimmer-badge::after {
  content: '';
  position: absolute;
  top: 0;
  left: -100%;
  width: 60%;
  height: 100%;
  background: linear-gradient(
    90deg,
    transparent,
    rgba(255, 255, 255, 0.25),
    transparent
  );
  animation: nuda-shimmer-sweep 2.5s ease-in-out infinite;
  will-change: left;
}

@keyframes nuda-shimmer-sweep {
  0% { left: -100%; }
  50%, 100% { left: 150%; }
}

@media (prefers-reduced-motion: reduce) {
  .nuda-shimmer-badge::after { animation: none; }
}

/* Dot Badge
   Minimal dot badge with pulse.
   Customize: data-color attribute values */

.nuda-dot-badge {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  font-size: 13px;
  color: #ccc;
}

.nuda-dot-badge__dot {
  width: 7px;
  height: 7px;
  border-radius: 50%;
  position: relative;
}

.nuda-dot-badge[data-color="red"] .nuda-dot-badge__dot {
  background: #ef4444;
}

.nuda-dot-badge[data-color="green"] .nuda-dot-badge__dot {
  background: #22c55e;
}

.nuda-dot-badge__dot::after {
  content: '';
  position: absolute;
  inset: 0;
  border-radius: 50%;
  background: inherit;
  animation: nuda-dot-ping 1.8s ease-out infinite;
  will-change: transform, opacity;
}

@keyframes nuda-dot-ping {
