/* Underline Nav
   Nav links with sliding underline indicator.
   Customize: --nav-accent, --nav-text, --nav-text-hover */

.nuda-underline-nav {
  --nav-accent: #e4ff54;
  --nav-text: #999;
  --nav-text-hover: #fff;
  display: flex;
  gap: 2rem;
  position: relative;
  padding-bottom: 2px;
}

.nuda-underline-nav__link {
  color: var(--nav-text);
  text-decoration: none;
  font-size: 0.9rem;
  padding: 0.5rem 0;
  position: relative;
  transition: color 0.3s ease;
}

.nuda-underline-nav__link::after {
  content: '';
  position: absolute;
  bottom: 0;
  left: 0;
  width: 100%;
  height: 2px;
  background: var(--nav-accent);
  transform: scaleX(0);
  transition: transform 0.3s ease;
  transform-origin: left;
}

.nuda-underline-nav__link:hover {
  color: var(--nav-text-hover);
}

.nuda-underline-nav__link:hover::after,
.nuda-underline-nav__link.active::after {
  transform: scaleX(1);
}

.nuda-underline-nav__link.active {
  color: var(--nav-text-hover);
}

@media (prefers-reduced-motion: reduce) {
