/* Fade Tooltip
   Tooltip that fades in on hover above the trigger.
   Customize: --tooltip-bg, --tooltip-text, --tooltip-radius */

.nuda-fade-tooltip-wrap {
  position: relative;
  display: inline-block;
}

.nuda-fade-tooltip__trigger {
  background: rgba(255, 255, 255, 0.08);
  border: 1px solid rgba(255, 255, 255, 0.12);
  color: #ccc;
  padding: 0.45rem 1rem;
  border-radius: 8px;
  font-size: 0.85rem;
  cursor: pointer;
}

.nuda-fade-tooltip {
  --tooltip-bg: #1a1a1a;
  --tooltip-text: #ccc;
  --tooltip-radius: 6px;
  position: absolute;
  bottom: calc(100% + 8px);
  left: 50%;
  transform: translateX(-50%);
  background: var(--tooltip-bg);
  border: 1px solid rgba(255, 255, 255, 0.1);
  color: var(--tooltip-text);
  font-size: 0.75rem;
  padding: 0.4rem 0.75rem;
  border-radius: var(--tooltip-radius);
  white-space: nowrap;
  opacity: 0;
  pointer-events: none;
  transition: opacity 0.2s ease;
}

.nuda-fade-tooltip-wrap:hover .nuda-fade-tooltip {
  opacity: 1;
}

@media (prefers-reduced-motion: reduce) {
  .nuda-fade-tooltip {
    transition: none;
  }
}

/* Scale Tooltip
   Tooltip that scales up from origin point on hover.
   Customize: --tooltip-bg, --tooltip-text */

.nuda-scale-tooltip-wrap {
  position: relative;
  display: inline-block;
}

.nuda-scale-tooltip__trigger {
  background: rgba(255, 255, 255, 0.08);
  border: 1px solid rgba(255, 255, 255, 0.12);
  color: #ccc;
  padding: 0.45rem 1rem;
  border-radius: 8px;
  font-size: 0.85rem;
  cursor: pointer;
}

.nuda-scale-tooltip {
  --tooltip-bg: #1a1a1a;
  --tooltip-text: #ccc;
  position: absolute;
  bottom: calc(100% + 8px);
  left: 50%;
  background: var(--tooltip-bg);
  border: 1px solid rgba(255, 255, 255, 0.1);
  color: var(--tooltip-text);
  font-size: 0.75rem;
  padding: 0.4rem 0.75rem;
  border-radius: 6px;
  white-space: nowrap;
  opacity: 0;
  transform: translateX(-50%) scale(0.85);
  transform-origin: center bottom;
  pointer-events: none;
  transition: opacity 0.2s ease, transform 0.2s ease;
}

.nuda-scale-tooltip-wrap:hover .nuda-scale-tooltip {
  opacity: 1;
  transform: translateX(-50%) scale(1);
}

@media (prefers-reduced-motion: reduce) {
  .nuda-scale-tooltip {
    transition: none;
  }
}

