/* Slide Drawer — Toggle with .is-open class */

(function () {
  var backdrop = document.getElementById('drawer-backdrop');
  if (!backdrop) return;

  var closeBtn = backdrop.querySelector('.nuda-drawer__close');

  function close() {
    backdrop.classList.remove('is-open');
  }

  if (closeBtn) closeBtn.addEventListener('click', close);

  backdrop.addEventListener('click', function (e) {
    if (e.target === backdrop) close();
  });

  document.addEventListener('keydown', function (e) {
    if (e.key === 'Escape') close();
  });
})();

/* Dropdown Menu
   Animated dropdown with scale + fade entrance.
   Customize: --dropdown-bg, --dropdown-accent */

.nuda-dropdown {
  position: relative;
  display: inline-block;
}

.nuda-dropdown__trigger {
  background: rgba(255, 255, 255, 0.06);
  border: 1px solid rgba(255, 255, 255, 0.1);
  border-radius: 8px;
  padding: 0.5rem 1rem;
  color: #ccc;
  font-size: 0.85rem;
  cursor: pointer;
  transition: background 0.2s;
}

.nuda-dropdown__trigger:hover {
  background: rgba(255, 255, 255, 0.1);
}

.nuda-dropdown__menu {
  position: absolute;
  top: calc(100% + 4px);
  left: 0;
  min-width: 160px;
  background: #141414;
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 10px;
  padding: 0.25rem;
  opacity: 0;
  visibility: hidden;
  transform: translateY(-6px) scale(0.97);
  transform-origin: top left;
  transition: opacity 0.2s ease, transform 0.2s ease, visibility 0.2s ease;
  z-index: 100;
}

.nuda-dropdown.is-open .nuda-dropdown__menu {
  opacity: 1;
  visibility: visible;
  transform: translateY(0) scale(1);
}

.nuda-dropdown__item {
  display: block;
  padding: 0.5rem 0.75rem;
  border-radius: 6px;
  color: #ccc;
  font-size: 0.8rem;
  text-decoration: none;
  transition: background 0.15s;
}

.nuda-dropdown__item:hover {
  background: rgba(255, 255, 255, 0.06);
  color: #fff;
