  border-radius: 16px 16px 0 0;
  padding: 1rem 1.5rem 2rem;
  max-height: 80vh;
  overflow-y: auto;
  transform: translateY(100%);
  transition: transform 0.4s cubic-bezier(0.16, 1, 0.3, 1);
}

.nuda-bsheet-backdrop.is-open .nuda-bsheet {
  transform: translateY(0);
}

.nuda-bsheet__handle {
  width: 36px;
