  color: #999;
}

@media (prefers-reduced-motion: reduce) {
  .nuda-bsheet-backdrop,
  .nuda-bsheet {
    transition: none;
  }
}

/* Bottom Sheet — Toggle with .is-open class */

(function () {
  var backdrop = document.getElementById('bottom-sheet');
  if (!backdrop) return;

  function close() {
    backdrop.classList.remove('is-open');
  }

  backdrop.addEventListener('click', function (e) {
    if (e.target === backdrop) close();
  });

  document.addEventListener('keydown', function (e) {
    if (e.key === 'Escape') close();
  });

  // To open: backdrop.classList.add('is-open');
})();

/* Popover
   Click-triggered popover with arrow.
   Customize: --pop-bg, --pop-border */

.nuda-popover {
  position: relative;
  display: inline-block;
}

.nuda-popover__trigger {
  background: rgba(228, 255, 84, 0.1);
  border: 1px solid rgba(228, 255, 84, 0.2);
  border-radius: 8px;
  padding: 0.5rem 1rem;
  color: #e4ff54;
  font-size: 0.85rem;
  cursor: pointer;
}

.nuda-popover__content {
  position: absolute;
  bottom: calc(100% + 8px);
  left: 50%;
  transform: translateX(-50%) translateY(4px);
  background: #1a1a1a;
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 10px;
  padding: 0.75rem 1rem;
  min-width: 180px;
  opacity: 0;
  visibility: hidden;
  transition: opacity 0.2s ease, transform 0.2s ease, visibility 0.2s ease;
  z-index: 100;
}

.nuda-popover.is-open .nuda-popover__content {
  opacity: 1;
  visibility: visible;
  transform: translateX(-50%) translateY(0);
}

.nuda-popover__arrow {
  position: absolute;
  bottom: -5px;
  left: 50%;
  transform: translateX(-50%);
  width: 0;
  height: 0;
  border-left: 6px solid transparent;
  border-right: 6px solid transparent;
  border-top: 6px solid #1a1a1a;
}

.nuda-popover__title {
  font-size: 0.85rem;
  font-weight: 700;
  color: #fff;
  margin: 0 0 0.25rem;
}

.nuda-popover__body {
  font-size: 0.78rem;
  color: #999;
  margin: 0;
}

@media (prefers-reduced-motion: reduce) {
  .nuda-popover__content { transition: none; }
}

/* Popover — Toggle with .is-open class */

(function () {
  var popovers = document.querySelectorAll('.nuda-popover');
  popovers.forEach(function (pop) {
    var trigger = pop.querySelector('.nuda-popover__trigger');
    if (!trigger) return;

    trigger.addEventListener('click', function (e) {
      e.stopPropagation();
      pop.classList.toggle('is-open');
    });

    document.addEventListener('click', function (e) {
      if (!pop.contains(e.target)) {
        pop.classList.remove('is-open');
      }
    });
  });
})();

