        btn.classList.add('is-active');
        btn.setAttribute('aria-selected', 'true');
        var panel = tabs.querySelector('[data-panel="' + btn.dataset.tab + '"]');
        if (panel) panel.classList.add('is-active');

        indicator.style.transform = 'translateX(' + (i * 100) + '%)';
      });
    });
  });
})();

