/* KPI Card
   Compact metric card with title, delta, value, and growing bar.
   Customize: --kpi-target (the bar fill %), --kpi-color, --kpi-bg */

.nuda-kpi {
  --kpi-color: #e4ff54;
  --kpi-bg: rgba(255, 255, 255, 0.03);
  --kpi-target: 87%;
  width: 100%;
  max-width: 200px;
  padding: 12px 14px;
  background: var(--kpi-bg);
  border: 1px solid rgba(255, 255, 255, 0.06);
  border-radius: 12px;
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.nuda-kpi__head {
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.nuda-kpi__title {
  font: 600 0.625rem ui-sans-serif, system-ui, sans-serif;
  color: #a1a1aa;
  text-transform: uppercase;
  letter-spacing: 0.08em;
}

.nuda-kpi__delta {
  font: 700 0.625rem ui-sans-serif, system-ui, sans-serif;
  color: var(--kpi-color);
  background: rgba(228, 255, 84, 0.1);
  padding: 2px 6px;
  border-radius: 6px;
}

.nuda-kpi__value {
  font: 700 1.6rem ui-sans-serif, system-ui, sans-serif;
  color: #fafafa;
  font-variant-numeric: tabular-nums;
  line-height: 1;
}

.nuda-kpi__value i {
  font-size: 0.8rem;
  font-style: normal;
  color: #a1a1aa;
  margin-left: 1px;
}

.nuda-kpi__bar {
  position: relative;
  width: 100%;
  height: 4px;
  background: rgba(255, 255, 255, 0.06);
  border-radius: 2px;
  overflow: hidden;
}

.nuda-kpi__bar span {
  position: absolute;
  left: 0;
  top: 0;
  height: 100%;
  width: 0;
  background: linear-gradient(90deg, var(--kpi-color), rgba(228, 255, 84, 0.6));
  border-radius: 2px;
  animation: nuda-kpi-fill 2s cubic-bezier(0.4, 0, 0.2, 1) forwards;
}

@keyframes nuda-kpi-fill {
  to { width: var(--kpi-target); }
}

@media (prefers-reduced-motion: reduce) {
  .nuda-kpi__bar span { width: var(--kpi-target); animation: none; }
}

/* Confetti Burst
   Radial confetti from a central pulsing core.
   Customize: --conf-distance, piece colors via inline --c. */

.nuda-confetti {
  --conf-distance: 50px;
  position: relative;
  width: 120px;
  height: 120px;
  display: flex;
  align-items: center;
  justify-content: center;
}

.nuda-confetti::before {
  content: "";
  position: absolute;
  width: 8px;
  height: 8px;
  border-radius: 50%;
  background: #e4ff54;
  box-shadow: 0 0 12px rgba(228, 255, 84, 0.6);
  animation: nuda-conf-core 2s ease-in-out infinite;
}

.nuda-confetti__piece {
  position: absolute;
  width: 6px;
  height: 6px;
  background: var(--c, #e4ff54);
  transform: rotate(var(--a, 0deg)) translateY(0);
  transform-origin: center;
  border-radius: 1px;
  animation: nuda-conf-burst 2s cubic-bezier(0.2, 0.6, 0.4, 1) var(--d, 0s) infinite;
}

.nuda-confetti__piece:nth-child(2n) { width: 4px; height: 8px; }
.nuda-confetti__piece:nth-child(3n) { border-radius: 50%; }

@keyframes nuda-conf-burst {
  0%        { transform: rotate(var(--a)) translateY(0) scale(0.4); opacity: 0; }
  15%       { opacity: 1; }
  80%, 100% { transform: rotate(var(--a)) translateY(calc(var(--conf-distance) * -1)) scale(1); opacity: 0; }
}

@keyframes nuda-conf-core {
  0%, 100% { transform: scale(0.6); opacity: 0.4; }
  50%      { transform: scale(1.2); opacity: 1;   }
}

@media (prefers-reduced-motion: reduce) {
  .nuda-confetti__piece,
  .nuda-confetti::before { animation: none; }
}

