/* Scroll Counter Bar
   A vertical rail with a fill (scaleY) and a knob (translateY) that
   both track scroll progress via scroll() timelines. transform only. */

.nuda-scrollcb__rail { position: relative; overflow: hidden; }

.nuda-scrollcb__fill {
  position: absolute;
  inset: 0;
  background: #e4ff54;
  transform-origin: 50% 0;
  transform: scaleY(0);
  animation: nuda-scrollcb-fill linear;
  animation-timeline: scroll(nearest block);
}

.nuda-scrollcb__knob {
  animation: nuda-scrollcb-knob linear;
  animation-timeline: scroll(nearest block);
}

@keyframes nuda-scrollcb-fill { to { transform: scaleY(1); } }
@keyframes nuda-scrollcb-knob { to { transform: translateY(100%); } }

@supports not (animation-timeline: scroll()) {
  .nuda-scrollcb__fill { transform: scaleY(1); }
}

@media (prefers-reduced-motion: reduce) {
  .nuda-scrollcb__fill,
  .nuda-scrollcb__knob {
    animation: none;
    animation-timeline: none;
  }
  .nuda-scrollcb__fill { transform: scaleY(1); }
}

/* Scroll Color Shift
   The container's hue rotates with scroll progress via a scroll(self)
   timeline. Animates filter only (no layout). */

.nuda-scrollcs__scroller {
  background: linear-gradient(135deg, #09090b, #1a2e05);
  animation: nuda-scrollcs-hue linear;
  animation-timeline: scroll(self block);
}

@keyframes nuda-scrollcs-hue {
  from { filter: hue-rotate(0deg); }
  to   { filter: hue-rotate(300deg); }
}

@supports not (animation-timeline: scroll()) {
  .nuda-scrollcs__scroller { filter: hue-rotate(0deg); }
}

@media (prefers-reduced-motion: reduce) {
  .nuda-scrollcs__scroller {
    animation: none;
    animation-timeline: none;
    filter: none;
  }
}

/* Scroll Rotate
   An element rotates a full turn across the scroll range using a
   scroll() timeline. transform: rotate only. */

.nuda-scrollrot__stage {
  display: flex;
  align-items: center;
  justify-content: center;
}

.nuda-scrollrot__mark {
  transform: rotate(0deg);
  animation: nuda-scrollrot-spin linear;
  animation-timeline: scroll(nearest block);
}

@keyframes nuda-scrollrot-spin {
  to { transform: rotate(360deg); }
}

@supports not (animation-timeline: scroll()) {
  .nuda-scrollrot__mark { transform: rotate(45deg); }
}

@media (prefers-reduced-motion: reduce) {
  .nuda-scrollrot__mark {
    animation: none;
    animation-timeline: none;
    transform: rotate(45deg);
  }
}

/* Scale In on View
   Elements scale from 0.7 to 1 as they enter the scrollport, via a
   view() timeline. transform + opacity only. Customize: --scale-from */

.nuda-scrollsi__tile {
  --scale-from: 0.7;
  opacity: 0;
  transform: scale(var(--scale-from));
  animation: nuda-scrollsi-in linear both;
  animation-timeline: view();
  animation-range: entry 0% entry 50%;
}

@keyframes nuda-scrollsi-in {
  to { opacity: 1; transform: scale(1); }
}

@supports not (animation-timeline: view()) {
  .nuda-scrollsi__tile { opacity: 1; transform: none; }
}

@media (prefers-reduced-motion: reduce) {
  .nuda-scrollsi__tile {
    animation: none;
    opacity: 1;
    transform: none;
  }
}

/* Horizontal Snap
   A scroll-snap row where the centered slide scales up via an inline
   view() timeline. scroll-snap + transform only (no layout writes). */

.nuda-scrollsnap__row {
  display: flex;
  gap: 0.7rem;
  overflow-x: auto;
  scroll-snap-type: x mandatory;
}

.nuda-scrollsnap__slide {
  flex: 0 0 78%;
  scroll-snap-align: center;
  transform: scale(0.92);
  animation: nuda-scrollsnap-pop linear both;
  animation-timeline: view(inline);
  animation-range: cover 30% cover 70%;
}

@keyframes nuda-scrollsnap-pop {
  to { transform: scale(1); }
}

@supports not (animation-timeline: view()) {
  .nuda-scrollsnap__slide { transform: none; }
}

@media (prefers-reduced-motion: reduce) {
  .nuda-scrollsnap__slide {
    animation: none;
    animation-timeline: none;
    transform: none;
  }
}

/* Cross Fade
   Default cross-fade between two states using the View Transitions API.
   The named element fades old -> new automatically.
   Customize: --vt-accent, animation-duration */

.nuda-vt-crossfade__stage {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 200px;
  height: 96px;
  border-radius: 12px;
  border: 1px solid rgba(255, 255, 255, 0.1);
  /* Opt this element into its own snapshot for the transition. */
  view-transition-name: vt-crossfade-stage;
}

.nuda-vt-crossfade__stage[data-state="a"] { background: #18181b; }
.nuda-vt-crossfade__stage[data-state="b"] { background: #1f2937; }

.nuda-vt-crossfade__panel {
  --vt-accent: #e4ff54;
  font-size: 1rem;
  font-weight: 700;
  color: var(--vt-accent);
}

.nuda-vt-crossfade__btn {
  background: #e4ff54;
  color: #09090b;
  border: none;
  border-radius: 8px;
  padding: 0.5rem 1rem;
  font-weight: 700;
  cursor: pointer;
}

.nuda-vt-crossfade__btn:focus-visible {
  outline: 2px solid #e4ff54;
  outline-offset: 2px;
}

/* Tune the cross-fade. The UA default is already a fade; this controls timing. */
::view-transition-old(vt-crossfade-stage),
::view-transition-new(vt-crossfade-stage) {
  animation-duration: 0.4s;
  animation-timing-function: cubic-bezier(0.4, 0, 0.2, 1);
}

@media (prefers-reduced-motion: reduce) {
  ::view-transition-old(vt-crossfade-stage),
  ::view-transition-new(vt-crossfade-stage) { animation: none; }
}

/* Cross Fade — vanilla JS
   Swaps state inside a view transition with an instant fallback. */

(function () {
  document.querySelectorAll(".nuda-vt-crossfade").forEach(function (root) {
    var stage = root.querySelector(".nuda-vt-crossfade__stage");
    var panel = root.querySelector(".nuda-vt-crossfade__panel");
    var btn = root.querySelector(".nuda-vt-crossfade__btn");

    function doSwap() {
      var next = stage.dataset.state === "a" ? "b" : "a";
      stage.dataset.state = next;
      panel.textContent = next === "a" ? "State A" : "State B";
    }

    btn.addEventListener("click", function () {
      if (!document.startViewTransition) { doSwap(); return; }
      document.startViewTransition(doSwap);
    });
  });
})();

/* Shared Element
   The dot has a stable view-transition-name, so the API morphs it from its old
   position/size to the new one — even across DOM changes.
   Customize: --vt-accent, the easing on the group */

.nuda-vt-shared__track {
  display: flex;
  align-items: center;
  width: 220px;
  height: 64px;
  padding: 0 10px;
  border-radius: 12px;
  border: 1px solid rgba(255, 255, 255, 0.1);
  background: #18181b;
}

.nuda-vt-shared__track[data-pos="left"]  { justify-content: flex-start; }
.nuda-vt-shared__track[data-pos="right"] { justify-content: flex-end; }

.nuda-vt-shared__dot {
  --vt-accent: #e4ff54;
  width: 36px;
  height: 36px;
  border-radius: 50%;
  background: var(--vt-accent);
  /* Stable name => the group animates position + size between snapshots. */
  view-transition-name: vt-shared-dot;
}

.nuda-vt-shared__btn {
  background: #e4ff54;
  color: #09090b;
  border: none;
  border-radius: 8px;
  padding: 0.5rem 1rem;
  font-weight: 700;
  cursor: pointer;
}

.nuda-vt-shared__btn:focus-visible {
  outline: 2px solid #e4ff54;
  outline-offset: 2px;
}

/* The group pseudo controls the morph (transform/size interpolation). */
::view-transition-group(vt-shared-dot) {
  animation-duration: 0.5s;
  animation-timing-function: cubic-bezier(0.34, 1.56, 0.64, 1);
}

@media (prefers-reduced-motion: reduce) {
  ::view-transition-group(vt-shared-dot) { animation: none; }
}

/* Shared Element — vanilla JS
   Toggles the dot's container alignment inside a view transition. */

(function () {
  document.querySelectorAll(".nuda-vt-shared").forEach(function (root) {
    var track = root.querySelector(".nuda-vt-shared__track");
    var btn = root.querySelector(".nuda-vt-shared__btn");

    function doSwap() {
      track.dataset.pos = track.dataset.pos === "left" ? "right" : "left";
    }

    btn.addEventListener("click", function () {
      if (!document.startViewTransition) { doSwap(); return; }
      document.startViewTransition(doSwap);
    });
  });
})();

/* Slide Page
   Directional page slide: the old page exits left, the new one enters from the
   right via custom keyframes on the view-transition pseudo-elements.
   Customize: keyframe directions, animation-duration */

.nuda-vt-slide__viewport {
  width: 240px;
  height: 120px;
  border-radius: 12px;
  border: 1px solid rgba(255, 255, 255, 0.1);
  overflow: hidden;
}

.nuda-vt-slide__page {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 100%;
  height: 100%;
  font-weight: 700;
  color: #e4ff54;
  view-transition-name: vt-slide-page;
}

.nuda-vt-slide__page[data-page="1"] { background: #18181b; }
.nuda-vt-slide__page[data-page="2"] { background: #1f2937; }

.nuda-vt-slide__btn {
  background: #e4ff54;
  color: #09090b;
  border: none;
  border-radius: 8px;
  padding: 0.5rem 1rem;
  font-weight: 700;
