/* Grid to Detail
   A gallery thumbnail expands into a hero. The thumbnail and the hero share one
   view-transition-name, so the API morphs the small tile into the large view
   (and back) — the classic "open the photo" transition.
   Customize: --vt-accent gradient, the group easing */

.nuda-vt-grid__stage { width: 240px; height: 150px; }

.nuda-vt-grid__grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 8px;
  width: 100%;
  height: 100%;
}

.nuda-vt-grid__thumb { border-radius: 8px; background: #27272a; }

.nuda-vt-grid__thumb--hero {
  background: linear-gradient(135deg, #e4ff54, #a3e635);
  view-transition-name: vt-grid-hero;
}

.nuda-vt-grid__hero {
  display: none;
  width: 100%;
  height: 100%;
  border-radius: 12px;
  background: linear-gradient(135deg, #e4ff54, #a3e635);
  /* Same name as the thumb: only one is in the DOM at a time, so it morphs. */
  view-transition-name: vt-grid-hero;
}

.nuda-vt-grid__stage[data-view="detail"] .nuda-vt-grid__grid { display: none; }
.nuda-vt-grid__stage[data-view="detail"] .nuda-vt-grid__hero { display: block; }

.nuda-vt-grid__btn {
  background: #e4ff54;
  color: #09090b;
  border: none;
  border-radius: 8px;
  padding: 0.5rem 1rem;
  font-weight: 700;
  cursor: pointer;
}

.nuda-vt-grid__btn:focus-visible {
  outline: 2px solid #e4ff54;
  outline-offset: 2px;
}

::view-transition-group(vt-grid-hero) {
  animation-duration: 0.45s;
  animation-timing-function: cubic-bezier(0.34, 1.2, 0.64, 1);
}

@media (prefers-reduced-motion: reduce) {
  ::view-transition-group(vt-grid-hero) { animation: none; }
}

/* Grid to Detail — vanilla JS
   Toggles between the grid and the hero detail inside a view transition. */

(function () {
  document.querySelectorAll(".nuda-vt-grid").forEach(function (root) {
    var stage = root.querySelector(".nuda-vt-grid__stage");
    var btn = root.querySelector(".nuda-vt-grid__btn");

    function doSwap() {
      stage.dataset.view = stage.dataset.view === "grid" ? "detail" : "grid";
    }

    btn.addEventListener("click", function () {
      if (!document.startViewTransition) { doSwap(); return; }
      document.startViewTransition(doSwap);
    });
  });
})();

/* Pure CSS Accordion
   Native <details>/<summary>. No JS.
   Customize: --nuda-css-acc-accent */

.nuda-css-accordion {
  --nuda-css-acc-accent: #e4ff54;
  display: flex;
  flex-direction: column;
  gap: 6px;
  max-width: 480px;
  color: #fff;
}

.nuda-css-accordion__item {
  background: rgba(255, 255, 255, 0.03);
  border: 1px solid rgba(255, 255, 255, 0.07);
  border-radius: 10px;
  overflow: hidden;
}

.nuda-css-accordion__item[open] {
  border-color: rgba(228, 255, 84, 0.2);
}

.nuda-css-accordion__header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 8px;
  min-height: 44px;
  padding: 0.85rem 1rem;
  font-size: 0.95rem;
  font-weight: 600;
  color: #ccc;
  cursor: pointer;
  list-style: none;
  transition: color 0.2s;
}

.nuda-css-accordion__header::-webkit-details-marker { display: none; }

.nuda-css-accordion__header:hover { color: #fff; }

.nuda-css-accordion__header:focus-visible {
  outline: 2px solid var(--nuda-css-acc-accent);
  outline-offset: -2px;
}

.nuda-css-accordion__icon {
  display: inline-block;
  font-size: 1.1rem;
  color: #666;
  transition: transform 0.3s ease, color 0.2s;
}

.nuda-css-accordion__item[open] .nuda-css-accordion__icon {
  color: var(--nuda-css-acc-accent);
  transform: rotate(45deg);
}

.nuda-css-accordion__body {
  padding: 0 1rem 0.9rem;
  font-size: 0.85rem;
  color: #999;
  animation: nuda-css-acc-open 0.3s ease-out;
}

@keyframes nuda-css-acc-open {
  from { opacity: 0; transform: translateY(-6px); }
  to   { opacity: 1; transform: translateY(0); }
}

@media (prefers-reduced-motion: reduce) {
  .nuda-css-accordion__body { animation: none; }
  .nuda-css-accordion__icon { transition: none; }
}

/* Pure CSS Tabs
   Hidden radios + sibling selectors switch panels. No JS.
   Customize: --nuda-css-tab-accent */

.nuda-css-tabs {
  --nuda-css-tab-accent: #e4ff54;
  max-width: 480px;
}

.nuda-css-tabs__bar {
  display: flex;
  background: rgba(255, 255, 255, 0.04);
  border-radius: 10px;
  padding: 4px;
  gap: 2px;
}

/* Visually-hidden native radios (still focusable) */
.nuda-css-tabs__radio {
  position: absolute;
  width: 1px; height: 1px;
  margin: -1px; overflow: hidden;
  clip: rect(0, 0, 0, 0); border: 0;
}

.nuda-css-tabs__tab {
  flex: 1;
  display: flex;
  align-items: center;
  justify-content: center;
  min-height: 44px;
  text-align: center;
  font-size: 0.9rem;
  color: #888;
  border-radius: 8px;
  cursor: pointer;
  transition: color 0.2s, background 0.2s;
}

.nuda-css-tabs__tab:hover { color: #ccc; }

.nuda-css-tabs__panel {
  display: none;
  margin-top: 0.5rem;
  padding: 1rem;
  font-size: 0.85rem;
  color: #bbb;
  background: rgba(255, 255, 255, 0.02);
  border: 1px solid rgba(255, 255, 255, 0.06);
  border-radius: 10px;
  animation: nuda-css-tab-fade 0.3s ease-out;
}

/* Keyboard focus ring on the visible label */
.nuda-css-tabs__radio:focus-visible + .nuda-css-tabs__bar label {
  outline: 2px solid var(--nuda-css-tab-accent);
  outline-offset: 2px;
}

/* Active tab + matching panel */
#nuda-css-tab-r1:checked ~ .nuda-css-tabs__bar label[for="nuda-css-tab-r1"],
#nuda-css-tab-r2:checked ~ .nuda-css-tabs__bar label[for="nuda-css-tab-r2"] {
  background: var(--nuda-css-tab-accent);
  color: #09090b;
  font-weight: 700;
}

#nuda-css-tab-r1:checked ~ .nuda-css-tabs__panel--1,
#nuda-css-tab-r2:checked ~ .nuda-css-tabs__panel--2 {
  display: block;
}

@keyframes nuda-css-tab-fade {
  from { opacity: 0; transform: translateY(6px); }
  to   { opacity: 1; transform: translateY(0); }
}

@media (prefers-reduced-motion: reduce) {
  .nuda-css-tabs__panel { animation: none; }
}

/* Pure CSS Modal
   The :target pseudo-class shows the overlay when its id
   is the URL hash. No JS.
   Customize: --nuda-css-modal-accent */

.nuda-css-modal {
  --nuda-css-modal-accent: #e4ff54;
}

.nuda-css-modal__open {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-height: 44px;
  padding: 0.6rem 1.2rem;
  font-size: 0.9rem;
  font-weight: 600;
  color: #09090b;
  background: var(--nuda-css-modal-accent);
  border-radius: 8px;
  text-decoration: none;
  cursor: pointer;
}

.nuda-css-modal__overlay {
  position: fixed;
  inset: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  background: rgba(0, 0, 0, 0.6);
  opacity: 0;
  pointer-events: none;
  transition: opacity 0.25s ease;
  z-index: 100;
}

.nuda-css-modal__dialog {
  width: 90%;
  max-width: 400px;
  padding: 1.5rem;
  background: #111114;
  border: 1px solid rgba(228, 255, 84, 0.2);
  border-radius: 14px;
  color: #fff;
  transform: scale(0.9);
  transition: transform 0.25s cubic-bezier(0.16, 1, 0.3, 1);
  box-shadow: 0 18px 50px rgba(0, 0, 0, 0.6);
}

.nuda-css-modal__title { margin: 0 0 0.5rem; font-size: 1.05rem; font-weight: 700; }
.nuda-css-modal__text  { margin: 0 0 1rem; font-size: 0.85rem; color: #999; }

.nuda-css-modal__close {
  display: inline-flex;
  align-items: center;
  min-height: 44px;
  padding: 0.5rem 1rem;
  font-size: 0.85rem;
  color: #ccc;
  border: 1px solid rgba(255, 255, 255, 0.15);
  border-radius: 8px;
  text-decoration: none;
  cursor: pointer;
}

/* Open state — driven entirely by the URL hash */
.nuda-css-modal__overlay:target {
  opacity: 1;
  pointer-events: auto;
}

.nuda-css-modal__overlay:target .nuda-css-modal__dialog {
  transform: scale(1);
}

@media (prefers-reduced-motion: reduce) {
  .nuda-css-modal__overlay,
  .nuda-css-modal__dialog { transition: none; }
