  font-size: 15px;
  font-weight: 700;
  color: var(--neon-card-color);
  text-shadow: 0 0 8px rgba(228, 255, 84, 0.5);
}

.nuda-neon-card__body {
  margin: 0;
  font-size: 12px;
  line-height: 1.5;
  color: #c9cbd1;
}

@media (prefers-reduced-motion: reduce) {
  .nuda-neon-card { transition: none; }
