/* ── Tube Light ──────────────────────────────────────────────
   A glowing band travels along the tube by shifting a gradient's
   background-position (GPU-friendly, no layout work).
   Customize:
     --neon-tube-color : neon hue
     --neon-tube-speed : sweep cycle
   ──────────────────────────────────────────────────────────── */
.nuda-neon-tube {
  --neon-tube-color: #e4ff54;
  --neon-tube-speed: 2.6s;
  position: relative;
  width: 220px;
  height: 12px;
  border-radius: 99px;
  background: #16161c;
  overflow: hidden;
  box-shadow: inset 0 0 6px rgba(0, 0, 0, 0.6);
}

.nuda-neon-tube__fill {
  position: absolute;
  inset: 0;
  border-radius: inherit;
  background: linear-gradient(
    90deg,
    rgba(228, 255, 84, 0) 0%,
    var(--neon-tube-color) 30%,
    #aef0ff 50%,
    var(--neon-tube-color) 70%,
    rgba(228, 255, 84, 0) 100%
  );
  background-size: 220% 100%;
  box-shadow: 0 0 12px rgba(228, 255, 84, 0.6);
  animation: nuda-neon-tube-fill var(--neon-tube-speed) linear infinite;
  will-change: background-position;
}

@keyframes nuda-neon-tube-fill {
  0%   { background-position: 120% 0; }
  100% { background-position: -120% 0; }
}

@media (prefers-reduced-motion: reduce) {
  .nuda-neon-tube__fill {
    animation: none;
    background-position: 50% 0;
  }
}

/* ── Pulse Beacon ────────────────────────────────────────────
   A steady glowing core with an expanding-and-fading halo ring.
   Cyan-green secondary hue reads well as an "online" indicator.
   Customize:
     --neon-beacon-color : status hue
     --neon-beacon-speed : pulse cycle
   ──────────────────────────────────────────────────────────── */
.nuda-neon-beacon {
  --neon-beacon-color: #6ee7b7;
  --neon-beacon-speed: 1.8s;
  position: relative;
  display: inline-flex;
  width: 16px;
  height: 16px;
}

.nuda-neon-beacon__core {
  position: absolute;
  inset: 0;
  margin: auto;
  width: 10px;
  height: 10px;
  border-radius: 50%;
  background: var(--neon-beacon-color);
  box-shadow: 0 0 8px var(--neon-beacon-color), 0 0 16px rgba(110, 231, 183, 0.7);
}

.nuda-neon-beacon__ring {
  position: absolute;
  inset: 0;
  border-radius: 50%;
  border: 2px solid var(--neon-beacon-color);
  animation: nuda-neon-beacon-pulse var(--neon-beacon-speed) ease-out infinite;
  will-change: transform, opacity;
}

@keyframes nuda-neon-beacon-pulse {
  0%   { transform: scale(0.6); opacity: 0.8; }
  100% { transform: scale(2.2); opacity: 0; }
}

@media (prefers-reduced-motion: reduce) {
  .nuda-neon-beacon__ring {
    animation: none;
    opacity: 0;
  }
}

/* ── Neon Grid ───────────────────────────────────────────────
   A retro "outrun" floor: a perspective-tilted grid whose lines
   scroll toward the viewer by shifting background-position only.
   Customize:
     --neon-grid-color : grid line hue
     --neon-grid-speed : scroll cycle
   ──────────────────────────────────────────────────────────── */
.nuda-neon-grid {
  --neon-grid-color: #e4ff54;
  --neon-grid-speed: 1.6s;
  position: relative;
  width: 240px;
  height: 120px;
  background: #09090b;
  border-radius: 12px;
  overflow: hidden;
  perspective: 160px;
}

/* Fade the far edge into the background for depth. */
.nuda-neon-grid::after {
  content: '';
  position: absolute;
  inset: 0;
  background: linear-gradient(180deg, #09090b 0%, rgba(9, 9, 11, 0) 45%);
  z-index: 1;
  pointer-events: none;
}

.nuda-neon-grid__floor {
  position: absolute;
  left: -50%;
  right: -50%;
  bottom: -20%;
  height: 160%;
  background-image:
    linear-gradient(rgba(228, 255, 84, 0.5) 1px, transparent 1px),
    linear-gradient(90deg, rgba(228, 255, 84, 0.5) 1px, transparent 1px);
  background-size: 28px 28px;
  transform: rotateX(72deg);
  transform-origin: bottom center;
  filter: drop-shadow(0 0 4px rgba(228, 255, 84, 0.5));
  animation: nuda-neon-grid-scroll var(--neon-grid-speed) linear infinite;
  will-change: background-position;
}

@keyframes nuda-neon-grid-scroll {
  0%   { background-position: 0 0; }
  100% { background-position: 0 28px; }
}

@media (prefers-reduced-motion: reduce) {
  .nuda-neon-grid__floor { animation: none; }
}

/* Blob Morph
   Organic border-radius blob that morphs and rotates.
   Customize: --morph-blob-size, --morph-blob-start, --morph-blob-end */

.nuda-morph-blob {
  --morph-blob-size: 72px;
  --morph-blob-start: #e4ff54;
  --morph-blob-end: #a3b830;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 16px;
}

.nuda-morph-blob__shape {
  width: var(--morph-blob-size);
  height: var(--morph-blob-size);
  background: linear-gradient(135deg, var(--morph-blob-start), var(--morph-blob-end));
  animation: nuda-morph-blob-spin 6s ease-in-out infinite;
  will-change: border-radius, transform;
}

@keyframes nuda-morph-blob-spin {
  0%   { border-radius: 42% 58% 63% 37% / 41% 44% 56% 59%; transform: rotate(0deg); }
  33%  { border-radius: 67% 33% 38% 62% / 55% 62% 38% 45%; transform: rotate(120deg); }
  66%  { border-radius: 38% 62% 56% 44% / 63% 37% 63% 37%; transform: rotate(240deg); }
  100% { border-radius: 42% 58% 63% 37% / 41% 44% 56% 59%; transform: rotate(360deg); }
}

@media (prefers-reduced-motion: reduce) {
  .nuda-morph-blob__shape {
    animation: none;
    border-radius: 50%;
  }
}

/* Clip-Path Morph
   Cycles through polygon shapes and a circle via animated clip-path.
   Customize: --morph-clip-size, --morph-clip-start, --morph-clip-end */

.nuda-morph-clip {
  --morph-clip-size: 72px;
  --morph-clip-start: #e4ff54;
  --morph-clip-end: #a3b830;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 16px;
}

.nuda-morph-clip__shape {
  width: var(--morph-clip-size);
  height: var(--morph-clip-size);
  background: linear-gradient(135deg, var(--morph-clip-start), var(--morph-clip-end));
  animation: nuda-morph-clip-cycle 5s ease-in-out infinite;
  will-change: clip-path;
}

@keyframes nuda-morph-clip-cycle {
  0%   { clip-path: polygon(50% 0%, 100% 50%, 50% 100%, 0% 50%); }
  25%  { clip-path: polygon(50% 0%, 90% 20%, 100% 60%, 75% 100%, 25% 100%, 0% 60%, 10% 20%); }
  50%  { clip-path: circle(50% at 50% 50%); }
  75%  { clip-path: polygon(20% 0%, 80% 0%, 100% 100%, 0% 100%); }
  100% { clip-path: polygon(50% 0%, 100% 50%, 50% 100%, 0% 50%); }
}

@media (prefers-reduced-motion: reduce) {
  .nuda-morph-clip__shape {
    animation: none;
    clip-path: circle(50% at 50% 50%);
  }
}

/* SVG Path Morph
   The morph itself lives in the inline SVG <animate> element (SMIL),
   so it is fully dependency-free. CSS only handles layout + a11y.
   Customize: change the path "values" or the <path fill>. */

.nuda-morph-svg {
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 16px;
}

@media (prefers-reduced-motion: reduce) {
  /* Freeze the SMIL morph for users who prefer reduced motion. */
  .nuda-morph-svg svg animate {
    display: none;
  }
}

/* Liquid Button
   Three blurred circles fused by an SVG goo filter; on hover the
   outer two slide out, giving a liquid split/merge effect.
   Customize: --morph-liquid-color, --morph-liquid-ink */

.nuda-morph-liquid {
  --morph-liquid-color: #e4ff54;
  --morph-liquid-ink: #09090b;
  position: relative;
  border: none;
  background: none;
  cursor: pointer;
  padding: 0;
  outline: none;
}

.nuda-morph-liquid__goo {
  position: absolute;
  inset: 0;
  filter: url(#nuda-morph-goo-filter);
  z-index: 0;
}

.nuda-morph-liquid__goo i {
  position: absolute;
  top: 50%;
  left: 50%;
  width: 60px;
  height: 60px;
  background: var(--morph-liquid-color);
  border-radius: 50%;
  transform: translate(-50%, -50%) scale(1);
  transition: transform 0.5s cubic-bezier(0.4, 0.2, 0.2, 1.2);
  will-change: transform;
}

.nuda-morph-liquid:hover .nuda-morph-liquid__goo i:nth-child(1),
.nuda-morph-liquid:focus-visible .nuda-morph-liquid__goo i:nth-child(1) {
  transform: translate(-150%, -50%) scale(0.7);
}

.nuda-morph-liquid:hover .nuda-morph-liquid__goo i:nth-child(3),
.nuda-morph-liquid:focus-visible .nuda-morph-liquid__goo i:nth-child(3) {
  transform: translate(50%, -50%) scale(0.7);
}

.nuda-morph-liquid__label {
  position: relative;
  z-index: 1;
  display: block;
  padding: 12px 28px;
  color: var(--morph-liquid-ink);
  font-weight: 700;
  font-size: 0.9rem;
}

.nuda-morph-liquid:focus-visible {
  outline: 2px solid var(--morph-liquid-color);
  outline-offset: 4px;
  border-radius: 8px;
}

@media (prefers-reduced-motion: reduce) {
  .nuda-morph-liquid__goo i {
    transition: none;
  }
}

