/* Card Morph
   A square smoothly rounds into a circle and scales up on hover/focus.
   Customize: --morph-card-size, --morph-card-start, --morph-card-end */

.nuda-morph-card {
  --morph-card-size: 90px;
  --morph-card-start: #e4ff54;
  --morph-card-end: #a3b830;
  display: flex;
  align-items: center;
  justify-content: center;
  width: var(--morph-card-size);
  height: var(--morph-card-size);
  background: linear-gradient(135deg, var(--morph-card-start), var(--morph-card-end));
  border-radius: 6px;
  cursor: pointer;
  outline: none;
  transition: border-radius 0.5s cubic-bezier(0.4, 0.2, 0.2, 1),
              transform 0.5s cubic-bezier(0.4, 0.2, 0.2, 1);
  will-change: border-radius, transform;
}

.nuda-morph-card__label {
  color: #09090b;
  font-weight: 700;
  font-size: 0.8rem;
}

.nuda-morph-card:hover,
.nuda-morph-card:focus-visible {
  border-radius: 50%;
  transform: scale(1.1);
}

.nuda-morph-card:focus-visible {
  outline: 2px solid var(--morph-card-start);
  outline-offset: 4px;
}

@media (prefers-reduced-motion: reduce) {
  .nuda-morph-card {
    transition: none;
  }
  .nuda-morph-card:hover,
  .nuda-morph-card:focus-visible {
    transform: none;
  }
}

/* Wave Morph
   An SVG wave divider whose crest/trough morph via SMIL <animate>.
   Layout + a11y handled in CSS; the morph is in the markup.
   Customize: change the <path fill> or the path "values". */

.nuda-morph-wave {
  border-radius: 8px;
  overflow: hidden;
  background: #09090b;
  display: flex;
  align-items: flex-end;
}

.nuda-morph-wave svg {
  display: block;
}

@media (prefers-reduced-motion: reduce) {
  .nuda-morph-wave svg animate {
    display: none;
  }
}

/* Shape Toggle
   A circle morphs into a rotated square when .is-square is toggled.
   Customize: --morph-toggle-size, --morph-toggle-color */

.nuda-morph-toggle {
  --morph-toggle-size: 56px;
  --morph-toggle-color: #e4ff54;
  background: none;
  border: none;
  cursor: pointer;
  padding: 16px;
  outline: none;
}

.nuda-morph-toggle__shape {
  display: block;
  width: var(--morph-toggle-size);
  height: var(--morph-toggle-size);
  background: var(--morph-toggle-color);
  border-radius: 50%;
  transition: border-radius 0.45s cubic-bezier(0.4, 0.2, 0.2, 1.2),
              transform 0.45s cubic-bezier(0.4, 0.2, 0.2, 1.2);
  will-change: border-radius, transform;
}

.nuda-morph-toggle.is-square .nuda-morph-toggle__shape {
  border-radius: 8px;
  transform: rotate(45deg);
}

.nuda-morph-toggle:focus-visible {
  outline: 2px solid var(--morph-toggle-color);
  outline-offset: 2px;
  border-radius: 8px;
}

@media (prefers-reduced-motion: reduce) {
  .nuda-morph-toggle__shape {
    transition: none;
  }
  .nuda-morph-toggle.is-square .nuda-morph-toggle__shape {
    transform: none;
  }
}

// Toggle the circle <-> square morph
const toggle = document.querySelector(".nuda-morph-toggle");
toggle.addEventListener("click", () => {
  const on = toggle.getAttribute("aria-pressed") === "true";
  toggle.setAttribute("aria-pressed", String(!on));
  toggle.classList.toggle("is-square", !on);
});

/* Confetti Burst
   Radial confetti pop re-triggered on every click.
   Customize: --confetti-burst-bg, piece colors via inline --c. */

.nuda-confetti-burst {
  --confetti-burst-bg: #e4ff54;
  position: relative;
  background: var(--confetti-burst-bg);
  color: #09090b;
  border: none;
  border-radius: 10px;
  padding: 12px 22px;
  min-height: 44px;
  font: 600 14px/1 system-ui, sans-serif;
  cursor: pointer;
  outline: none;
}

.nuda-confetti-burst:focus-visible {
  box-shadow: 0 0 0 3px rgba(228, 255, 84, 0.5);
}

.nuda-confetti-burst__pieces {
  position: absolute;
  inset: 0;
  pointer-events: none;
  display: flex;
  align-items: center;
  justify-content: center;
}

.nuda-confetti-burst__piece {
  position: absolute;
  width: 7px;
  height: 7px;
  background: var(--c, #e4ff54);
  border-radius: 1px;
  opacity: 0;
  transform: rotate(var(--a, 0deg)) translateY(0) scale(0.4);
  will-change: transform, opacity;
}

.nuda-confetti-burst__piece:nth-child(2n) { width: 5px; height: 9px; }
.nuda-confetti-burst__piece:nth-child(3n) { border-radius: 50%; }

.nuda-confetti-burst--pop .nuda-confetti-burst__piece {
  animation: nuda-confetti-burst-fly 0.8s cubic-bezier(0.2, 0.6, 0.4, 1) forwards;
}

@keyframes nuda-confetti-burst-fly {
  0%   { opacity: 0; transform: rotate(var(--a)) translateY(0) scale(0.4); }
  15%  { opacity: 1; }
  100% { opacity: 0; transform: rotate(var(--a)) translateY(-46px) scale(1); }
}

@media (prefers-reduced-motion: reduce) {
  .nuda-confetti-burst--pop .nuda-confetti-burst__piece { animation: none; opacity: 0; }
}

/* Confetti Burst — vanilla JS
   Re-triggers the pop animation on each click. */

(function () {
  document.querySelectorAll(".nuda-confetti-burst").forEach(function (btn) {
    btn.addEventListener("click", function () {
      btn.classList.remove("nuda-confetti-burst--pop");
      void btn.offsetWidth; // reflow so the animation restarts
      btn.classList.add("nuda-confetti-burst--pop");
      setTimeout(function () {
        btn.classList.remove("nuda-confetti-burst--pop");
      }, 900);
    });
  });
})();

