/* Goal Progress
   Goal tracker: title + value, filling bar with shine, milestone segments.
   Customize: --goal-color, --goal-target. */

.nuda-goal {
  --goal-color: #e4ff54;
  --goal-target: 82%;
  width: 100%;
  max-width: 220px;
  display: flex;
  flex-direction: column;
  gap: 8px;
  padding: 12px;
}

.nuda-goal__head {
  display: flex;
  justify-content: space-between;
  align-items: baseline;
}

.nuda-goal__title {
  font: 600 0.625rem ui-sans-serif, system-ui, sans-serif;
  color: #a1a1aa;
  text-transform: uppercase;
  letter-spacing: 0.08em;
}

.nuda-goal__amount {
  font: 700 0.875rem ui-sans-serif, system-ui, sans-serif;
  color: #fafafa;
  font-variant-numeric: tabular-nums;
}

.nuda-goal__amount i {
  font-size: 0.65rem;
  font-style: normal;
  color: #a1a1aa;
  font-weight: 500;
