/* Lightbox Grow
   Card scales up with a glow shadow + an "expand" hint icon appears.
   Pair with a real lightbox library on click.
   Customize: --lb-glow */

.nuda-lightbox {
  --lb-glow: rgba(228, 255, 84, 0.25);
  position: relative;
  width: 100%;
  aspect-ratio: 1;
  border-radius: 12px;
  overflow: hidden;
  margin: 0;
  cursor: zoom-in;
  transition:
    transform 0.35s cubic-bezier(0.4, 0, 0.2, 1),
    box-shadow 0.35s;
}

.nuda-lightbox:hover {
  transform: scale(1.04);
  box-shadow:
    0 12px 40px -8px var(--lb-glow),
    0 8px 16px -4px rgba(0, 0, 0, 0.4);
}

.nuda-lightbox__img {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  object-fit: cover;
  transition:
    transform 0.6s cubic-bezier(0.4, 0, 0.2, 1),
    filter 0.35s;
}

.nuda-lightbox:hover .nuda-lightbox__img {
  transform: scale(1.08);
  filter: brightness(1.05) saturate(1.1);
}

.nuda-lightbox__icon {
  position: absolute;
  right: 10px;
  top: 10px;
  width: 26px;
  height: 26px;
  display: flex;
  align-items: center;
  justify-content: center;
  background: rgba(0, 0, 0, 0.5);
  backdrop-filter: blur(4px);
  border-radius: 6px;
  color: #fafafa;
  opacity: 0;
  transform: scale(0.8);
  transition: opacity 0.3s, transform 0.3s;
}

.nuda-lightbox__icon svg { width: 14px; height: 14px; }

.nuda-lightbox:hover .nuda-lightbox__icon {
  opacity: 1;
  transform: scale(1);
}

