  align-items: center;
  justify-content: space-between;
  gap: 8px;
}

.nuda-composer__chip {
  font: 600 0.625rem ui-sans-serif, system-ui, sans-serif;
  color: var(--comp-accent);
  background: rgba(228, 255, 84, 0.1);
  padding: 3px 7px;
  border-radius: 5px;
}

.nuda-composer__send {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 28px;
  height: 28px;
  background: var(--comp-accent);
  color: #09090b;
  border: none;
  border-radius: 7px;
  cursor: pointer;
  transition: transform 0.2s, box-shadow 0.2s;
}

.nuda-composer__send:hover {
  transform: translateX(2px);
  box-shadow: 0 0 10px rgba(228, 255, 84, 0.4);
}

.nuda-composer__send svg { width: 14px; height: 14px; }

/* Citation Chip
   Inline numeric source links with hover lift + glow.
   Customize: --cite-accent, --cite-bg */

.nuda-cite {
  --cite-accent: #e4ff54;
  --cite-bg: rgba(228, 255, 84, 0.12);
  font: 500 0.875rem ui-sans-serif, system-ui, sans-serif;
  color: #fafafa;
  line-height: 1.7;
  margin: 0;
}

.nuda-cite__chip {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-width: 16px;
  height: 16px;
  padding: 0 5px;
  margin: 0 2px;
  background: var(--cite-bg);
  color: var(--cite-accent);
  font: 700 0.625rem ui-sans-serif, system-ui, sans-serif;
  border-radius: 4px;
  text-decoration: none;
  vertical-align: 1px;
  transition: background 0.2s, transform 0.2s, box-shadow 0.2s, color 0.2s;
}

.nuda-cite__chip:hover {
  background: var(--cite-accent);
  color: #09090b;
  transform: translateY(-1px);
  box-shadow: 0 0 6px rgba(228, 255, 84, 0.4);
}

/* Token Counter
   Context window meter; gradient warns as it nears the limit.
   Customize: --tk-target (current %) */

.nuda-tokens {
  --tk-target: 52%;
  width: 100%;
  max-width: 240px;
  padding: 10px;
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.nuda-tokens__head {
  display: flex;
  justify-content: space-between;
  align-items: baseline;
}

.nuda-tokens__label {
  font: 600 0.625rem ui-sans-serif, system-ui, sans-serif;
  color: #a1a1aa;
  text-transform: uppercase;
  letter-spacing: 0.08em;
}

.nuda-tokens__num {
  font: 700 0.875rem ui-sans-serif, system-ui, sans-serif;
  color: #fafafa;
  font-variant-numeric: tabular-nums;
}

.nuda-tokens__num i {
  font-size: 0.7rem;
  font-style: normal;
  color: #63636e;
  font-weight: 500;
  margin-left: 2px;
}

.nuda-tokens__bar {
  height: 5px;
  background: rgba(255, 255, 255, 0.06);
  border-radius: 3px;
  overflow: hidden;
  position: relative;
}

.nuda-tokens__fill {
  position: absolute;
  left: 0;
  top: 0;
  height: 100%;
  width: 0;
  background: linear-gradient(
    90deg,
    #e4ff54 0%,
    rgba(228, 255, 84, 0.7) 70%,
    #ffae54 100%
  );
  border-radius: 3px;
  box-shadow: 0 0 4px rgba(228, 255, 84, 0.3);
  animation: nuda-tk-fill 1.6s cubic-bezier(0.4, 0, 0.2, 1) forwards;
}

@keyframes nuda-tk-fill { to { width: var(--tk-target); } }

@media (prefers-reduced-motion: reduce) {
  .nuda-tokens__fill { width: var(--tk-target); animation: none; }
}

/* Model Selector
   Pill button with status dot, model name, plan badge, chevron flip on hover.
   Customize: --model-accent */

.nuda-model {
  --model-accent: #e4ff54;
  display: inline-flex;
  align-items: center;
  gap: 8px;
  padding: 6px 10px 6px 12px;
  background: rgba(255, 255, 255, 0.04);
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 8px;
  color: #fafafa;
  font: 600 0.875rem ui-sans-serif, system-ui, sans-serif;
  cursor: pointer;
  transition: border-color 0.25s, background 0.25s;
}

.nuda-model:hover {
  border-color: rgba(228, 255, 84, 0.3);
  background: rgba(255, 255, 255, 0.06);
}

.nuda-model__dot {
  width: 7px;
  height: 7px;
  border-radius: 50%;
  background: var(--model-accent);
  box-shadow: 0 0 6px var(--model-accent);
  animation: nuda-model-pulse 2s ease-in-out infinite;
}

.nuda-model__badge {
  font: 700 0.55rem ui-sans-serif, system-ui, sans-serif;
  color: #09090b;
  background: var(--model-accent);
  padding: 2px 6px;
  border-radius: 4px;
  letter-spacing: 0.04em;
  text-transform: uppercase;
}

.nuda-model__chev {
  width: 12px;
  height: 12px;
  color: #a1a1aa;
  transition: transform 0.25s;
}

.nuda-model:hover .nuda-model__chev { transform: rotate(180deg); }

@keyframes nuda-model-pulse {
  0%, 100% { opacity: 0.7; }
  50%      { opacity: 1; }
}

@media (prefers-reduced-motion: reduce) {
  .nuda-model__dot { animation: none; }
}

/* Stop Generating
   Pill button with spinner ring + center square; turns red on hover.
   Customize: --stop-color, --stop-danger */

.nuda-stop {
  --stop-color: #e4ff54;
  --stop-danger: #ff6363;
  display: inline-flex;
  align-items: center;
  gap: 10px;
  padding: 8px 14px;
  background: rgba(255, 255, 255, 0.04);
  border: 1px solid rgba(255, 255, 255, 0.1);
  border-radius: 999px;
  color: #fafafa;
  font: 600 0.875rem ui-sans-serif, system-ui, sans-serif;
  cursor: pointer;
  transition: border-color 0.25s, background 0.25s, color 0.25s;
}

.nuda-stop:hover {
  border-color: var(--stop-danger);
  background: rgba(255, 99, 99, 0.08);
  color: #fff;
}

.nuda-stop__icon {
  position: relative;
  width: 16px;
  height: 16px;
  display: flex;
  align-items: center;
  justify-content: center;
}

.nuda-stop__icon::before {
  content: "";
  position: absolute;
  inset: 0;
  border: 1.5px solid var(--stop-color);
  border-radius: 50%;
  border-top-color: transparent;
  animation: nuda-stop-spin 1s linear infinite;
  box-sizing: border-box;
  transition: border-color 0.25s;
}

.nuda-stop:hover .nuda-stop__icon::before {
  border-color: var(--stop-danger);
  border-top-color: transparent;
}

.nuda-stop__square {
  width: 7px;
  height: 7px;
  background: var(--stop-color);
  border-radius: 1px;
  transition: background 0.25s;
}

.nuda-stop:hover .nuda-stop__square { background: var(--stop-danger); }

@keyframes nuda-stop-spin { to { transform: rotate(360deg); } }

@media (prefers-reduced-motion: reduce) {
  .nuda-stop__icon::before { animation: none; }
}

/* Message Actions
   Inline action toolbar typically shown on hover under an AI message.
   Customize: --act-accent */

.nuda-msgact {
  --act-accent: #e4ff54;
  display: inline-flex;
  align-items: center;
  gap: 2px;
  padding: 3px;
  background: rgba(255, 255, 255, 0.03);
  border: 1px solid rgba(255, 255, 255, 0.06);
  border-radius: 10px;
}

.nuda-msgact__btn {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 28px;
  height: 28px;
  background: transparent;
  border: none;
  color: #a1a1aa;
  cursor: pointer;
  border-radius: 7px;
  transition: background 0.2s, color 0.2s, transform 0.2s;
}

.nuda-msgact__btn:hover {
  background: rgba(228, 255, 84, 0.1);
  color: var(--act-accent);
  transform: translateY(-1px);
}

.nuda-msgact__btn:active { transform: translateY(0) scale(0.92); }

.nuda-msgact__btn svg { width: 15px; height: 15px; }

/* Drop Zone
   Dashed area with bobbing icon; turns accent on hover or .is-over (drag-enter).
   Customize: --drop-accent, --drop-bg */

.nuda-drop {
  --drop-accent: #e4ff54;
  --drop-bg: rgba(255, 255, 255, 0.02);
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 8px;
  width: 100%;
  max-width: 360px;
  padding: 24px;
  border: 1.5px dashed rgba(255, 255, 255, 0.15);
  border-radius: 12px;
  background: var(--drop-bg);
  cursor: pointer;
  transition: border-color 0.25s, background 0.25s;
}

.nuda-drop:hover,
.nuda-drop.is-over {
  border-color: var(--drop-accent);
  background: rgba(228, 255, 84, 0.04);
}

.nuda-drop__icon {
  width: 32px;
  height: 32px;
  color: #a1a1aa;
  animation: nuda-drop-bob 2.4s ease-in-out infinite;
  transition: color 0.25s;
}

.nuda-drop:hover .nuda-drop__icon,
.nuda-drop.is-over .nuda-drop__icon { color: var(--drop-accent); }

.nuda-drop__text {
  font: 600 0.875rem ui-sans-serif, system-ui, sans-serif;
  color: #fafafa;
  margin: 0;
}

.nuda-drop__hint {
  font: 500 0.7rem ui-sans-serif, system-ui, sans-serif;
  color: #63636e;
}

@keyframes nuda-drop-bob {
  0%, 100% { transform: translateY(0); }
  50%      { transform: translateY(-4px); }
}

@media (prefers-reduced-motion: reduce) {
  .nuda-drop__icon { animation: none; }
}

/* Drop Zone — wires up native drag events + click-to-browse. */

(function () {
  var zone = document.querySelector('.nuda-drop');
  if (!zone) return;
  var input = zone.querySelector('input[type="file"]');

  ['dragenter', 'dragover'].forEach(function (ev) {
    zone.addEventListener(ev, function (e) {
      e.preventDefault();
      zone.classList.add('is-over');
    });
  });
  ['dragleave', 'drop'].forEach(function (ev) {
    zone.addEventListener(ev, function (e) {
      e.preventDefault();
      zone.classList.remove('is-over');
    });
  });

  zone.addEventListener('drop', function (e) {
    handle(e.dataTransfer.files);
  });
  zone.addEventListener('click', function () { input && input.click(); });
  input && input.addEventListener('change', function () { handle(input.files); });

  function handle(files) {
    // Replace with your upload logic.
    console.log('files:', files);
  }
})();

/* File Card
   Compact upload row: icon, file name, progress bar, percentage.
   Customize: --p (current %), --fc-accent, --fc-bg */

.nuda-file {
  --p: 0%;
  --fc-accent: #e4ff54;
  --fc-bg: rgba(255, 255, 255, 0.03);
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 10px 12px;
  width: 100%;
  max-width: 320px;
  background: var(--fc-bg);
  border: 1px solid rgba(255, 255, 255, 0.06);
  border-radius: 10px;
  animation: nuda-fc-in 0.5s cubic-bezier(0.4, 0, 0.2, 1);
}

.nuda-file__icon {
  flex-shrink: 0;
  width: 28px;
  height: 28px;
  display: flex;
  align-items: center;
  justify-content: center;
  background: rgba(228, 255, 84, 0.1);
  color: var(--fc-accent);
  border-radius: 6px;
}

.nuda-file__icon svg { width: 16px; height: 16px; }

.nuda-file__info {
  flex: 1;
  min-width: 0;
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.nuda-file__name {
  font: 600 0.75rem ui-sans-serif, system-ui, sans-serif;
  color: #fafafa;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.nuda-file__bar {
  height: 4px;
  background: rgba(255, 255, 255, 0.06);
  border-radius: 2px;
  overflow: hidden;
}

.nuda-file__bar span {
  display: block;
  height: 100%;
  width: 0;
  background: linear-gradient(90deg, var(--fc-accent), rgba(228, 255, 84, 0.6));
  border-radius: 2px;
  box-shadow: 0 0 4px rgba(228, 255, 84, 0.4);
  animation: nuda-fc-prog 2s cubic-bezier(0.4, 0, 0.2, 1) forwards;
}

.nuda-file__pct {
  font: 700 0.7rem ui-sans-serif, system-ui, sans-serif;
  color: #a1a1aa;
  font-variant-numeric: tabular-nums;
  flex-shrink: 0;
}

@keyframes nuda-fc-in {
  from { opacity: 0; transform: translateY(8px); }
  to   { opacity: 1; transform: translateY(0); }
}

@keyframes nuda-fc-prog { to { width: var(--p); } }

@media (prefers-reduced-motion: reduce) {
  .nuda-file,
  .nuda-file__bar span { animation: none; }
  .nuda-file__bar span { width: var(--p); }
}

