/* Multi-File Selector
   Compact accent pill summarizing pending files.
   Customize: --mf-accent */

.nuda-multi {
  --mf-accent: #e4ff54;
  display: inline-flex;
  align-items: center;
  gap: 12px;
  padding: 8px 10px 8px 12px;
  background: rgba(228, 255, 84, 0.06);
  border: 1px solid rgba(228, 255, 84, 0.2);
  border-radius: 10px;
  animation: nuda-mf-in 0.4s cubic-bezier(0.34, 1.56, 0.64, 1);
}

.nuda-multi__icon {
  width: 26px;
  height: 26px;
  display: flex;
  align-items: center;
  justify-content: center;
  color: var(--mf-accent);
  flex-shrink: 0;
  filter: drop-shadow(0 0 4px rgba(228, 255, 84, 0.4));
}

.nuda-multi__icon svg { width: 100%; height: 100%; }

.nuda-multi__info {
  display: flex;
  flex-direction: column;
  line-height: 1;
}

.nuda-multi__count {
  font: 700 0.875rem ui-sans-serif, system-ui, sans-serif;
  color: #fafafa;
  font-variant-numeric: tabular-nums;
}

.nuda-multi__size {
  font: 500 0.7rem ui-sans-serif, system-ui, sans-serif;
  color: #a1a1aa;
  margin-top: 3px;
}

.nuda-multi__clear {
  display: flex;
  align-items: center;
  justify-content: center;
