/* Cmd-K Trigger
   Subtle search-like button with a keyboard shortcut hint.
   Customize: --cmdk-accent */

.nuda-cmdkbtn {
  --cmdk-accent: #e4ff54;
  display: inline-flex;
  align-items: center;
  gap: 10px;
  padding: 8px 8px 8px 12px;
