  color: #a1a1aa;
  font: 500 0.875rem ui-sans-serif, system-ui, sans-serif;
  cursor: pointer;
  transition: border-color 0.25s, background 0.25s, color 0.25s;
  min-width: 240px;
}

.nuda-cmdkbtn:hover {
  border-color: rgba(228, 255, 84, 0.3);
  background: rgba(255, 255, 255, 0.06);
