/* Spotlight Overlay
   Cmd-K style panel: query + divider + result list. Includes entry animation.
   Customize: --sl-bg, --sl-accent */

.nuda-spotlight {
  --sl-bg: rgba(20, 20, 24, 0.95);
  --sl-accent: #e4ff54;
  position: relative;
  width: 100%;
  max-width: 480px;
  padding: 8px;
  background: rgba(0, 0, 0, 0.4);
