/* System Indicator
   Pill showing "auto" mode is active and which OS theme is currently mirrored.
   Customize: --sys-accent */

.nuda-sysind {
  --sys-accent: #e4ff54;
  display: inline-flex;
  align-items: center;
  gap: 12px;
  padding: 9px 12px 9px 10px;
