.nuda-hero-s__line {
  height: 8px;
  background: linear-gradient(90deg, var(--hs-accent), rgba(228, 255, 84, 0.3));
  border-radius: 4px;
}

@keyframes nuda-hs-l {
  from { opacity: 0; transform: translateX(-16px); }
