  from { opacity: 0; transform: translateX(16px) rotate(-3deg); }
  to   { opacity: 1; transform: translateX(0) rotate(-3deg); }
}

@media (prefers-reduced-motion: reduce) {
  .nuda-hero-s__text, .nuda-hero-s__visual { animation: none; }
}

