/* Newsletter Hero
   Headline + email form + reassurance line. Form border glows on focus.
   Customize: --news-accent */

.nuda-news {
  --news-accent: #e4ff54;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 10px;
  padding: 60px 24px;
  text-align: center;
  width: 100%;
  max-width: 540px;
  margin: 0 auto;
}

.nuda-news h2 {
  font: 800 clamp(1.75rem, 4vw, 2.5rem) ui-sans-serif, system-ui, sans-serif;
  color: #fafafa;
  margin: 0 0 4px;
  letter-spacing: -0.02em;
}

.nuda-news__form {
  display: flex;
  align-items: center;
  gap: 6px;
  width: 100%;
  background: rgba(255, 255, 255, 0.04);
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 10px;
  padding: 5px;
  transition: border-color 0.25s, box-shadow 0.25s;
}

.nuda-news__form:focus-within {
  border-color: rgba(228, 255, 84, 0.4);
  box-shadow: 0 0 0 3px rgba(228, 255, 84, 0.1);
}

.nuda-news__input {
  flex: 1;
  background: transparent;
  border: none;
  color: #fafafa;
  font: 500 0.95rem ui-sans-serif, system-ui, sans-serif;
  outline: none;
  padding: 8px 12px;
  min-width: 0;
}

.nuda-news__input::placeholder { color: #63636e; }

.nuda-news__btn {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 36px;
  height: 36px;
  background: var(--news-accent);
  color: #09090b;
  border: none;
  border-radius: 7px;
  font: 700 1.1rem ui-sans-serif, system-ui, sans-serif;
  cursor: pointer;
  transition: transform 0.2s, box-shadow 0.2s;
}

.nuda-news__btn:hover {
  transform: translateX(2px);
  box-shadow: 0 0 12px rgba(228, 255, 84, 0.4);
}

.nuda-news__hint {
  font: 500 0.7rem ui-sans-serif, system-ui, sans-serif;
  color: #63636e;
}

/* Scroll Indicator
   Tiny "mouse" with a wheel that scrolls; whole thing bobs.
   Customize: --si-accent */

.nuda-scrind {
  --si-accent: #e4ff54;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 8px;
  padding: 16px;
  animation: nuda-si-bob 2s ease-in-out infinite;
}

.nuda-scrind__label {
  font: 700 0.625rem ui-sans-serif, system-ui, sans-serif;
  color: #63636e;
  text-transform: uppercase;
  letter-spacing: 0.12em;
}

.nuda-scrind__mouse {
  position: relative;
  width: 22px;
  height: 36px;
  border: 1.5px solid rgba(255, 255, 255, 0.2);
  border-radius: 12px;
  display: flex;
  justify-content: center;
  padding-top: 6px;
}

.nuda-scrind__wheel {
  width: 2px;
  height: 6px;
  background: var(--si-accent);
  border-radius: 1px;
  box-shadow: 0 0 4px rgba(228, 255, 84, 0.5);
  animation: nuda-si-wheel 1.6s cubic-bezier(0.4, 0, 0.2, 1) infinite;
}

.nuda-scrind__chev {
  width: 12px;
  height: 12px;
  color: #63636e;
}

@keyframes nuda-si-bob {
  0%, 100% { transform: translateY(0); }
  50%      { transform: translateY(6px); }
}

@keyframes nuda-si-wheel {
  0%   { transform: translateY(0);    opacity: 1; }
  50%  { transform: translateY(10px); opacity: 0.4; }
  100% { transform: translateY(0);    opacity: 1; }
}

@media (prefers-reduced-motion: reduce) {
  .nuda-scrind,
  .nuda-scrind__wheel { animation: none; }
}

