   Customize: --bv-bg (inner), gradient stops on .nuda-bestv__bg */

.nuda-bestv {
  --bv-bg: rgba(15, 15, 17, 0.95);
  position: relative;
  width: 100%;
  max-width: 240px;
  padding: 2px;
  border-radius: 14px;
  overflow: hidden;
}

.nuda-bestv__bg {
  position: absolute;
  inset: 0;
  background: conic-gradient(
    from 0deg,
    #e4ff54,
    #a78bfa,
    #fb7185,
    #38bdf8,
    #e4ff54
  );
  animation: nuda-bv-rot 4s linear infinite;
}

.nuda-bestv__inner {
  position: relative;
  background: var(--bv-bg);
  border-radius: 12px;
  padding: 16px 20px;
  display: flex;
  flex-direction: column;
  gap: 6px;
  backdrop-filter: blur(8px);
}

.nuda-bestv__tag {
  font: 800 0.625rem ui-sans-serif, system-ui, sans-serif;
  color: #e4ff54;
  text-transform: uppercase;
  letter-spacing: 0.08em;
}

.nuda-bestv__name {
  font: 700 1.25rem ui-sans-serif, system-ui, sans-serif;
  color: #fafafa;
  letter-spacing: -0.02em;
}

.nuda-bestv__price {
  font: 800 1.5rem ui-sans-serif, system-ui, sans-serif;
  color: #fafafa;
  font-variant-numeric: tabular-nums;
  line-height: 1;
}

.nuda-bestv__price i {
  font-size: 0.7rem;
  font-style: normal;
  color: #a1a1aa;
  font-weight: 500;
  margin-left: 2px;
}

@keyframes nuda-bv-rot { to { transform: rotate(360deg); } }

@media (prefers-reduced-motion: reduce) {
  .nuda-bestv__bg { animation: none; }
}

/* Play/Pause Morph
   Two pause bars; .is-paused flattens to a play triangle via clip-path.
   Customize: --pp-bg, --pp-fg */

.nuda-pp {
  --pp-bg: #e4ff54;
  --pp-fg: #09090b;
  position: relative;
  width: 48px;
  height: 48px;
  background: var(--pp-bg);
  border: none;
  border-radius: 50%;
  cursor: pointer;
  transition: transform 0.25s, box-shadow 0.25s, background 0.25s;
  display: flex;
  align-items: center;
  justify-content: center;
}

.nuda-pp:hover {
  transform: scale(1.08);
  box-shadow: 0 0 16px rgba(228, 255, 84, 0.5);
}

.nuda-pp__bar {
  position: absolute;
  width: 6px;
  height: 18px;
  background: var(--pp-fg);
  border-radius: 2px;
  transition: transform 0.35s cubic-bezier(0.4, 0, 0.2, 1);
}

.nuda-pp__bar--l { transform: translateX(-4px); }
.nuda-pp__bar--r { transform: translateX(4px); }

.nuda-pp:hover .nuda-pp__bar--l { transform: translateX(-3px) scaleX(1.2) skewX(-12deg); }
.nuda-pp:hover .nuda-pp__bar--r { transform: translateX(3px)  scaleX(1.2) skewX(12deg); }

.nuda-pp.is-paused .nuda-pp__bar {
  clip-path: polygon(0 0, 100% 50%, 0 100%);
  background: var(--pp-fg);
  transform: translateX(0);
}

.nuda-pp.is-paused .nuda-pp__bar--r { display: none; }

