/* Scrubber
   Track grows on hover; thumb appears; buffered region shown behind progress.
   Customize: --scrub-accent, --scrub-track */

.nuda-scrub {
  --scrub-accent: #e4ff54;
  --scrub-track: rgba(255, 255, 255, 0.1);
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 10px;
  width: 100%;
  max-width: 480px;
}

.nuda-scrub__time {
  font: 600 0.7rem ui-monospace, monospace;
  color: #a1a1aa;
  font-variant-numeric: tabular-nums;
  flex-shrink: 0;
}

.nuda-scrub__track {
  position: relative;
  flex: 1;
  height: 4px;
  background: var(--scrub-track);
  border-radius: 2px;
  cursor: pointer;
  transition: height 0.2s;
}

.nuda-scrub__track:hover { height: 6px; }

.nuda-scrub__buffer {
  position: absolute;
  left: 0;
  top: 0;
  height: 100%;
  background: rgba(255, 255, 255, 0.15);
  border-radius: 2px;
}

.nuda-scrub__progress {
  position: absolute;
  left: 0;
  top: 0;
  height: 100%;
  background: linear-gradient(90deg, var(--scrub-accent), rgba(228, 255, 84, 0.7));
  border-radius: 2px;
  box-shadow: 0 0 4px rgba(228, 255, 84, 0.5);
}

.nuda-scrub__thumb {
  position: absolute;
  top: 50%;
  width: 12px;
  height: 12px;
  border-radius: 50%;
  background: #fafafa;
  transform: translate(-50%, -50%) scale(0);
  transition: transform 0.2s;
  box-shadow: 0 0 8px rgba(228, 255, 84, 0.5);
}

.nuda-scrub__track:hover .nuda-scrub__thumb {
  transform: translate(-50%, -50%) scale(1);
}

/* Volume Slider
   Icon-only by default; bar slides out on hover and fills.
   Customize: --vol-accent, the expanded width. */

.nuda-vol {
  --vol-accent: #e4ff54;
  --vol-expanded: 80px;
  display: inline-flex;
  align-items: center;
  gap: 0;
  background: rgba(0, 0, 0, 0.4);
  padding: 6px 8px;
  border-radius: 8px;
  overflow: hidden;
}

.nuda-vol__icon {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 26px;
  height: 26px;
  background: transparent;
  border: none;
  color: #fafafa;
  cursor: pointer;
  transition: color 0.2s;
}

.nuda-vol__icon:hover { color: var(--vol-accent); }

.nuda-vol__icon svg { width: 16px; height: 16px; }

.nuda-vol__bar {
  width: 0;
  height: 3px;
  background: rgba(255, 255, 255, 0.2);
  border-radius: 2px;
  overflow: hidden;
  opacity: 0;
  transition:
    width 0.3s cubic-bezier(0.4, 0, 0.2, 1),
    margin-left 0.3s,
    opacity 0.25s;
}

.nuda-vol:hover .nuda-vol__bar,
.nuda-vol__icon:focus ~ .nuda-vol__bar {
  width: var(--vol-expanded);
  margin-left: 8px;
  opacity: 1;
}

.nuda-vol__fill {
  display: block;
  height: 100%;
  background: linear-gradient(90deg, var(--vol-accent), rgba(228, 255, 84, 0.6));
  border-radius: 2px;
  transform: scaleX(0);
  transform-origin: left;
  transition: transform 0.3s cubic-bezier(0.4, 0, 0.2, 1) 0.1s;
}

.nuda-vol:hover .nuda-vol__fill { transform: scaleX(1); }

/* Buffer Indicator
   Translucent overlay with spinner for video stalls.
   Customize: --buf-accent */

.nuda-buf {
  --buf-accent: #e4ff54;
  position: relative;
  width: 100%;
  max-width: 480px;
  aspect-ratio: 16 / 9;
  border-radius: 12px;
  overflow: hidden;
  background: linear-gradient(135deg, #1a1a1f, #0e0e10);
}

.nuda-buf__video {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  object-fit: cover;
}

.nuda-buf__overlay {
  position: absolute;
  inset: 0;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 10px;
  background: rgba(0, 0, 0, 0.5);
  backdrop-filter: blur(2px);
}

.nuda-buf__spinner {
  width: 32px;
  height: 32px;
  border: 2.5px solid rgba(255, 255, 255, 0.15);
  border-top-color: var(--buf-accent);
  border-radius: 50%;
  animation: nuda-buf-spin 0.8s linear infinite;
  filter: drop-shadow(0 0 4px rgba(228, 255, 84, 0.4));
}

.nuda-buf__label {
  font: 600 0.75rem ui-sans-serif, system-ui, sans-serif;
  color: #fafafa;
  text-transform: uppercase;
  letter-spacing: 0.08em;
}

@keyframes nuda-buf-spin { to { transform: rotate(360deg); } }

@media (prefers-reduced-motion: reduce) {
  .nuda-buf__spinner { animation: none; }
}

/* Big Play Button
   Centered play CTA over a video; pulsing rings draw attention.
   Customize: --bigp-accent */

.nuda-bigp {
  --bigp-accent: #e4ff54;
  position: relative;
  width: 100%;
  max-width: 480px;
  aspect-ratio: 16 / 9;
  background: linear-gradient(135deg, #1a1a1f, #0e0e10);
  border-radius: 12px;
  overflow: hidden;
  display: flex;
  align-items: center;
  justify-content: center;
}

.nuda-bigp__video {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  object-fit: cover;
}

.nuda-bigp__btn {
  position: relative;
  width: 64px;
  height: 64px;
  background: rgba(228, 255, 84, 0.15);
  border: 2px solid var(--bigp-accent);
  border-radius: 50%;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  color: var(--bigp-accent);
  backdrop-filter: blur(8px);
  transition: transform 0.25s, background 0.25s;
}

.nuda-bigp__btn:hover {
  transform: scale(1.1);
  background: rgba(228, 255, 84, 0.25);
}

.nuda-bigp__pulse {
  position: absolute;
  inset: 0;
  border: 2px solid var(--bigp-accent);
  border-radius: 50%;
  animation: nuda-bigp-pulse 2s ease-out infinite;
  opacity: 0;
}

.nuda-bigp__pulse--b { animation-delay: 1s; }

.nuda-bigp__icon {
  width: 22px;
  height: 22px;
  margin-left: 3px;
  filter: drop-shadow(0 0 4px rgba(228, 255, 84, 0.4));
}

@keyframes nuda-bigp-pulse {
  0%   { transform: scale(1);   opacity: 0.6; }
  100% { transform: scale(1.8); opacity: 0;   }
}

@media (prefers-reduced-motion: reduce) {
  .nuda-bigp__pulse { animation: none; }
}

/* Controls Reveal
   Player chrome that slides up from bottom on hover.
   Customize: --vctrl-accent */

.nuda-vctrl {
  --vctrl-accent: #e4ff54;
  position: relative;
  width: 100%;
  max-width: 480px;
  aspect-ratio: 16 / 9;
  background: linear-gradient(135deg, #1a1a1f, #0e0e10);
  border-radius: 12px;
  overflow: hidden;
}

.nuda-vctrl__video {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  object-fit: cover;
}

.nuda-vctrl__bar {
  position: absolute;
  left: 0;
  right: 0;
  bottom: 0;
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 10px 14px;
  background: linear-gradient(0deg, rgba(0, 0, 0, 0.7), transparent);
  transform: translateY(100%);
  opacity: 0;
  transition: transform 0.3s, opacity 0.3s;
}

.nuda-vctrl:hover .nuda-vctrl__bar {
  transform: translateY(0);
  opacity: 1;
}

.nuda-vctrl__btn {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 24px;
  height: 24px;
  background: transparent;
  border: none;
  color: #fafafa;
  cursor: pointer;
  flex-shrink: 0;
  transition: color 0.2s;
}

.nuda-vctrl__btn:hover { color: var(--vctrl-accent); }

.nuda-vctrl__btn svg { width: 14px; height: 14px; }

.nuda-vctrl__progress {
  flex: 1;
  height: 3px;
  background: rgba(255, 255, 255, 0.2);
  border-radius: 2px;
  overflow: hidden;
}

.nuda-vctrl__progress span {
  display: block;
  height: 100%;
  width: 38%;
  background: var(--vctrl-accent);
  border-radius: 2px;
  box-shadow: 0 0 4px rgba(228, 255, 84, 0.5);
}

.nuda-vctrl__time {
  font: 600 0.7rem ui-monospace, monospace;
  color: #fafafa;
  font-variant-numeric: tabular-nums;
  flex-shrink: 0;
}

/* Speed Selector
   Compact playback-speed pill row.
   Customize: --speed-accent */

.nuda-speed {
  --speed-accent: #e4ff54;
  display: inline-flex;
  background: rgba(0, 0, 0, 0.5);
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 8px;
  padding: 3px;
  backdrop-filter: blur(8px);
}

.nuda-speed__opt {
  padding: 5px 10px;
  font: 700 0.7rem ui-sans-serif, system-ui, sans-serif;
  color: #a1a1aa;
  cursor: pointer;
  border-radius: 5px;
  font-variant-numeric: tabular-nums;
  transition: background 0.2s, color 0.2s;
}

.nuda-speed__opt:hover {
  color: #fafafa;
  background: rgba(255, 255, 255, 0.06);
}

.nuda-speed__opt.is-active {
  background: var(--speed-accent);
  color: #09090b;
  box-shadow: 0 0 6px rgba(228, 255, 84, 0.4);
}

/* Captions Toggle
   "CC" badge with an underline that draws when active.
   Customize: --cc-accent */

.nuda-cc {
  --cc-accent: #e4ff54;
  position: relative;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 7px 12px;
  background: transparent;
  border: none;
  color: #fafafa;
  cursor: pointer;
  transition: color 0.2s;
}

.nuda-cc:hover { color: var(--cc-accent); }

.nuda-cc__box {
  font: 800 0.75rem ui-sans-serif, system-ui, sans-serif;
  letter-spacing: 0.04em;
  padding: 3px 6px;
  border: 1.5px solid currentColor;
  border-radius: 4px;
  line-height: 1;
}

.nuda-cc.is-active { color: var(--cc-accent); }

.nuda-cc.is-active .nuda-cc__box {
  background: rgba(228, 255, 84, 0.15);
  box-shadow: 0 0 4px rgba(228, 255, 84, 0.3);
}

.nuda-cc__line {
  position: absolute;
  left: 50%;
  bottom: -2px;
  width: 0;
  height: 2px;
  background: var(--cc-accent);
  border-radius: 1px;
  transform: translateX(-50%);
  transition: width 0.3s cubic-bezier(0.4, 0, 0.2, 1);
}

.nuda-cc.is-active .nuda-cc__line {
  width: 60%;
  box-shadow: 0 0 4px rgba(228, 255, 84, 0.5);
}

/* Fullscreen Morph
   Four corner brackets fly outward on hover (entering FS) or inward when active.
   Customize: --fs-accent */

.nuda-fs {
  --fs-accent: #e4ff54;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 36px;
  height: 36px;
  background: transparent;
  border: none;
  color: #fafafa;
  cursor: pointer;
  border-radius: 6px;
  transition: background 0.2s, color 0.2s;
}

.nuda-fs:hover {
  background: rgba(228, 255, 84, 0.1);
  color: var(--fs-accent);
}

.nuda-fs svg { width: 18px; height: 18px; }

.nuda-fs path {
  transition: transform 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  transform-origin: center;
}

.nuda-fs:hover .nuda-fs__c1 { transform: translate(-2px, -2px); }
.nuda-fs:hover .nuda-fs__c2 { transform: translate(2px,  -2px); }
.nuda-fs:hover .nuda-fs__c3 { transform: translate(-2px,  2px); }
.nuda-fs:hover .nuda-fs__c4 { transform: translate(2px,   2px); }

.nuda-fs.is-fs .nuda-fs__c1 { transform: translate(2px,  2px); }
.nuda-fs.is-fs .nuda-fs__c2 { transform: translate(-2px, 2px); }
.nuda-fs.is-fs .nuda-fs__c3 { transform: translate(2px, -2px); }
.nuda-fs.is-fs .nuda-fs__c4 { transform: translate(-2px,-2px); }

/* Live Indicator
   Translucent pill: pulsing dot, LIVE text, viewer count separator.
   Customize: --livev-color */

.nuda-livev {
  --livev-color: #ff4d4d;
  display: inline-flex;
  align-items: center;
  gap: 8px;
  padding: 5px 10px;
  background: rgba(0, 0, 0, 0.6);
  border: 1px solid rgba(255, 255, 255, 0.1);
  border-radius: 6px;
  backdrop-filter: blur(8px);
}

.nuda-livev__dot {
  position: relative;
  width: 7px;
  height: 7px;
  border-radius: 50%;
  background: var(--livev-color);
  box-shadow: 0 0 6px var(--livev-color);
}

.nuda-livev__dot::after {
  content: "";
  position: absolute;
  inset: 0;
  border-radius: 50%;
  background: var(--livev-color);
  animation: nuda-livev-pulse 1.4s ease-out infinite;
}

.nuda-livev__label {
  font: 800 0.7rem ui-sans-serif, system-ui, sans-serif;
  color: #fff;
  letter-spacing: 0.08em;
}

.nuda-livev__viewers {
  font: 600 0.7rem ui-sans-serif, system-ui, sans-serif;
  color: #a1a1aa;
  font-variant-numeric: tabular-nums;
  border-left: 1px solid rgba(255, 255, 255, 0.15);
  padding-left: 8px;
}

@keyframes nuda-livev-pulse {
  0%   { transform: scale(1);   opacity: 0.6; }
  100% { transform: scale(2.5); opacity: 0;   }
}

@media (prefers-reduced-motion: reduce) {
  .nuda-livev__dot::after { animation: none; }
}

.nuda-spot {
  position: relative;
  width: 130px;
  height: 90px;
  background: linear-gradient(135deg,#1a1a1f,#0e0e10);
  border-radius: 8px;
  overflow: hidden;
}

.nuda-spot__bg {
  position: absolute;
