/* Tab Bar
   Editor-style file tabs with active underline + per-tab close button.
   Customize: --tabs-accent, --tabs-bg */

.nuda-tabs {
  --tabs-accent: #e4ff54;
  --tabs-bg: #0a0a0a;
  display: inline-flex;
  background: var(--tabs-bg);
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 8px 8px 0 0;
  padding: 4px 4px 0;
  gap: 2px;
}

.nuda-tabs__tab {
  display: inline-flex;
  align-items: center;
  gap: 7px;
  padding: 6px 12px;
  background: transparent;
  color: #a1a1aa;
  font: 500 0.85rem ui-monospace, monospace;
  border-radius: 6px 6px 0 0;
  cursor: pointer;
  transition: background 0.2s, color 0.2s;
  position: relative;
}

.nuda-tabs__tab:hover {
  background: rgba(255, 255, 255, 0.04);
  color: #fafafa;
}

.nuda-tabs__tab.is-active {
  background: rgba(228, 255, 84, 0.08);
  color: #fafafa;
}

.nuda-tabs__tab.is-active::after {
  content: "";
  position: absolute;
  left: 0;
  right: 0;
  bottom: -4px;
  height: 2px;
  background: var(--tabs-accent);
  box-shadow: 0 0 4px rgba(228, 255, 84, 0.5);
}

.nuda-tabs__tab i {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 14px;
  height: 14px;
  color: #63636e;
  font-style: normal;
  font-size: 0.95rem;
  line-height: 1;
  border-radius: 3px;
  transition: background 0.2s, color 0.2s;
}

.nuda-tabs__tab i:hover {
  background: rgba(255, 99, 99, 0.15);
  color: #ff6363;
}

/* Syntax Reveal
   Lines fade-slide in with a stagger driven by the inline --d.
   Customize: --syn-bg, token colors. */

.nuda-syn {
  --syn-bg: #0a0a0a;
  margin: 0;
  padding: 12px 12px 12px 0;
  background: var(--syn-bg);
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 8px;
  font: 500 0.85rem ui-monospace, monospace;
  color: #fafafa;
  width: 100%;
  max-width: 480px;
  overflow: hidden;
  line-height: 1.6;
}

.nuda-syn code {
  display: flex;
  flex-direction: column;
}

.nuda-syn__line {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 0 8px;
  opacity: 0;
  transform: translateX(-8px);
  animation: nuda-syn-in 0.4s cubic-bezier(0.4, 0, 0.2, 1) var(--d, 0s) forwards;
}

.nuda-syn__line i {
  display: inline-flex;
  justify-content: flex-end;
  width: 22px;
  color: #63636e;
  font-style: normal;
  font-size: 0.75rem;
  flex-shrink: 0;
  border-right: 1px solid rgba(255, 255, 255, 0.06);
  padding-right: 6px;
}

.nuda-syn__a { color: #a78bfa; }
.nuda-syn__b { color: #fbbf24; }
.nuda-syn__c { color: #e4ff54; }
.nuda-syn__d { color: #38bdf8; }

@keyframes nuda-syn-in {
  to { opacity: 1; transform: translateX(0); }
}

@media (prefers-reduced-motion: reduce) {
  .nuda-syn__line { animation: none; opacity: 1; transform: none; }
}

