const btn = document.querySelector('.nuda-authload');

btn.addEventListener('click', () => {
  btn.classList.add('is-loading');
  setTimeout(() => {
    btn.classList.remove('is-loading');
    btn.classList.add('is-success');
    btn.querySelector('.nuda-authload__text').textContent = 'Signed in';
  }, 1600);
});

.nuda-authload {
  position: relative;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 10px 22px;
  min-width: 160px;
  background: #e4ff54;
  color: #09090b;
  border: 0;
  border-radius: 10px;
  font-size: 13px;
  font-weight: 600;
  cursor: pointer;
  overflow: hidden;
  transition: background 0.3s;
}

.nuda-authload__text {
  transition: opacity 0.25s, transform 0.35s;
}

.nuda-authload__spinner {
  position: absolute;
  width: 14px;
  height: 14px;
  border-radius: 50%;
  border: 2px solid rgba(9, 9, 11, 0.25);
  border-top-color: #09090b;
  opacity: 0;
  transform: scale(0.6);
  transition: opacity 0.25s, transform 0.35s;
  animation: nuda-auth-spin 0.9s linear infinite;
}

.nuda-authload.is-loading { background: #b8cc43; cursor: progress; }
.nuda-authload.is-loading .nuda-authload__text { opacity: 0; transform: translateX(8px); }
.nuda-authload.is-loading .nuda-authload__spinner { opacity: 1; transform: scale(1); }

.nuda-authload.is-success { background: #6ee7b7; }
.nuda-authload.is-success .nuda-authload__spinner { display: none; }

@keyframes nuda-auth-spin { to { transform: rotate(360deg); } }

.nuda-mini-cal {
  padding: 14px;
  background: rgba(255,255,255,.02);
  border: 1px solid rgba(255,255,255,.06);
  border-radius: 14px;
  width: 100%;
  max-width: 260px;
  animation: _calIn .55s cubic-bezier(.16,1,.3,1) both;
}

.nuda-mini-cal__head {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 10px;
  color: #fafafa;
  font-size: 12px;
  font-weight: 600;
}

.nuda-mini-cal__head button {
  background: rgba(255,255,255,.04);
  border: 1px solid rgba(255,255,255,.08);
  color: #fafafa;
  width: 22px;
  height: 22px;
  border-radius: 6px;
  cursor: pointer;
  font-size: 14px;
  line-height: 1;
  transition: background .2s,transform .2s;
}

.nuda-mini-cal__head button:hover {
  background: rgba(255,255,255,.08);
  transform: translateY(-1px);
}

.nuda-mini-cal__grid {
  display: grid;
  grid-template-columns: repeat(7,1fr);
  gap: 2px;
}

.nuda-mini-cal__dow {
  text-align: center;
  color: #63636e;
  font-size: 10px;
  padding: 2px 0;
}

.nuda-mini-cal__day {
  position: relative;
  background: transparent;
  border: 0;
  color: #a0a0a8;
  width: 30px;
  height: 30px;
  border-radius: 7px;
  cursor: pointer;
  font-size: 11px;
  transition: background .2s,color .2s,transform .15s;
}

.nuda-mini-cal__day:hover {
  background: rgba(255,255,255,.06);
  color: #fafafa;
  transform: scale(1.05);
}

.nuda-mini-cal__day.is-active {
  background: #e4ff54;
  color: #09090b;
  font-weight: 600;
  animation: _dayPop .35s cubic-bezier(.16,1,.3,1);
}

.nuda-mini-cal__day.has-event::after {
  content: '';
  position: absolute;
  left: 50%;
  bottom: 3px;
  transform: translateX(-50%);
  width: 3px;
  height: 3px;
  background: #e4ff54;
  border-radius: 50%;
}

.nuda-mini-cal__day.is-active.has-event::after {
  background: #09090b;
}

@keyframes _calIn {
  from {
    opacity: 0;
    transform: translateY(8px);
  }
  to {
    opacity: 1;
    transform: none;
  }
}

@keyframes _dayPop {
