.nuda-pindrop {
  position: relative;
  display: inline-flex;
  flex-direction: column;
  align-items: center;
  width: 30px;
  height: 50px;
}

.nuda-pindrop svg {
  width: 30px;
  height: 40px;
  animation: _pinFall .7s cubic-bezier(.34,1.56,.64,1);
}

.nuda-pindrop__pin {
  transform-origin: 12px 32px;
  animation: _pinSettle 1.2s cubic-bezier(.34,1.56,.64,1) .55s;
}

.nuda-pindrop__shadow {
  width: 18px;
  height: 5px;
  border-radius: 50%;
  background: rgba(0,0,0,.5);
  filter: blur(2px);
  margin-top: -4px;
  animation: _pinShadow .7s ease-out;
}

@keyframes _pinFall {
  0% {
    transform: translateY(-26px) scale(.6);
    opacity: 0;
  }
  60% {
    transform: translateY(2px) scale(1.08);
  }
  100% {
    transform: translateY(0) scale(1);
    opacity: 1;
  }
}

@keyframes _pinSettle {
  0%,50%,100% {
    transform: scale(1);
  }
  25% {
    transform: scale(.94,1.06);
  }
  75% {
    transform: scale(1.04,.96);
  }
}

@keyframes _pinShadow {
  0% {
    transform: scale(.2);
    opacity: 0;
  }
  60% {
    transform: scale(.6);
  }
  100% {
    transform: scale(1);
    opacity: 1;
  }
}

@media (prefers-reduced-motion:reduce) {
  .nuda-pindrop svg,.nuda-pindrop__pin,.nuda-pindrop__shadow {
    animation: none;
  }
}

