const cluster = document.querySelector('.nuda-cluster');
const center  = cluster.querySelector('.nuda-cluster__center');
center.addEventListener('click', () => cluster.classList.toggle('is-open'));

.nuda-cluster {
  position: relative;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 80px;
  height: 80px;
}

.nuda-cluster__center {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 34px;
  height: 34px;
  border-radius: 50%;
  background: #e4ff54;
  color: #09090b;
  font-weight: 700;
  font-size: 14px;
  box-shadow: 0 0 0 4px rgba(228,255,84,.18),0 0 16px rgba(228,255,84,.4);
  cursor: pointer;
  z-index: 1;
  transition: transform .25s;
}

.nuda-cluster:hover .nuda-cluster__center {
  transform: scale(.9);
}

.nuda-cluster__pin {
  position: absolute;
  display: flex;
  align-items: center;
  justify-content: center;
  width: 20px;
  height: 20px;
  border-radius: 50%;
  background: #62b6ff;
  color: #fafafa;
  font-size: 10px;
  font-weight: 700;
  opacity: 0;
  transform: translate(0,0) scale(0);
  transition: opacity .35s,transform .55s cubic-bezier(.34,1.56,.64,1);
}

.nuda-cluster.is-open .nuda-cluster__pin {
  opacity: 1;
  transform: translate(var(--x),var(--y)) scale(1);
}

.nuda-cluster.is-open .nuda-cluster__pin:nth-child(2) {
  transition-delay: 0ms;
}

.nuda-cluster.is-open .nuda-cluster__pin:nth-child(3) {
  transition-delay: 60ms;
}

.nuda-cluster.is-open .nuda-cluster__pin:nth-child(4) {
  transition-delay: 120ms;
}

.nuda-cluster.is-open .nuda-cluster__pin:nth-child(5) {
  transition-delay: 180ms;
}

.nuda-cluster.is-open .nuda-cluster__pin:nth-child(6) {
  transition-delay: 240ms;
}

.nuda-mappop {
  position: relative;
  display: inline-flex;
  flex-direction: column;
  align-items: center;
  animation: _popIn .5s cubic-bezier(.34,1.56,.64,1);
}

.nuda-mappop__card {
  padding: 8px 12px;
  background: #fafafa;
  color: #09090b;
  border-radius: 8px;
  box-shadow: 0 10px 24px -8px rgba(0,0,0,.5);
}

.nuda-mappop__title {
  font-size: 12px;
  font-weight: 700;
}

.nuda-mappop__meta {
  font-size: 10px;
  color: #63636e;
  margin-top: 1px;
}

.nuda-mappop__tail {
  width: 0;
  height: 0;
  border: 6px solid transparent;
  border-top-color: #fafafa;
  margin-top: -1px;
}

.nuda-mappop__pin {
  margin-top: -2px;
  width: 14px;
  height: 14px;
  border-radius: 50%;
  background: #e4ff54;
  border: 2px solid #fafafa;
  box-shadow: 0 0 0 1px rgba(0,0,0,.3);
}

.nuda-mappop__pin span {
  display: block;
  width: 100%;
  height: 100%;
  border-radius: 50%;
  animation: _popPing 2s ease-out infinite;
  background: #e4ff54;
  opacity: .5;
}

@keyframes _popIn {
  0% {
    transform: translateY(8px) scale(.92);
    opacity: 0;
  }
  60% {
    transform: translateY(-2px) scale(1.04);
  }
  100% {
    transform: none;
    opacity: 1;
  }
}

@keyframes _popPing {
  from {
    transform: scale(1);
    opacity: .5;
  }
  to {
    transform: scale(2.2);
    opacity: 0;
  }
}

@media (prefers-reduced-motion:reduce) {
  .nuda-mappop,.nuda-mappop__pin span {
    animation: none;
  }
}

