/* Digital Clock
   Glowing monospace digits with a blinking colon.
   Customize: --bg, --accent, --dim */

.nuda-digital {
  --bg: #09090b;
  --accent: #e4ff54;
  --dim: rgba(228, 255, 84, 0.15);
  display: inline-flex;
  align-items: baseline;
  gap: 2px;
  padding: 18px 22px;
  background: var(--bg);
  border: 1px solid rgba(255, 255, 255, 0.06);
  border-radius: 12px;
  font-family: ui-monospace, "SF Mono", Menlo, monospace;
  font-size: 48px;
  font-weight: 600;
  color: var(--accent);
  text-shadow: 0 0 12px var(--dim), 0 0 24px var(--dim);
  letter-spacing: -2px;
}

.nuda-digital__d {
  display: inline-block;
  min-width: 0.6em;
  text-align: center;
}

.nuda-digital__sep {
  animation: nuda-digital-blink 1s steps(2) infinite;
}

.nuda-digital__ampm {
  margin-left: 10px;
  font-size: 14px;
  letter-spacing: 1px;
  opacity: 0.7;
  align-self: center;
}

@keyframes nuda-digital-blink {
  50% { opacity: 0.2; }
}

@media (prefers-reduced-motion: reduce) {
  .nuda-digital__sep { animation: none; }
}

/* Flip Clock
   Split-flap aesthetic. The bottom half folds down to reveal a new digit.
   In a real implementation, JS would swap the values on each tick. */

.nuda-flip {
  --bg: #111114;
  --ink: #fafafa;
  display: inline-flex;
  align-items: center;
  gap: 6px;
  padding: 14px;
  background: #09090b;
  border: 1px solid rgba(255, 255, 255, 0.06);
  border-radius: 12px;
}

.nuda-flip__card {
  position: relative;
  width: 46px;
  height: 64px;
  border-radius: 8px;
  background: var(--bg);
  overflow: hidden;
  box-shadow: inset 0 -1px 0 rgba(255, 255, 255, 0.04);
}

.nuda-flip__top,
.nuda-flip__bot {
  position: absolute;
  left: 0;
  right: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  height: 50%;
  font-family: ui-monospace, Menlo, monospace;
  font-size: 36px;
  font-weight: 700;
  color: var(--ink);
  overflow: hidden;
}

.nuda-flip__top {
  top: 0;
  background: linear-gradient(180deg, #1c1c22, #15151a);
  align-items: flex-end;
  padding-bottom: 2px;
}

.nuda-flip__bot {
  bottom: 0;
  background: linear-gradient(180deg, #0e0e12, #16161c);
  align-items: flex-start;
  padding-top: 2px;
}

.nuda-flip__bot--anim {
  transform-origin: top;
  animation: nuda-flip-drop 4s ease-in-out infinite;
}

.nuda-flip__hinge {
  position: absolute;
  left: 0;
  right: 0;
  top: 50%;
  height: 1px;
  background: rgba(0, 0, 0, 0.5);
  box-shadow: 0 1px 0 rgba(255, 255, 255, 0.04);
}

.nuda-flip__colon {
  font: 600 28px ui-monospace, Menlo, monospace;
  color: var(--ink);
  opacity: 0.6;
  animation: nuda-flip-blink 1s steps(2) infinite;
