/* Pomodoro Timer Ring
   SVG arc countdown over 25 minutes (1500s) for the classic Pomodoro session.
   Customize: --accent for break/work mode coloring */

.nuda-pomo {
  --accent: #ff5e7a;
  --bg: #0c0c10;
  position: relative;
  width: 140px;
  height: 140px;
  display: inline-grid;
  place-items: center;
  background: var(--bg);
  border-radius: 50%;
  border: 1px solid rgba(255, 255, 255, 0.06);
}

.nuda-pomo__svg {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  transform: rotate(-90deg);
}

.nuda-pomo__track {
  fill: none;
  stroke: rgba(255, 255, 255, 0.08);
  stroke-width: 6;
}

.nuda-pomo__bar {
  fill: none;
  stroke: var(--accent);
  stroke-width: 6;
  stroke-linecap: round;
  stroke-dasharray: 326.7; /* 2 * PI * 52 */
  stroke-dashoffset: 90;
  filter: drop-shadow(0 0 6px var(--accent));
  animation: nuda-pomo-tick 1500s linear forwards;
}

.nuda-pomo__inner {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 4px;
  z-index: 1;
}

.nuda-pomo__time {
  font: 600 26px ui-monospace, Menlo, monospace;
  color: #fafafa;
  letter-spacing: -1px;
}

.nuda-pomo__label {
  font: 500 10px system-ui, sans-serif;
  letter-spacing: 2px;
  color: var(--accent);
}

@keyframes nuda-pomo-tick {
  to { stroke-dashoffset: 326.7; }
}

@media (prefers-reduced-motion: reduce) {
  .nuda-pomo__bar { animation: none; }
}

/* Stopwatch
   Sweeping seconds hand with a digital readout and last-lap marker.
   Customize: --accent, --bg */

.nuda-sw {
  --accent: #e4ff54;
  --bg: #0c0c10;
  position: relative;
  display: inline-block;
  padding: 14px;
  background: var(--bg);
  border-radius: 14px;
  border: 1px solid rgba(255, 255, 255, 0.06);
}

.nuda-sw__crown {
  position: absolute;
  top: -6px;
  left: 50%;
  width: 14px;
  height: 8px;
  margin-left: -7px;
  background: #1a1a20;
  border: 1px solid rgba(255, 255, 255, 0.1);
  border-radius: 3px;
}

.nuda-sw__face {
  position: relative;
  width: 150px;
  height: 150px;
  border-radius: 50%;
  background: radial-gradient(circle at 50% 40%, #15151a, #09090b);
  display: grid;
  place-items: center;
}

.nuda-sw__svg {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
}

.nuda-sw__bezel {
  fill: none;
  stroke: rgba(255, 255, 255, 0.06);
  stroke-width: 1;
}

.nuda-sw__hand {
  stroke: var(--accent);
  stroke-width: 2;
  stroke-linecap: round;
  transform-origin: 60px 60px;
  animation: nuda-sw-sweep 60s linear infinite;
  filter: drop-shadow(0 0 4px var(--accent));
}

.nuda-sw__time {
  font: 600 22px ui-monospace, Menlo, monospace;
  color: #fafafa;
  z-index: 1;
}

.nuda-sw__time span {
  color: var(--accent);
  font-size: 18px;
}

.nuda-sw__laps {
  position: absolute;
  bottom: 24px;
  font: 500 9px system-ui;
  letter-spacing: 1.5px;
  color: #63636e;
  z-index: 1;
}

@keyframes nuda-sw-sweep {
  to { transform: rotate(360deg); }
}

@media (prefers-reduced-motion: reduce) {
  .nuda-sw__hand { animation: none; }
}

