.nuda-world__sun {
  position: absolute;
  top: -3px;
  left: 18%;
  width: 9px;
  height: 9px;
  border-radius: 50%;
  background: var(--accent);
  box-shadow: 0 0 8px var(--accent);
  animation: nuda-world-glow 3s ease-in-out infinite;
}

.nuda-world__foot {
  display: flex;
