/* Countdown Ring
   SVG circle with gradient stroke that draws on mount.
   Set stroke-dashoffset via JS each tick for live updates. */

.nuda-cd {
  position: relative;
  width: 150px;
  height: 150px;
  display: inline-grid;
  place-items: center;
}

.nuda-cd__svg {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  transform: rotate(-90deg);
}

.nuda-cd__track {
  fill: none;
  stroke: rgba(255, 255, 255, 0.06);
  stroke-width: 8;
}

.nuda-cd__bar {
  fill: none;
  stroke: url(#nuda-cd-grad);
  stroke-width: 8;
  stroke-linecap: round;
  stroke-dasharray: 314.15; /* 2 * PI * 50 */
  stroke-dashoffset: 314.15;
  animation: nuda-cd-draw 2.4s cubic-bezier(0.16, 1, 0.3, 1) forwards;
}

.nuda-cd__inner {
  display: flex;
  flex-direction: column;
  align-items: center;
  z-index: 1;
}

.nuda-cd__num {
  font: 700 44px system-ui;
  color: #fafafa;
  line-height: 1;
  letter-spacing: -2px;
}

.nuda-cd__unit {
  font: 500 10px system-ui;
  color: #a0a0a8;
  letter-spacing: 2px;
  margin-top: 4px;
}

@keyframes nuda-cd-draw {
  to { stroke-dashoffset: 78; }
}

@media (prefers-reduced-motion: reduce) {
  .nuda-cd__bar { animation: none; stroke-dashoffset: 78; }
}

/* Tick Marks Face
   60 minute marks; every 5th is a major hour tick.
   Generate via a CSS preprocessor or template loop. */

.nuda-ticks {
  --bg: #0c0c10;
  --accent: #e4ff54;
  display: inline-block;
  padding: 14px;
  background: var(--bg);
  border-radius: 50%;
  border: 1px solid rgba(255, 255, 255, 0.06);
}

.nuda-ticks__face {
  position: relative;
  width: 160px;
  height: 160px;
  border-radius: 50%;
  background: radial-gradient(circle, #111114, #09090b);
}

.nuda-ticks__t {
  position: absolute;
  left: 50%;
  top: 50%;
  width: 1px;
  height: 6px;
  margin-left: -0.5px;
  background: rgba(255, 255, 255, 0.25);
  transform-origin: center 72px;
}

.nuda-ticks__t--major {
  width: 2px;
  height: 10px;
  margin-left: -1px;
  background: var(--accent);
  box-shadow: 0 0 4px rgba(228, 255, 84, 0.4);
}

.nuda-ticks__dot {
  position: absolute;
  left: 50%;
  top: 50%;
  width: 6px;
  height: 6px;
  margin: -3px 0 0 -3px;
  border-radius: 50%;
  background: var(--accent);
  animation: nuda-ticks-pulse 2s ease-in-out infinite;
}

@keyframes nuda-ticks-pulse {
  50% { transform: scale(1.4); opacity: 0.6; }
}

@media (prefers-reduced-motion: reduce) {
  .nuda-ticks__dot { animation: none; }
}

/* Swiss Railway Clock
   Iconic Hans Hilfiker design. The seconds hand sweeps in 60 discrete
   steps with the red disc tip. */

.nuda-swiss {
  --bg: #fafafa;
  --ink: #09090b;
  --red: #ff5e7a;
  display: inline-block;
  padding: 10px;
  background: #0c0c10;
  border-radius: 50%;
  border: 1px solid rgba(255, 255, 255, 0.06);
}

.nuda-swiss__face {
  position: relative;
  width: 160px;
  height: 160px;
  border-radius: 50%;
  background: var(--bg);
  box-shadow: inset 0 0 0 4px var(--ink);
}

.nuda-swiss__h {
  position: absolute;
  left: 50%;
  top: 50%;
  width: 4px;
  height: 12px;
  margin-left: -2px;
  background: var(--ink);
  transform-origin: center 66px;
}

.nuda-swiss__hour,
.nuda-swiss__min {
  position: absolute;
  left: 50%;
  bottom: 50%;
  background: var(--ink);
  transform-origin: bottom center;
  border-radius: 2px;
}

.nuda-swiss__hour {
  width: 6px;
  height: 42px;
  margin-left: -3px;
}

.nuda-swiss__min {
  width: 4px;
  height: 62px;
  margin-left: -2px;
}

.nuda-swiss__sec {
  position: absolute;
  left: 50%;
  bottom: 50%;
  width: 0;
  transform-origin: bottom center;
  animation: nuda-swiss-sec 60s steps(60) infinite;
}

.nuda-swiss__secBar {
  position: absolute;
  left: -1px;
  bottom: 0;
  width: 2px;
  height: 68px;
  background: var(--red);
}

.nuda-swiss__secDot {
  position: absolute;
  left: -7px;
  top: -72px;
  width: 16px;
  height: 16px;
  border-radius: 50%;
  background: var(--red);
