/* Sand Hourglass
   Top chamber drains while the bottom fills, with falling grains.
   Two clip-paths form the triangular hourglass profile. */

.nuda-hg {
  --sand: #ffb45e;
  --glass: rgba(255, 255, 255, 0.06);
  position: relative;
  display: inline-block;
  width: 80px;
  padding: 6px;
}

.nuda-hg__top,
.nuda-hg__bot {
  position: relative;
  width: 80px;
  height: 48px;
  background: var(--glass);
  border: 1px solid rgba(255, 255, 255, 0.08);
  overflow: hidden;
}

.nuda-hg__top {
  border-radius: 4px 4px 50% 50% / 4px 4px 30% 30%;
  clip-path: polygon(0 0, 100% 0, 55% 100%, 45% 100%);
}

.nuda-hg__bot {
  border-radius: 50% 50% 4px 4px / 30% 30% 4px 4px;
  clip-path: polygon(45% 0, 55% 0, 100% 100%, 0 100%);
  margin-top: -1px;
}

.nuda-hg__sandTop {
  position: absolute;
  inset: 0;
  background: var(--sand);
  animation: nuda-hg-drain 6s linear infinite;
}

.nuda-hg__sandBot {
  position: absolute;
  left: 0;
  right: 0;
  bottom: 0;
  height: 0;
  background: var(--sand);
  animation: nuda-hg-fill 6s linear infinite;
}

.nuda-hg__neck {
  position: relative;
  width: 8px;
  height: 6px;
  margin: -1px auto;
  background: #0c0c10;
  border-left: 1px solid rgba(255, 255, 255, 0.08);
  border-right: 1px solid rgba(255, 255, 255, 0.08);
}

.nuda-hg__stream {
  position: absolute;
  left: 50%;
  top: 0;
  width: 1.5px;
  height: 6px;
  margin-left: -0.75px;
  background: var(--sand);
}

.nuda-hg__grain {
  position: absolute;
  left: 50%;
  top: 0;
  width: 2px;
  height: 2px;
  background: var(--sand);
  border-radius: 50%;
  animation: nuda-hg-grain 1.4s linear infinite;
}

@keyframes nuda-hg-drain { to { height: 0; } }
@keyframes nuda-hg-fill  { to { height: 100%; } }
@keyframes nuda-hg-grain {
  0%   { top: 0;     opacity: 1; }
  80%  {             opacity: 1; }
  100% { top: 40px;  opacity: 0; }
}

@media (prefers-reduced-motion: reduce) {
  .nuda-hg__sandTop,
  .nuda-hg__sandBot,
  .nuda-hg__grain { animation: none; }
  .nuda-hg__sandTop { height: 50%; }
  .nuda-hg__sandBot { height: 50%; }
}

