/* Binary Clock
   Six columns of 4 dots representing BCD-encoded hours, minutes, seconds.
   Lit dots use the accent color with a subtle glow pulse. */

.nuda-bin {
  --accent: #6ee7b7;
  --off: #1a1a20;
  display: inline-block;
  padding: 14px;
  background: #09090b;
  border: 1px solid rgba(255, 255, 255, 0.06);
  border-radius: 10px;
  font-family: ui-monospace, Menlo, monospace;
  color: #fafafa;
}

.nuda-bin__label {
  font-size: 9px;
  letter-spacing: 3px;
  color: #63636e;
  margin-bottom: 8px;
  text-align: center;
}

.nuda-bin__grid {
  display: grid;
  grid-template-columns: repeat(6, 1fr);
  gap: 6px;
}

.nuda-bin__col {
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.nuda-bin__dot {
  width: 14px;
  height: 14px;
  border-radius: 50%;
  background: var(--off);
  border: 1px solid rgba(255, 255, 255, 0.06);
}

.nuda-bin__dot--on {
  background: var(--accent);
  box-shadow: 0 0 8px var(--accent);
  animation: nuda-bin-glow 3s ease-in-out infinite;
}

.nuda-bin__dot--on:nth-child(2) { animation-delay: 0.4s; }
.nuda-bin__dot--on:nth-child(3) { animation-delay: 0.8s; }

.nuda-bin__foot {
  margin-top: 10px;
  text-align: center;
  font-size: 11px;
  letter-spacing: 2px;
  color: #a0a0a8;
}

@keyframes nuda-bin-glow {
  0%, 100% { box-shadow: 0 0 8px var(--accent); }
  50%      { box-shadow: 0 0 14px var(--accent); }
}

@media (prefers-reduced-motion: reduce) {
  .nuda-bin__dot--on { animation: none; }
}

