/* Verified Customer Badge
   Customer testimonial with a pop-in verification checkmark. */

.nuda-verified {
  max-width: 380px;
  padding: 1.5rem;
  background: #0c0c10;
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 14px;
  color: #fafafa;
  font-family: ui-sans-serif, system-ui, sans-serif;
}

.nuda-verified__quote {
  margin: 0 0 1rem;
  font-size: 0.9375rem;
  line-height: 1.55;
}

.nuda-verified__footer {
  display: flex;
  align-items: center;
  gap: 0.75rem;
}

.nuda-verified__avatar {
  width: 36px;
  height: 36px;
  border-radius: 50%;
  background: linear-gradient(135deg, #62b6ff, #6ee7b7);
  display: grid;
  place-items: center;
  font-size: 0.75rem;
  font-weight: 700;
  color: #0c0c10;
  flex-shrink: 0;
}

.nuda-verified__name {
  display: flex;
  align-items: center;
  gap: 0.375rem;
  font-size: 0.875rem;
  font-weight: 600;
  line-height: 1.2;
}

.nuda-verified__badge {
  display: inline-grid;
  place-items: center;
  width: 16px;
  height: 16px;
  animation: nuda-vb-pop 0.5s cubic-bezier(0.34, 1.56, 0.64, 1) 0.2s both;
}

.nuda-verified__badge svg { width: 16px; height: 16px; }

@keyframes nuda-vb-pop {
  from { transform: scale(0); opacity: 0; }
  to   { transform: scale(1); opacity: 1; }
}

.nuda-verified__role {
  margin-top: 0.125rem;
  font-size: 0.75rem;
  color: #a0a0a8;
}

@media (prefers-reduced-motion: reduce) {
  .nuda-verified__badge { animation: none; }
}

/* Testimonial Grid Masonry
   Two-column staggered grid using grid-row: span N for tall cards. */

.nuda-masonry {
  max-width: 480px;
  display: grid;
  grid-template-columns: 1fr 1fr;
  grid-auto-rows: minmax(80px, auto);
  gap: 0.75rem;
  font-family: ui-sans-serif, system-ui, sans-serif;
}

.nuda-masonry__card {
  padding: 1rem;
  background: #0c0c10;
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 12px;
  color: #fafafa;
  display: flex;
  flex-direction: column;
  justify-content: space-between;
  gap: 0.75rem;
  transition:
    border-color 0.3s cubic-bezier(0.16, 1, 0.3, 1),
    transform 0.3s cubic-bezier(0.16, 1, 0.3, 1);
}

.nuda-masonry__card:hover {
  border-color: rgba(255, 255, 255, 0.16);
  transform: translateY(-2px);
}

.nuda-masonry__card p {
  margin: 0;
  font-size: 0.8125rem;
  line-height: 1.5;
}

.nuda-masonry__card footer {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  font-size: 0.6875rem;
  color: #a0a0a8;
}

.nuda-masonry__avatar {
  width: 22px;
  height: 22px;
  border-radius: 50%;
  display: grid;
  place-items: center;
  font-size: 0.5625rem;
  font-weight: 700;
  color: #0c0c10;
  flex-shrink: 0;
}

@media (prefers-reduced-motion: reduce) {
  .nuda-masonry__card { transition: none; }
  .nuda-masonry__card:hover { transform: none; }
}

/* Quote with Spotlight
   Radial highlight slowly drifts behind the quote. */

.nuda-spotlight {
  position: relative;
  max-width: 420px;
  padding: 2rem 1.75rem 1.5rem;
  background: #0c0c10;
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 16px;
  color: #fafafa;
  font-family: ui-sans-serif, system-ui, sans-serif;
  overflow: hidden;
  isolation: isolate;
}

.nuda-spotlight__glow {
  position: absolute;
  top: -40%;
  left: -20%;
  width: 80%;
  height: 160%;
  background: radial-gradient(
    closest-side,
    rgba(228, 255, 84, 0.22),
    transparent 70%
  );
  filter: blur(8px);
  z-index: -1;
  animation: nuda-sp-drift 8s ease-in-out infinite;
}

@keyframes nuda-sp-drift {
  0%, 100% { transform: translate(0, 0); }
  50%      { transform: translate(40%, 10%); }
}

.nuda-spotlight__mark {
  position: absolute;
  top: -0.5rem;
  right: 1rem;
  font-size: 5rem;
  line-height: 1;
  color: #e4ff54;
  font-family: Georgia, serif;
  opacity: 0.18;
  font-weight: 700;
  pointer-events: none;
}

.nuda-spotlight p {
  margin: 0 0 1.25rem;
  font-size: 1rem;
  line-height: 1.55;
  position: relative;
  z-index: 1;
}

.nuda-spotlight footer {
  display: flex;
  align-items: center;
  gap: 0.625rem;
  font-size: 0.8125rem;
  color: #a0a0a8;
}

.nuda-spotlight__avatar {
  width: 30px;
  height: 30px;
  border-radius: 50%;
  background: linear-gradient(135deg, #e4ff54, #ffb45e);
  display: grid;
  place-items: center;
  font-size: 0.6875rem;
  font-weight: 700;
  color: #0c0c10;
}

@media (prefers-reduced-motion: reduce) {
  .nuda-spotlight__glow { animation: none; }
}

/* Numbered Stat Quote
   Big gradient number leads a supporting quote. */

.nuda-stat-quote {
  max-width: 380px;
  padding: 1.5rem;
  background: #0c0c10;
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 14px;
  color: #fafafa;
