/* Inline Quote with Link
   Inline blockquote tucked into running prose with animated link underlines. */

.nuda-inline-quote {
  max-width: 480px;
  margin: 0;
  padding: 1rem 1.25rem;
  background: #0c0c10;
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 12px;
  color: #a0a0a8;
  font-family: ui-sans-serif, system-ui, sans-serif;
  font-size: 0.9375rem;
  line-height: 1.6;
}

.nuda-inline-quote__link {
  position: relative;
  color: #fafafa;
  font-weight: 500;
  text-decoration: none;
  background-image: linear-gradient(#e4ff54, #e4ff54);
  background-size: 0% 1px;
  background-position: 0 100%;
  background-repeat: no-repeat;
  transition:
    background-size 0.4s cubic-bezier(0.16, 1, 0.3, 1),
    color 0.3s ease;
}

.nuda-inline-quote__link:hover,
.nuda-inline-quote__link:focus-visible {
  background-size: 100% 1px;
  color: #e4ff54;
  outline: none;
}

.nuda-inline-quote__q {
  font-style: italic;
  color: #fafafa;
  quotes: "\201C" "\201D";
}

.nuda-inline-quote__q::before {
  content: open-quote;
  color: #e4ff54;
  margin-right: 0.05em;
}

.nuda-inline-quote__q::after {
  content: close-quote;
  color: #e4ff54;
  margin-left: 0.05em;
}

@media (prefers-reduced-motion: reduce) {
  .nuda-inline-quote__link { transition: none; }
}

/* Comment Thread
   Avatar + body + meta time with subtle entrance.
   Customize: --c-bg, --c-border, --c-accent */

.nuda-comment-thread {
  --c-bg: #0c0c10;
  --c-border: #1c1c22;
  display: flex;
  gap: 12px;
  padding: 14px;
  background: var(--c-bg);
  border: 1px solid var(--c-border);
  border-radius: 12px;
  max-width: 420px;
  animation: nuda-ct-fade 0.5s cubic-bezier(0.16, 1, 0.3, 1) both;
}

.nuda-comment-thread__avatar {
  width: 36px;
  height: 36px;
  border-radius: 50%;
  background: linear-gradient(135deg, #9d6dff, #62b6ff);
  color: #fafafa;
  font-size: 13px;
  font-weight: 600;
  display: grid;
  place-items: center;
  flex-shrink: 0;
}

.nuda-comment-thread__body { flex: 1; min-width: 0; }

.nuda-comment-thread__header {
  display: flex;
  align-items: baseline;
  gap: 8px;
  margin-bottom: 4px;
}

.nuda-comment-thread__name {
  color: #fafafa;
  font-size: 13px;
  font-weight: 600;
}

.nuda-comment-thread__time {
  color: #63636e;
  font-size: 11px;
}

.nuda-comment-thread__text {
  color: #a0a0a8;
  font-size: 13px;
  line-height: 1.5;
  margin: 0;
}

@keyframes nuda-ct-fade {
  from { opacity: 0; transform: translateY(6px); }
  to { opacity: 1; transform: translateY(0); }
}

@media (prefers-reduced-motion: reduce) {
  .nuda-comment-thread { animation: none; }
}

.nuda-reply-nested {
  display: flex;
  flex-direction: column;
  gap: 10px;
  max-width: 440px;
}

.nuda-reply-nested__parent,.nuda-reply-nested__child {
  display: flex;
  gap: 10px;
  padding: 12px;
  background: #0c0c10;
  border: 1px solid #1c1c22;
  border-radius: 10px;
}

.nuda-reply-nested__children {
  position: relative;
  padding-left: 28px;
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.nuda-reply-nested__children::before {
  content: "";
  position: absolute;
  left: 14px;
  top: 0;
  bottom: 8px;
  width: 2px;
  background: linear-gradient(180deg,#e4ff54,transparent);
  transform-origin: top;
  animation: _rngrow .6s cubic-bezier(.16,1,.3,1) both;
}

.nuda-reply-nested__avatar {
  width: 28px;
  height: 28px;
  border-radius: 50%;
  color: #fafafa;
  font-size: 11px;
  font-weight: 600;
  display: grid;
  place-items: center;
  flex-shrink: 0;
}

.nuda-reply-nested__body {
  flex: 1;
  min-width: 0;
}

.nuda-reply-nested__name {
  color: #fafafa;
  font-size: 12px;
  font-weight: 600;
  display: block;
  margin-bottom: 2px;
}

.nuda-reply-nested__text {
  color: #a0a0a8;
  font-size: 12px;
  line-height: 1.5;
  margin: 0;
}

.nuda-reply-nested__child {
  animation: _rnslide .5s cubic-bezier(.16,1,.3,1) both;
}

@keyframes _rngrow {
  from {
    transform: scaleY(0);
  }
  to {
    transform: scaleY(1);
  }
}

@keyframes _rnslide {
  from {
    opacity: 0;
    transform: translateX(-8px);
  }
  to {
    opacity: 1;
    transform: translateX(0);
  }
}

@media (prefers-reduced-motion:reduce) {
  .nuda-reply-nested__children::before,.nuda-reply-nested__child {
    animation: none;
    transform: none;
    opacity: 1;
  }
}

/* Emoji Reaction Picker
   Popover with 6 reactions; each pops in then scales on hover.
   Customize: --ep-bg, --ep-border */

.nuda-emoji-picker {
  --ep-bg: #111114;
  --ep-border: #1c1c22;
  display: inline-flex;
  gap: 4px;
  padding: 6px;
  background: var(--ep-bg);
  border: 1px solid var(--ep-border);
  border-radius: 999px;
  box-shadow: 0 8px 24px rgba(0, 0, 0, 0.4);
}

.nuda-emoji-picker__btn {
  width: 32px;
  height: 32px;
  display: grid;
  place-items: center;
  background: transparent;
  border: 0;
  border-radius: 50%;
  font-size: 18px;
  cursor: pointer;
  transition:
    transform 0.25s cubic-bezier(0.16, 1, 0.3, 1),
    background 0.2s;
  animation: nuda-ep-in 0.4s cubic-bezier(0.16, 1, 0.3, 1) both;
  padding: 0;
}

.nuda-emoji-picker__btn:hover {
  background: #1c1c22;
  transform: scale(1.3) translateY(-3px);
}

.nuda-emoji-picker__btn:focus-visible {
  outline: 2px solid #e4ff54;
  outline-offset: 2px;
}

@keyframes nuda-ep-in {
  from { opacity: 0; transform: scale(0.3) translateY(8px); }
  to { opacity: 1; transform: scale(1) translateY(0); }
}

@media (prefers-reduced-motion: reduce) {
  .nuda-emoji-picker__btn {
    animation: none;
    transition: none;
  }
  .nuda-emoji-picker__btn:hover {
    transform: none;
    background: #1c1c22;
  }
}

