/* Like Button
   Heart fills + ripple glow when toggled on.
   Toggle aria-pressed="true" in JS to lock the liked state. */

.nuda-like-btn {
  position: relative;
  display: inline-flex;
  align-items: center;
  gap: 6px;
  padding: 7px 14px 7px 12px;
  background: #0c0c10;
  border: 1px solid #1c1c22;
  border-radius: 999px;
  color: #a0a0a8;
  font-size: 12px;
  font-weight: 500;
  cursor: pointer;
  overflow: hidden;
  transition: color 0.25s, border-color 0.25s;
}

.nuda-like-btn__icon {
  width: 16px;
  height: 16px;
  color: #a0a0a8;
  transition: color 0.25s, transform 0.35s cubic-bezier(0.16, 1, 0.3, 1);
}

.nuda-like-btn__ripple {
  position: absolute;
  inset: 0;
  background: radial-gradient(circle at center, rgba(255, 94, 122, 0.25), transparent 65%);
