  fill: #ff5e7a;
  animation: nuda-lb-pop 0.5s cubic-bezier(0.16, 1, 0.3, 1);
}

.nuda-like-btn:focus-visible {
  outline: 2px solid #e4ff54;
  outline-offset: 2px;
}

