/* Comment Loading Skeleton
   Avatar + four lines with a shimmer sweep.
   Customize: shimmer tint by editing the gradient color. */

.nuda-comment-skel {
  display: flex;
  gap: 12px;
  padding: 14px;
  background: #0c0c10;
  border: 1px solid #1c1c22;
  border-radius: 12px;
  max-width: 420px;
}

.nuda-comment-skel__avatar {
  width: 36px;
  height: 36px;
  border-radius: 50%;
  flex-shrink: 0;
  background: #1c1c22;
  position: relative;
  overflow: hidden;
}

.nuda-comment-skel__body {
  flex: 1;
  display: flex;
  flex-direction: column;
  gap: 8px;
  padding-top: 4px;
}

.nuda-comment-skel__line {
  height: 10px;
  border-radius: 5px;
  background: #1c1c22;
  position: relative;
  overflow: hidden;
}

.nuda-comment-skel__line--head { width: 35%; height: 8px; }
.nuda-comment-skel__line--w90  { width: 90%; }
.nuda-comment-skel__line--w70  { width: 70%; }
.nuda-comment-skel__line--w50  { width: 50%; }

.nuda-comment-skel__avatar::after,
.nuda-comment-skel__line::after {
  content: "";
  position: absolute;
  inset: 0;
  background: linear-gradient(
    90deg,
    transparent,
    rgba(228, 255, 84, 0.08) 50%,
    transparent
  );
  transform: translateX(-100%);
  animation: nuda-cskel 1.6s ease-in-out infinite;
}

@keyframes nuda-cskel {
  to { transform: translateX(100%); }
}

@media (prefers-reduced-motion: reduce) {
  .nuda-comment-skel__avatar::after,
  .nuda-comment-skel__line::after {
    animation: none;
    opacity: 0.4;
    transform: none;
  }
}

/* Pinned Comment
   Highlighted card with a wobbling pin icon and accent stripe.
   Customize: --pin-accent */

.nuda-pinned {
  --pin-accent: #e4ff54;
  position: relative;
  padding: 14px;
  background: linear-gradient(
    135deg,
    rgba(228, 255, 84, 0.08),
    rgba(228, 255, 84, 0.02)
  );
  border: 1px solid rgba(228, 255, 84, 0.35);
  border-radius: 12px;
  max-width: 420px;
  overflow: hidden;
}

.nuda-pinned::before {
  content: "";
  position: absolute;
  left: 0;
  top: 0;
  bottom: 0;
  width: 3px;
  background: var(--pin-accent);
}

.nuda-pinned__tag {
  display: inline-flex;
  align-items: center;
  gap: 5px;
  color: var(--pin-accent);
  font-size: 11px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.04em;
  margin-bottom: 8px;
}

.nuda-pinned__pin {
  width: 12px;
  height: 12px;
  animation: nuda-pin-wobble 4s cubic-bezier(0.16, 1, 0.3, 1) infinite;
  transform-origin: 50% 30%;
}

.nuda-pinned__row {
  display: flex;
  gap: 10px;
  align-items: flex-start;
}

.nuda-pinned__avatar {
  width: 32px;
  height: 32px;
  border-radius: 50%;
  background: linear-gradient(135deg, #e4ff54, #6ee7b7);
  color: #09090b;
  font-size: 11px;
  font-weight: 700;
  display: grid;
  place-items: center;
  flex-shrink: 0;
}

.nuda-pinned__name {
  color: #fafafa;
  font-size: 13px;
  font-weight: 600;
  margin-bottom: 2px;
}

.nuda-pinned__text {
  color: #a0a0a8;
  font-size: 13px;
  line-height: 1.5;
  margin: 0;
}

@keyframes nuda-pin-wobble {
  0%, 90%, 100% { transform: rotate(0); }
  93% { transform: rotate(-15deg); }
  96% { transform: rotate(12deg); }
}

@media (prefers-reduced-motion: reduce) {
  .nuda-pinned__pin { animation: none; }
}

.nuda-hl-reply {
  position: relative;
  padding: 1.5px;
  border-radius: 13px;
  max-width: 420px;
  background: conic-gradient(from 0deg,#9d6dff,#62b6ff,#6ee7b7,#e4ff54,#9d6dff);
  background-size: 200% 200%;
  animation: _hlrotate 5s linear infinite;
}

.nuda-hl-reply::after {
  content: "";
  position: absolute;
  inset: 0;
  border-radius: inherit;
  background: radial-gradient(circle at 50% 50%,rgba(157,109,255,.25),transparent 70%);
  opacity: .6;
  animation: _hlpulse 3s ease-in-out infinite;
  pointer-events: none;
}

.nuda-hl-reply__inner {
  position: relative;
  display: flex;
  gap: 10px;
  padding: 12px;
  background: #0c0c10;
  border-radius: 12px;
  z-index: 1;
}

.nuda-hl-reply__avatar {
  width: 32px;
  height: 32px;
  border-radius: 50%;
  background: linear-gradient(135deg,#9d6dff,#ff6dd4);
  color: #fafafa;
  font-size: 11px;
  font-weight: 600;
  display: grid;
  place-items: center;
  flex-shrink: 0;
}

.nuda-hl-reply__body {
  flex: 1;
}

.nuda-hl-reply__name {
  color: #fafafa;
  font-size: 13px;
  font-weight: 600;
  margin-bottom: 4px;
  display: flex;
  align-items: center;
  gap: 6px;
  flex-wrap: wrap;
}

.nuda-hl-reply__chip {
  font-size: 10px;
  font-weight: 600;
  color: #9d6dff;
  background: rgba(157,109,255,.12);
  padding: 1px 6px;
  border-radius: 999px;
  text-transform: uppercase;
  letter-spacing: .04em;
}

.nuda-hl-reply__text {
  color: #a0a0a8;
  font-size: 13px;
  line-height: 1.5;
  margin: 0;
}

@keyframes _hlrotate {
  to {
    background-position: 200% 0;
  }
}

@keyframes _hlpulse {
  0%,100% {
    opacity: .4;
  }
  50% {
    opacity: .75;
  }
}

@media (prefers-reduced-motion:reduce) {
  .nuda-hl-reply,.nuda-hl-reply::after {
    animation: none;
  }
}

/* Reaction Stack
   Overlapping emoji "avatars" that fan out on hover. */

.nuda-reaction-stack {
  display: inline-flex;
  align-items: center;
  padding: 3px 10px 3px 3px;
  background: #0c0c10;
  border: 1px solid #1c1c22;
  border-radius: 999px;
}

.nuda-reaction-stack__chip {
  width: 22px;
  height: 22px;
  display: inline-grid;
  place-items: center;
  background: #111114;
  border: 1.5px solid #0c0c10;
  border-radius: 50%;
  font-size: 11px;
  line-height: 1;
  margin-left: -7px;
  transition: transform 0.25s cubic-bezier(0.16, 1, 0.3, 1);
  animation: nuda-rs-in 0.45s cubic-bezier(0.16, 1, 0.3, 1) both;
}

.nuda-reaction-stack__chip:first-of-type { margin-left: 0; }

.nuda-reaction-stack:hover .nuda-reaction-stack__chip { transform: translateY(-2px); }
.nuda-reaction-stack:hover .nuda-reaction-stack__chip:nth-child(2) {
  transform: translateY(-2px) translateX(2px);
}
.nuda-reaction-stack:hover .nuda-reaction-stack__chip:nth-child(3) {
  transform: translateY(-2px) translateX(4px);
}
.nuda-reaction-stack:hover .nuda-reaction-stack__chip:nth-child(4) {
  transform: translateY(-2px) translateX(6px);
}

.nuda-reaction-stack__count {
  color: #a0a0a8;
  font-size: 11px;
  font-weight: 600;
  margin-left: 6px;
  font-variant-numeric: tabular-nums;
}

@keyframes nuda-rs-in {
  from { opacity: 0; transform: scale(0.3); }
  to { opacity: 1; transform: scale(1); }
}

@media (prefers-reduced-motion: reduce) {
  .nuda-reaction-stack__chip { animation: none; transition: none; }
  .nuda-reaction-stack:hover .nuda-reaction-stack__chip { transform: none; }
}

