/* Quote Reply
   Reply that excerpts an original comment in a quoted block.
   Hover swaps the accent to lime. */

.nuda-quote-reply {
  display: flex;
  flex-direction: column;
  gap: 10px;
  padding: 14px;
  background: #0c0c10;
  border: 1px solid #1c1c22;
  border-radius: 12px;
  max-width: 440px;
}

.nuda-quote-reply__quote {
  position: relative;
  margin: 0;
  padding: 10px 12px 10px 32px;
  background: #111114;
  border-left: 2px solid #62b6ff;
  border-radius: 0 8px 8px 0;
  transition: border-color 0.3s, background 0.3s;
}

.nuda-quote-reply:hover .nuda-quote-reply__quote {
  border-color: #e4ff54;
  background: #13131a;
}

.nuda-quote-reply__mark {
  position: absolute;
  left: 8px;
  top: 10px;
  width: 16px;
  height: 16px;
  color: #62b6ff;
  opacity: 0.7;
  transition: color 0.3s, transform 0.4s cubic-bezier(0.16, 1, 0.3, 1);
}

.nuda-quote-reply:hover .nuda-quote-reply__mark {
  color: #e4ff54;
  transform: scale(1.1) rotate(-6deg);
}

.nuda-quote-reply__name {
  display: block;
  color: #a0a0a8;
  font-size: 11px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.04em;
  margin-bottom: 4px;
}

.nuda-quote-reply__text {
  color: #a0a0a8;
  font-size: 12px;
  line-height: 1.5;
  margin: 0;
  font-style: italic;
}

.nuda-quote-reply__reply {
  color: #fafafa;
  font-size: 13px;
  line-height: 1.55;
  margin: 0;
}

@media (prefers-reduced-motion: reduce) {
  .nuda-quote-reply__quote,
  .nuda-quote-reply__mark { transition: none; }
  .nuda-quote-reply:hover .nuda-quote-reply__mark { transform: none; }
}

/* Emoji Hover Preview Tooltip
   Hover or focus an emoji button to reveal a large preview + shortcode. */

.nuda-emoji-tip-row {
  display: inline-flex;
  gap: 8px;
  padding: 8px;
  background: #0c0c10;
  border: 1px solid #1c1c22;
  border-radius: 999px;
}

.nuda-emoji-tip {
  position: relative;
  display: inline-block;
}

.nuda-emoji-tip__btn {
  width: 32px;
  height: 32px;
  display: grid;
  place-items: center;
  background: transparent;
  border: 0;
  border-radius: 50%;
  font-size: 18px;
  cursor: pointer;
  transition: background 0.2s, transform 0.25s cubic-bezier(0.16, 1, 0.3, 1);
  padding: 0;
}

.nuda-emoji-tip__btn:hover {
  background: #1c1c22;
  transform: translateY(-2px);
}

.nuda-emoji-tip__btn:focus-visible {
  outline: 2px solid #e4ff54;
  outline-offset: 2px;
}

.nuda-emoji-tip__pop {
  position: absolute;
  bottom: calc(100% + 10px);
  left: 50%;
  transform: translateX(-50%) translateY(8px) scale(0.85);
  transform-origin: bottom center;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 4px;
  padding: 10px 12px;
  background: #111114;
  border: 1px solid #1c1c22;
  border-radius: 10px;
  box-shadow: 0 12px 28px rgba(0, 0, 0, 0.5);
  opacity: 0;
  pointer-events: none;
  transition:
    opacity 0.25s,
    transform 0.3s cubic-bezier(0.16, 1, 0.3, 1);
  white-space: nowrap;
}

.nuda-emoji-tip__pop::after {
  content: "";
  position: absolute;
  top: 100%;
  left: 50%;
  transform: translateX(-50%);
  border: 5px solid transparent;
  border-top-color: #1c1c22;
}

.nuda-emoji-tip__big { font-size: 36px; line-height: 1; }
.nuda-emoji-tip__name {
  color: #a0a0a8;
  font-family: ui-monospace, SFMono-Regular, monospace;
  font-size: 11px;
}

.nuda-emoji-tip:hover .nuda-emoji-tip__pop,
.nuda-emoji-tip:focus-within .nuda-emoji-tip__pop {
  opacity: 1;
  transform: translateX(-50%) translateY(0) scale(1);
}

@media (prefers-reduced-motion: reduce) {
  .nuda-emoji-tip__btn,
  .nuda-emoji-tip__pop { transition: none; }
  .nuda-emoji-tip__btn:hover { transform: none; }
  .nuda-emoji-tip:hover .nuda-emoji-tip__pop,
  .nuda-emoji-tip:focus-within .nuda-emoji-tip__pop {
    transform: translateX(-50%) translateY(0) scale(1);
  }
}

