/* Bio Card
   Avatar with name and short bio.
   Customize: --bio-bg, --bio-accent */

.nuda-bio-card {
  --bio-bg: #0c0c10;
  --bio-accent: linear-gradient(135deg, #e4ff54, #6ee7b7);
  display: flex;
  gap: 14px;
  align-items: center;
  padding: 16px;
  background: var(--bio-bg);
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 14px;
  max-width: 340px;
  color: #fafafa;
  font-family: system-ui, sans-serif;
}

