/* Member Since Badge
   Minimal pill with a calendar icon and date.
   Customize: --since-accent, --since-text */

.nuda-since {
  --since-accent: #e4ff54;
  --since-text: #a0a0a8;
  display: inline-flex;
  align-items: center;
  gap: 6px;
  padding: 6px 12px;
  background: rgba(255, 255, 255, 0.04);
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 999px;
  font-family: system-ui, sans-serif;
  font-size: 0.78rem;
  color: var(--since-text);
}

.nuda-since__icon  { display: inline-flex; color: var(--since-accent); }
.nuda-since__label { color: var(--since-text); }

.nuda-since__date {
  color: #fafafa;
  font-weight: 600;
  font-variant-numeric: tabular-nums;
}

/* Achievements Strip
   Avatar + row of tonal medal chips.
   Customize: data-tone variants */

.nuda-achievements {
  display: inline-flex;
  align-items: center;
  gap: 10px;
  padding: 8px 12px 8px 8px;
  background: #0c0c10;
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 999px;
  font-family: system-ui, sans-serif;
}

.nuda-achievements__avatar {
  width: 32px;
  height: 32px;
  border-radius: 50%;
  display: grid;
  place-items: center;
  font-size: 0.72rem;
  font-weight: 600;
  color: #09090b;
  background: linear-gradient(135deg, #e4ff54, #62b6ff);
}

.nuda-achievements__medals { display: inline-flex; gap: 4px; }

.nuda-achievements__medal {
  width: 24px;
  height: 24px;
  border-radius: 50%;
  display: grid;
  place-items: center;
  border: 1px solid rgba(255, 255, 255, 0.08);
  transition: transform 0.25s cubic-bezier(0.2, 0.7, 0.3, 1);
}

.nuda-achievements__medal:hover { transform: translateY(-2px) scale(1.08); }

.nuda-achievements__medal[data-tone="gold"]   { color: #09090b; background: linear-gradient(135deg, #ffb45e, #e4ff54); }
.nuda-achievements__medal[data-tone="silver"] { color: #09090b; background: linear-gradient(135deg, #d0d0d8, #a0a0a8); }
.nuda-achievements__medal[data-tone="pink"]   { color: #09090b; background: linear-gradient(135deg, #ff6dd4, #ff5e7a); }
.nuda-achievements__medal[data-tone="blue"]   { color: #09090b; background: linear-gradient(135deg, #62b6ff, #9d6dff); }

@media (prefers-reduced-motion: reduce) {
  .nuda-achievements__medal { transition: none; }
  .nuda-achievements__medal:hover { transform: none; }
}

.nuda-hover {
  position: relative;
  display: inline-block;
  font-family: system-ui,sans-serif;
}

.nuda-hover__trigger {
  padding: 0;
  background: none;
  border: 0;
  color: #62b6ff;
  font-size: .9rem;
  font-weight: 500;
  cursor: pointer;
  text-decoration: underline;
  text-underline-offset: 3px;
}

.nuda-hover__card {
  position: absolute;
  top: calc(100% + 8px);
  left: 0;
  width: 260px;
  padding: 0 14px 14px;
  background: #111114;
  border: 1px solid rgba(255,255,255,.08);
  border-radius: 14px;
  opacity: 0;
  transform: translateY(-4px) scale(.97);
  transform-origin: top left;
  pointer-events: none;
  transition: opacity .22s ease,transform .22s cubic-bezier(.2,.7,.3,1);
  box-shadow: 0 16px 40px -16px rgba(0,0,0,.6);
  z-index: 2;
  color: #fafafa;
}

.nuda-hover:hover .nuda-hover__card,.nuda-hover:focus-within .nuda-hover__card {
  opacity: 1;
  transform: translateY(0) scale(1);
  pointer-events: auto;
}

.nuda-hover__cover {
  height: 46px;
  margin: 0 -14px;
  border-radius: 14px 14px 0 0;
  background: linear-gradient(135deg,#62b6ff,#9d6dff,#ff6dd4);
}

.nuda-hover__head {
  display: flex;
  justify-content: space-between;
  align-items: flex-end;
  margin-top: -22px;
  margin-bottom: 6px;
}

.nuda-hover__avatar {
  width: 46px;
  height: 46px;
  border-radius: 50%;
  display: grid;
  place-items: center;
  font-size: .85rem;
  font-weight: 700;
  color: #09090b;
  background: linear-gradient(135deg,#e4ff54,#6ee7b7);
  border: 3px solid #111114;
}

.nuda-hover__follow {
  padding: 5px 12px;
  background: #e4ff54;
  color: #09090b;
  border: 0;
  border-radius: 999px;
  font-size: .72rem;
  font-weight: 700;
  cursor: pointer;
}

.nuda-hover__name {
  font-size: .95rem;
  font-weight: 600;
}

.nuda-hover__bio {
  font-size: .78rem;
  color: #a0a0a8;
  line-height: 1.4;
  margin-top: 2px;
}

.nuda-hover__stats {
  display: flex;
  gap: 14px;
  margin-top: 10px;
  font-size: .75rem;
  color: #a0a0a8;
}

.nuda-hover__stats strong {
  color: #fafafa;
  font-weight: 600;
  font-variant-numeric: tabular-nums;
  margin-right: 2px;
}

@media (prefers-reduced-motion:reduce) {
  .nuda-hover__card {
    transition: opacity .2s;
  }
  .nuda-hover:hover .nuda-hover__card {
    transform: none;
  }
}

