/* Bio Reveal
   Native <details> truncates the bio at 2 lines and toggles it.
   No JavaScript required. Customize: --reveal-accent, line clamp. */

.nuda-bio-reveal {
  --reveal-accent: #e4ff54;
  max-width: 320px;
  font-family: system-ui, sans-serif;
  color: #fafafa;
}

.nuda-bio-reveal > summary {
  list-style: none;
  cursor: pointer;
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.nuda-bio-reveal > summary::-webkit-details-marker { display: none; }

.nuda-bio-reveal__text {
  margin: 0;
  font-size: 0.82rem;
  color: #a0a0a8;
  line-height: 1.5;
  display: -webkit-box;
  -webkit-line-clamp: 2;
  line-clamp: 2;
  -webkit-box-orient: vertical;
  overflow: hidden;
  transition: all 0.3s ease;
}

.nuda-bio-reveal[open] .nuda-bio-reveal__text {
  -webkit-line-clamp: unset;
  line-clamp: unset;
  display: block;
}

.nuda-bio-reveal__toggle {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  font-size: 0.75rem;
  font-weight: 600;
  color: var(--reveal-accent);
  align-self: flex-start;
}

.nuda-bio-reveal__less { display: none; }
.nuda-bio-reveal[open] .nuda-bio-reveal__more { display: none; }
.nuda-bio-reveal[open] .nuda-bio-reveal__less { display: inline; }

.nuda-bio-reveal__chev {
  transition: transform 0.25s cubic-bezier(0.2, 0.7, 0.3, 1);
}

.nuda-bio-reveal[open] .nuda-bio-reveal__chev {
  transform: rotate(180deg);
}

.nuda-bio-reveal > summary:focus-visible {
  outline: 2px solid var(--reveal-accent);
  outline-offset: 3px;
  border-radius: 6px;
}

@media (prefers-reduced-motion: reduce) {
  .nuda-bio-reveal__text,
  .nuda-bio-reveal__chev { transition: none; }
}

/* Preference Row
   A labeled row with description and a toggle switch.
   Customize: --row-bg, --row-border, --switch-on */

.nuda-pref-row {
  --row-bg: #0c0c10;
  --row-border: rgba(255, 255, 255, 0.06);
  --switch-on: #e4ff54;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 1rem;
  padding: 1rem 1.25rem;
  background: var(--row-bg);
  border: 1px solid var(--row-border);
  border-radius: 12px;
  width: 100%;
  max-width: 480px;
}

.nuda-pref-row__text {
  display: flex;
  flex-direction: column;
  gap: 0.25rem;
  min-width: 0;
}

.nuda-pref-row__label {
  color: #fafafa;
  font-size: 0.875rem;
  font-weight: 500;
}

.nuda-pref-row__desc {
  color: #a0a0a8;
  font-size: 0.75rem;
  line-height: 1.4;
}

.nuda-pref-row__switch {
  position: relative;
  width: 36px;
  height: 20px;
  flex-shrink: 0;
  cursor: pointer;
}

.nuda-pref-row__switch input {
  position: absolute;
  opacity: 0;
  width: 100%;
  height: 100%;
  margin: 0;
  cursor: pointer;
  z-index: 1;
}

.nuda-pref-row__switch span {
  position: absolute;
  inset: 0;
  background: rgba(255, 255, 255, 0.1);
  border-radius: 999px;
  transition: background 0.25s ease;
}

.nuda-pref-row__switch span::after {
  content: "";
  position: absolute;
  top: 2px;
  left: 2px;
  width: 16px;
  height: 16px;
  background: #fafafa;
  border-radius: 50%;
  transition: transform 0.25s ease;
}

.nuda-pref-row__switch input:checked + span {
  background: var(--switch-on);
}

.nuda-pref-row__switch input:checked + span::after {
  transform: translateX(16px);
  background: #09090b;
}

@media (prefers-reduced-motion: reduce) {
  .nuda-pref-row__switch span,
  .nuda-pref-row__switch span::after {
    transition: none;
  }
}

