/* Save Indicator
   A small autosaved pill with a pulsing green dot.
   Customize: --save-color, --save-bg */

.nuda-save {
  --save-color: #22c55e;
  --save-bg: #0c0c10;
  display: inline-flex;
  align-items: center;
  gap: 0.5rem;
  padding: 0.5rem 0.875rem;
  background: var(--save-bg);
  border: 1px solid rgba(255, 255, 255, 0.06);
  border-radius: 999px;
}

.nuda-save__dot {
  position: relative;
  width: 8px;
  height: 8px;
  border-radius: 50%;
  background: var(--save-color);
  flex-shrink: 0;
}

.nuda-save__dot::before {
  content: "";
  position: absolute;
  inset: -4px;
  border-radius: 50%;
  background: var(--save-color);
  opacity: 0.35;
  animation: nuda-save-pulse 2s ease-out infinite;
}

.nuda-save__text {
  color: #a0a0a8;
  font-size: 0.75rem;
  font-weight: 500;
  letter-spacing: 0.01em;
}

@keyframes nuda-save-pulse {
  0% {
    transform: scale(0.5);
    opacity: 0.5;
  }
  100% {
    transform: scale(1.6);
    opacity: 0;
  }
}

@media (prefers-reduced-motion: reduce) {
  .nuda-save__dot::before {
    animation: none;
    opacity: 0.4;
    transform: scale(1);
  }
}

/* Search Settings Input
   A search field with leading icon and trailing keyboard hint.
   Customize: --search-bg, --search-accent */

.nuda-set-search {
  --search-bg: #0c0c10;
  --search-accent: rgba(228, 255, 84, 0.4);
  display: flex;
  align-items: center;
  gap: 0.625rem;
  padding: 0 0.875rem;
  background: var(--search-bg);
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 10px;
  width: 100%;
  max-width: 420px;
  transition: border-color 0.2s ease, background 0.2s ease;
}

.nuda-set-search:focus-within {
  border-color: var(--search-accent);
  background: #111114;
}

.nuda-set-search__icon {
  width: 16px;
  height: 16px;
  color: #63636e;
  flex-shrink: 0;
}

.nuda-set-search input {
  flex: 1;
  background: transparent;
  border: 0;
  outline: 0;
  color: #fafafa;
  font-size: 0.875rem;
  padding: 0.625rem 0;
  font-family: inherit;
}

.nuda-set-search input::placeholder {
  color: #63636e;
}

.nuda-set-search__kbd {
  font-family: inherit;
  font-size: 0.6875rem;
  color: #a0a0a8;
  background: rgba(255, 255, 255, 0.06);
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 5px;
  padding: 0.125rem 0.375rem;
  flex-shrink: 0;
  letter-spacing: 0.04em;
}

@media (prefers-reduced-motion: reduce) {
  .nuda-set-search {
    transition: none;
  }
}

/* Two-column Setting
   Label on the left, control on the right.
   Customize: --row-border, --control-bg */

.nuda-two-col {
  --row-border: rgba(255, 255, 255, 0.06);
  --control-bg: #0c0c10;
  display: grid;
  grid-template-columns: 1fr auto;
  gap: 1rem 2rem;
  align-items: center;
  padding: 1.25rem 0;
  border-bottom: 1px solid var(--row-border);
  width: 100%;
  max-width: 560px;
}

.nuda-two-col__label {
  display: flex;
  flex-direction: column;
  gap: 0.25rem;
  min-width: 0;
}

.nuda-two-col__name {
  color: #fafafa;
  font-size: 0.875rem;
  font-weight: 500;
}

.nuda-two-col__hint {
  color: #a0a0a8;
  font-size: 0.75rem;
  line-height: 1.4;
}

.nuda-two-col__control {
  position: relative;
  display: flex;
  align-items: center;
}

.nuda-two-col__control select {
  appearance: none;
  background: var(--control-bg);
  border: 1px solid rgba(255, 255, 255, 0.08);
  color: #fafafa;
  font-size: 0.8125rem;
  font-family: inherit;
  padding: 0.5rem 2rem 0.5rem 0.875rem;
  border-radius: 8px;
  cursor: pointer;
  min-width: 160px;
  transition: border-color 0.2s ease;
}

.nuda-two-col__control select:hover {
  border-color: rgba(255, 255, 255, 0.15);
}

.nuda-two-col__control select:focus-visible {
  outline: 2px solid #e4ff54;
  outline-offset: 2px;
}

.nuda-two-col__control svg {
  position: absolute;
  right: 0.625rem;
  width: 12px;
  height: 12px;
  color: #a0a0a8;
  pointer-events: none;
}

@media (prefers-reduced-motion: reduce) {
  .nuda-two-col__control select {
    transition: none;
  }
}

