/* Drop Zone
   Dashed area inviting click-or-drop uploads.
   Customize: --dz-bg, --dz-border, --dz-accent */

.nuda-dropzone {
  --dz-bg: #0c0c10;
  --dz-border: rgba(255, 255, 255, 0.1);
  --dz-accent: #e4ff54;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 0.5rem;
  padding: 2rem 1.5rem;
  background: var(--dz-bg);
  border: 1.5px dashed var(--dz-border);
  border-radius: 12px;
  color: #a0a0a8;
  cursor: pointer;
  transition: border-color 0.2s, background 0.2s;
  min-width: 280px;
}

.nuda-dropzone:hover {
  border-color: rgba(228, 255, 84, 0.4);
  background: #111114;
}

.nuda-dropzone__icon {
  width: 32px;
  height: 32px;
  color: var(--dz-accent);
  opacity: 0.8;
}

.nuda-dropzone__title {
  margin: 0;
  font-size: 0.95rem;
  color: #fafafa;
  font-weight: 500;
}

.nuda-dropzone__hint {
  margin: 0;
  font-size: 0.8rem;
  color: #63636e;
}

@media (prefers-reduced-motion: reduce) {
  .nuda-dropzone {
    transition: none;
  }
}

/* Drop Zone Active
   Glowing solid-border state when files are hovered over it.
   Apply this class when a dragover event fires. */

.nuda-dropzone-active {
  --accent: #e4ff54;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 0.5rem;
  padding: 2rem 1.5rem;
  background: rgba(228, 255, 84, 0.06);
  border: 1.5px solid var(--accent);
  border-radius: 12px;
  color: #fafafa;
  min-width: 280px;
  box-shadow:
    0 0 0 4px rgba(228, 255, 84, 0.12),
    0 0 24px rgba(228, 255, 84, 0.2);
  animation: nuda-dz-pulse 1.6s ease-in-out infinite;
}

.nuda-dropzone-active__icon {
  width: 32px;
  height: 32px;
  color: var(--accent);
  animation: nuda-dz-bounce 1s ease-in-out infinite;
}

.nuda-dropzone-active__title {
  margin: 0;
  font-size: 0.95rem;
  font-weight: 600;
}

.nuda-dropzone-active__hint {
  margin: 0;
  font-size: 0.8rem;
  color: var(--accent);
}

@keyframes nuda-dz-pulse {
  0%, 100% {
    box-shadow:
      0 0 0 4px rgba(228, 255, 84, 0.12),
      0 0 24px rgba(228, 255, 84, 0.2);
  }
  50% {
    box-shadow:
      0 0 0 6px rgba(228, 255, 84, 0.2),
      0 0 32px rgba(228, 255, 84, 0.35);
  }
}

@keyframes nuda-dz-bounce {
  0%, 100% { transform: translateY(0); }
  50% { transform: translateY(-4px); }
}

@media (prefers-reduced-motion: reduce) {
  .nuda-dropzone-active,
  .nuda-dropzone-active__icon {
    animation: none;
  }
}

