/* File List Item
   A row showing one uploaded file: icon + name + size + remove. */

.nuda-fli {
  display: flex;
  align-items: center;
  gap: 0.75rem;
  padding: 0.75rem;
  background: #0c0c10;
  border: 1px solid rgba(255, 255, 255, 0.06);
  border-radius: 10px;
  min-width: 280px;
}

.nuda-fli__icon {
  width: 36px;
  height: 36px;
  display: flex;
  align-items: center;
  justify-content: center;
  background: #111114;
  border-radius: 8px;
  color: #62b6ff;
  flex-shrink: 0;
}

.nuda-fli__icon svg { width: 18px; height: 18px; }

.nuda-fli__meta { flex: 1; min-width: 0; }

.nuda-fli__name {
  margin: 0;
  font-size: 0.85rem;
  color: #fafafa;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  font-weight: 500;
}

.nuda-fli__size {
  margin: 0;
  font-size: 0.75rem;
  color: #63636e;
}

.nuda-fli__remove {
  width: 28px;
  height: 28px;
  display: flex;
  align-items: center;
  justify-content: center;
  background: transparent;
  border: none;
  color: #a0a0a8;
  border-radius: 6px;
  cursor: pointer;
  transition: background 0.15s, color 0.15s;
  flex-shrink: 0;
}

.nuda-fli__remove:hover {
  background: rgba(255, 94, 122, 0.12);
  color: #ff5e7a;
}

.nuda-fli__remove svg { width: 14px; height: 14px; }

@media (prefers-reduced-motion: reduce) {
  .nuda-fli__remove { transition: none; }
}

/* Upload Progress Bar
   Per-file progress with name + percent label.
   Customize: --bar-grad-from, --bar-grad-to */

.nuda-upbar {
  --bar-grad-from: #e4ff54;
  --bar-grad-to: #a8ff54;
  display: flex;
  flex-direction: column;
  gap: 0.4rem;
  padding: 0.75rem 0.9rem;
  background: #0c0c10;
  border: 1px solid rgba(255, 255, 255, 0.06);
  border-radius: 10px;
  min-width: 280px;
}

.nuda-upbar__row {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 0.5rem;
}

.nuda-upbar__name {
  font-size: 0.82rem;
  color: #fafafa;
  font-weight: 500;
}

.nuda-upbar__pct {
  font-size: 0.78rem;
  color: var(--bar-grad-from);
  font-variant-numeric: tabular-nums;
}

.nuda-upbar__track {
  position: relative;
  width: 100%;
  height: 6px;
  background: rgba(255, 255, 255, 0.06);
  border-radius: 999px;
  overflow: hidden;
}

.nuda-upbar__fill {
  height: 100%;
  background: linear-gradient(90deg, var(--bar-grad-from), var(--bar-grad-to));
  border-radius: 999px;
  transition: width 0.3s ease;
  box-shadow: 0 0 8px rgba(228, 255, 84, 0.4);
}

@media (prefers-reduced-motion: reduce) {
  .nuda-upbar__fill { transition: none; }
}

/* File Type Icons Grid
   5-up grid of supported file types with color-coded icons. */

.nuda-ftypes {
  display: grid;
  grid-template-columns: repeat(5, 1fr);
  gap: 0.5rem;
  padding: 0.75rem;
  background: #0c0c10;
  border: 1px solid rgba(255, 255, 255, 0.06);
  border-radius: 12px;
}

.nuda-ftype {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 0.35rem;
  padding: 0.6rem 0.25rem;
  background: #111114;
  border-radius: 8px;
  font-size: 0.7rem;
  font-weight: 600;
  letter-spacing: 0.04em;
  transition: transform 0.2s;
}

.nuda-ftype:hover { transform: translateY(-2px); }
.nuda-ftype svg { width: 22px; height: 22px; }

.nuda-ftype--pdf { color: #ff5e7a; }
.nuda-ftype--doc { color: #62b6ff; }
.nuda-ftype--img { color: #6ee7b7; }
.nuda-ftype--vid { color: #e4ff54; }
.nuda-ftype--zip { color: #a0a0a8; }

@media (prefers-reduced-motion: reduce) {
  .nuda-ftype { transition: none; }
  .nuda-ftype:hover { transform: none; }
}

/* Image Thumbnail Preview
   Square preview with a floating remove badge. */

.nuda-thumb {
  position: relative;
  display: flex;
  flex-direction: column;
  gap: 0.4rem;
  width: 120px;
}

.nuda-thumb__img {
  position: relative;
  width: 120px;
  height: 120px;
  border-radius: 10px;
  overflow: hidden;
  background: #111114;
  border: 1px solid rgba(255, 255, 255, 0.08);
}

.nuda-thumb__img img,
.nuda-thumb__img svg {
  width: 100%;
  height: 100%;
  object-fit: cover;
  display: block;
}

.nuda-thumb__remove {
  position: absolute;
  top: 6px;
  right: 6px;
  width: 22px;
  height: 22px;
  display: flex;
  align-items: center;
  justify-content: center;
  background: #09090b;
  border: 1px solid rgba(255, 255, 255, 0.1);
  border-radius: 50%;
  color: #fafafa;
  cursor: pointer;
  padding: 0;
  transition: background 0.15s, border-color 0.15s;
}

.nuda-thumb__remove:hover {
  background: #ff5e7a;
  border-color: #ff5e7a;
}

.nuda-thumb__remove svg { width: 11px; height: 11px; }

.nuda-thumb__name {
  margin: 0;
  font-size: 0.75rem;
  color: #a0a0a8;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

@media (prefers-reduced-motion: reduce) {
  .nuda-thumb__remove { transition: none; }
}

/* Upload Error State
   Red-bordered card with a retry CTA. */

.nuda-uperr {
  --err: #ff5e7a;
  display: flex;
  align-items: center;
  gap: 0.75rem;
  padding: 0.75rem;
  background: rgba(255, 94, 122, 0.06);
  border: 1px solid var(--err);
  border-radius: 10px;
  min-width: 300px;
}

.nuda-uperr__icon {
  width: 36px;
  height: 36px;
  display: flex;
  align-items: center;
  justify-content: center;
  background: rgba(255, 94, 122, 0.12);
  border-radius: 8px;
  color: var(--err);
  flex-shrink: 0;
}
.nuda-uperr__icon svg { width: 18px; height: 18px; }

.nuda-uperr__meta { flex: 1; min-width: 0; }

.nuda-uperr__name {
  margin: 0;
  font-size: 0.85rem;
  color: #fafafa;
  font-weight: 500;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.nuda-uperr__msg {
  margin: 0;
  font-size: 0.75rem;
  color: var(--err);
}

.nuda-uperr__retry {
  display: inline-flex;
  align-items: center;
  gap: 0.35rem;
  padding: 0.4rem 0.65rem;
  background: var(--err);
  color: #09090b;
  border: none;
  border-radius: 6px;
  font-size: 0.78rem;
  font-weight: 600;
  cursor: pointer;
  transition: filter 0.15s;
  flex-shrink: 0;
}

.nuda-uperr__retry:hover { filter: brightness(1.1); }
.nuda-uperr__retry svg { width: 13px; height: 13px; }

@media (prefers-reduced-motion: reduce) {
  .nuda-uperr__retry { transition: none; }
}

/* Multi-file Count Pill
   Inline summary of how many files are queued. */

.nuda-fcount {
  --accent: #e4ff54;
  display: inline-flex;
  align-items: center;
  gap: 0.45rem;
  padding: 0.4rem 0.7rem;
  background: rgba(228, 255, 84, 0.08);
  border: 1px solid rgba(228, 255, 84, 0.3);
  border-radius: 999px;
  color: #fafafa;
  font-size: 0.8rem;
  font-weight: 500;
}

.nuda-fcount__icon {
  width: 14px;
  height: 14px;
  color: var(--accent);
}

.nuda-fcount__num {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-width: 18px;
  height: 18px;
  padding: 0 5px;
  background: var(--accent);
  color: #09090b;
  border-radius: 999px;
  font-size: 0.72rem;
  font-weight: 700;
  font-variant-numeric: tabular-nums;
}

/* File Size Pill
   Compact KB/MB indicator. Color variants signal size buckets:
   --sm = small/light, default = medium, --lg = approaching limit. */

.nuda-fsize-row {
  display: flex;
  gap: 0.4rem;
  flex-wrap: wrap;
}

.nuda-fsize {
  display: inline-flex;
  align-items: center;
  padding: 0.2rem 0.55rem;
  background: #111114;
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 6px;
  color: #a0a0a8;
  font-size: 0.72rem;
  font-weight: 500;
  font-variant-numeric: tabular-nums;
  letter-spacing: 0.01em;
}

.nuda-fsize--sm {
  color: #6ee7b7;
  border-color: rgba(110, 231, 183, 0.25);
  background: rgba(110, 231, 183, 0.06);
}

.nuda-fsize--lg {
  color: #ff5e7a;
  border-color: rgba(255, 94, 122, 0.25);
  background: rgba(255, 94, 122, 0.06);
}

/* Upload Success Checkmark
   Circle draws, then check draws, then label fades in. */

.nuda-success {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 0.5rem;
  padding: 1rem;
  color: #6ee7b7;
}

.nuda-success__svg { width: 52px; height: 52px; }

.nuda-success__circle {
  stroke-dasharray: 152;
  stroke-dashoffset: 152;
  animation: nuda-success-circle 0.6s ease forwards;
}

.nuda-success__check {
  stroke-dasharray: 60;
  stroke-dashoffset: 60;
  animation: nuda-success-check 0.4s ease 0.5s forwards;
}

.nuda-success__label {
  margin: 0;
  font-size: 0.85rem;
  font-weight: 600;
  color: #6ee7b7;
  opacity: 0;
  animation: nuda-success-label 0.3s ease 0.8s forwards;
}

@keyframes nuda-success-circle { to { stroke-dashoffset: 0; } }
@keyframes nuda-success-check  { to { stroke-dashoffset: 0; } }
@keyframes nuda-success-label  { to { opacity: 1; } }

@media (prefers-reduced-motion: reduce) {
  .nuda-success__circle,
  .nuda-success__check {
    animation: none;
    stroke-dashoffset: 0;
  }
  .nuda-success__label { animation: none; opacity: 1; }
}

