/* Cancel Upload Button
   Ring-progress around an X that halts upload on click.
   Update stroke-dashoffset = circumference * (1 - progress).
   Circumference at r=15 is ~94.25. */

.nuda-cancel {
  display: inline-flex;
  align-items: center;
  gap: 0.6rem;
}

.nuda-cancel__progress {
  position: relative;
  width: 40px;
  height: 40px;
}

.nuda-cancel__progress svg {
  width: 100%;
  height: 100%;
  transform: rotate(-90deg);
}

.nuda-cancel__track {
  stroke: rgba(255, 255, 255, 0.08);
  stroke-width: 3;
}

.nuda-cancel__fill {
  stroke: #e4ff54;
  stroke-width: 3;
  stroke-linecap: round;
  stroke-dasharray: 94.25;
  stroke-dashoffset: 49;
  transition: stroke-dashoffset 0.3s ease;
}

.nuda-cancel__btn {
  position: absolute;
  inset: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  background: transparent;
  border: none;
  color: #fafafa;
  cursor: pointer;
  padding: 0;
  border-radius: 50%;
  transition: background 0.15s, color 0.15s;
}

.nuda-cancel__btn:hover {
  background: rgba(255, 94, 122, 0.12);
  color: #ff5e7a;
}

.nuda-cancel__btn svg { width: 14px; height: 14px; }

.nuda-cancel__label {
  font-size: 0.78rem;
  color: #a0a0a8;
  font-variant-numeric: tabular-nums;
}

@media (prefers-reduced-motion: reduce) {
  .nuda-cancel__fill,
  .nuda-cancel__btn { transition: none; }
}

/* Total Progress
   Aggregate progress card across all queued files. */

.nuda-total {
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
  padding: 0.85rem 1rem;
  background: #0c0c10;
  border: 1px solid rgba(255, 255, 255, 0.06);
  border-radius: 12px;
  min-width: 300px;
}

.nuda-total__head {
  display: flex;
  justify-content: space-between;
  font-size: 0.85rem;
}
.nuda-total__title { color: #fafafa; font-weight: 500; }
.nuda-total__count { color: #a0a0a8; }

.nuda-total__track {
  position: relative;
  width: 100%;
  height: 8px;
  background: rgba(255, 255, 255, 0.06);
  border-radius: 999px;
  overflow: hidden;
}

.nuda-total__fill {
  position: relative;
  height: 100%;
  background: linear-gradient(90deg, #62b6ff, #e4ff54);
  border-radius: 999px;
  transition: width 0.4s ease;
  overflow: hidden;
}

.nuda-total__shine {
  position: absolute;
  inset: 0;
  background: linear-gradient(
    90deg,
    transparent,
    rgba(255, 255, 255, 0.4),
    transparent
  );
  animation: nuda-total-shine 1.5s linear infinite;
}

.nuda-total__foot {
  display: flex;
  justify-content: space-between;
  font-size: 0.72rem;
  color: #63636e;
  font-variant-numeric: tabular-nums;
}

@keyframes nuda-total-shine {
  0%   { transform: translateX(-100%); }
  100% { transform: translateX(100%); }
}

@media (prefers-reduced-motion: reduce) {
  .nuda-total__fill { transition: none; }
  .nuda-total__shine { animation: none; display: none; }
}

/* File Validation Error
   Inline message for blocked extensions or oversize files. */

.nuda-valerr {
  display: flex;
  align-items: flex-start;
  gap: 0.6rem;
  padding: 0.7rem 0.85rem;
  background: rgba(255, 94, 122, 0.06);
  border: 1px solid rgba(255, 94, 122, 0.4);
  border-left: 3px solid #ff5e7a;
  border-radius: 8px;
  min-width: 280px;
}

.nuda-valerr__icon {
  width: 18px;
  height: 18px;
  color: #ff5e7a;
  flex-shrink: 0;
  margin-top: 1px;
}

.nuda-valerr__meta { flex: 1; min-width: 0; }

.nuda-valerr__title {
  margin: 0;
  font-size: 0.82rem;
  color: #fafafa;
  font-weight: 600;
}

.nuda-valerr__msg {
  margin: 0.15rem 0 0;
  font-size: 0.74rem;
  color: #a0a0a8;
}

.nuda-valerr__msg code {
  padding: 1px 5px;
  background: rgba(255, 94, 122, 0.12);
  color: #ff5e7a;
  border-radius: 4px;
  font-family: ui-monospace, SFMono-Regular, Menlo, monospace;
  font-size: 0.72rem;
}

/* Click-to-browse Button
   Paperclip-style button to open the file picker. */

.nuda-browse {
  display: inline-flex;
  align-items: center;
  gap: 0.5rem;
  padding: 0.55rem 0.95rem;
  background: #111114;
  color: #fafafa;
  border: 1px solid rgba(255, 255, 255, 0.1);
  border-radius: 8px;
  font-size: 0.85rem;
  font-weight: 500;
  cursor: pointer;
  transition:
    background 0.15s,
    border-color 0.15s,
    transform 0.15s;
}

.nuda-browse:hover {
  background: #0c0c10;
  border-color: rgba(228, 255, 84, 0.4);
}

.nuda-browse:hover .nuda-browse__icon {
  color: #e4ff54;
  transform: rotate(-12deg);
}

.nuda-browse:active { transform: translateY(1px); }

.nuda-browse__icon {
  width: 16px;
  height: 16px;
  color: #a0a0a8;
  transition: transform 0.2s, color 0.15s;
}

@media (prefers-reduced-motion: reduce) {
  .nuda-browse,
  .nuda-browse__icon { transition: none; }
  .nuda-browse:hover .nuda-browse__icon { transform: none; }
}

.nuda-paste {
  display: inline-flex;
  align-items: center;
  gap: .4rem;
  padding: .5rem .75rem;
  background: #0c0c10;
  border: 1px dashed rgba(255,255,255,.1);
  border-radius: 8px;
  color: #a0a0a8;
  font-size: .78rem;
}

.nuda-paste__icon {
  width: 14px;
  height: 14px;
  color: #62b6ff;
  flex-shrink: 0;
}

.nuda-paste__text {
  color: #a0a0a8;
}

.nuda-paste__kbd {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-width: 22px;
  height: 20px;
  padding: 0 5px;
  background: #111114;
  border: 1px solid rgba(255,255,255,.1);
  border-bottom-width: 2px;
  border-radius: 4px;
  color: #fafafa;
  font-family: ui-monospace,SFMono-Regular,Menlo,monospace;
  font-size: .7rem;
  font-weight: 500;
  line-height: 1;
}

.nuda-paste__plus {
  color: #63636e;
  font-size: .7rem;
}

/* Upload Queue Indicator
   Active item shows spinner; waiting items show numeric slot. */

.nuda-queue {
  display: flex;
  flex-direction: column;
  gap: 0.3rem;
  padding: 0.5rem;
  background: #0c0c10;
  border: 1px solid rgba(255, 255, 255, 0.06);
  border-radius: 10px;
  min-width: 280px;
}

.nuda-queue__item {
  display: flex;
  align-items: center;
  gap: 0.6rem;
  padding: 0.45rem 0.6rem;
  border-radius: 6px;
  font-size: 0.78rem;
  color: #a0a0a8;
}

.nuda-queue__item--active {
  background: rgba(228, 255, 84, 0.06);
  color: #fafafa;
}

.nuda-queue__dot {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 18px;
  height: 18px;
  background: #111114;
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 50%;
  color: #63636e;
  font-size: 0.65rem;
  font-weight: 600;
  flex-shrink: 0;
}

.nuda-queue__spinner {
  width: 14px;
  height: 14px;
  border: 1.5px solid rgba(228, 255, 84, 0.2);
  border-top-color: #e4ff54;
  border-radius: 50%;
  animation: nuda-queue-spin 0.8s linear infinite;
  flex-shrink: 0;
  margin: 2px;
}

.nuda-queue__label {
  flex: 1;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.nuda-queue__status {
  font-size: 0.7rem;
  color: #e4ff54;
  font-weight: 500;
}

.nuda-queue__status--wait { color: #63636e; }

@keyframes nuda-queue-spin {
  to { transform: rotate(360deg); }
}

@media (prefers-reduced-motion: reduce) {
  .nuda-queue__spinner { animation: none; }
}

/* File Replaced Notification
   Inline notice when a file overwrites an existing one. */

.nuda-replaced {
  display: flex;
  align-items: center;
  gap: 0.7rem;
  padding: 0.65rem 0.85rem;
  background: rgba(98, 182, 255, 0.06);
  border: 1px solid rgba(98, 182, 255, 0.3);
  border-radius: 10px;
  min-width: 280px;
  animation: nuda-replaced-slide 0.35s ease;
}

.nuda-replaced__icon {
  width: 32px;
  height: 32px;
  display: flex;
  align-items: center;
  justify-content: center;
  background: rgba(98, 182, 255, 0.12);
  border-radius: 8px;
  color: #62b6ff;
  flex-shrink: 0;
}
.nuda-replaced__icon svg { width: 16px; height: 16px; }

.nuda-replaced__body { flex: 1; min-width: 0; }

.nuda-replaced__title {
  margin: 0;
  font-size: 0.82rem;
  color: #fafafa;
  font-weight: 600;
}

.nuda-replaced__meta {
  margin: 0.1rem 0 0;
  display: flex;
  align-items: center;
  gap: 0.35rem;
  font-size: 0.74rem;
  flex-wrap: wrap;
}

.nuda-replaced__old {
  color: #63636e;
  text-decoration: line-through;
}

.nuda-replaced__arrow { color: #62b6ff; }

.nuda-replaced__new {
  color: #62b6ff;
  font-weight: 500;
}

@keyframes nuda-replaced-slide {
  from { opacity: 0; transform: translateY(-4px); }
  to   { opacity: 1; transform: translateY(0); }
}

@media (prefers-reduced-motion: reduce) {
  .nuda-replaced { animation: none; }
}

/* Empty State — No Files
   Friendly placeholder shown before any uploads exist. */

.nuda-empty {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 0.4rem;
  padding: 1.5rem 1.25rem;
  background: #0c0c10;
  border: 1px dashed rgba(255, 255, 255, 0.08);
  border-radius: 12px;
  min-width: 280px;
}

.nuda-empty__art {
  width: 64px;
  height: 64px;
  display: flex;
  align-items: center;
  justify-content: center;
  margin-bottom: 0.25rem;
  animation: nuda-empty-float 3s ease-in-out infinite;
}

.nuda-empty__art svg {
  width: 100%;
  height: 100%;
}

.nuda-empty__title {
  margin: 0;
  font-size: 0.9rem;
  color: #fafafa;
  font-weight: 600;
}

.nuda-empty__hint {
  margin: 0;
  font-size: 0.78rem;
  color: #63636e;
  text-align: center;
}

@keyframes nuda-empty-float {
  0%, 100% { transform: translateY(0); }
  50%      { transform: translateY(-4px); }
}

@media (prefers-reduced-motion: reduce) {
  .nuda-empty__art { animation: none; }
}

/* Chip Input Add
   Typed text becomes a chip on Enter.
   Customize: --chip-bg, --chip-accent */

.nuda-chip-input {
  --chip-accent: #e4ff54;
  display: flex;
  flex-wrap: wrap;
  align-items: center;
  gap: 6px;
  width: 100%;
  padding: 8px;
  background: #0c0c10;
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 10px;
  transition: border-color 0.2s ease;
}

.nuda-chip-input:focus-within {
  border-color: var(--chip-accent);
}

.nuda-chip-input__chip {
  display: inline-flex;
  align-items: center;
  padding: 4px 10px;
  font: 500 12px/1 ui-sans-serif, system-ui, sans-serif;
  color: #fafafa;
  background: #111114;
  border: 1px solid rgba(255, 255, 255, 0.06);
  border-radius: 99px;
}

.nuda-chip-input__field {
  flex: 1;
  min-width: 80px;
  padding: 4px 6px;
  font: 500 12px/1 ui-sans-serif, system-ui, sans-serif;
  color: #fafafa;
  background: transparent;
  border: 0;
  outline: 0;
}

.nuda-chip-input__field::placeholder {
  color: #63636e;
}

/* Chip Remove Animation
   Chip shrinks and fades when removed.
   Customize: --chip-bg, --chip-radius */

.nuda-chip-remove {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
}

.nuda-chip-remove__chip {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  padding: 4px 4px 4px 10px;
  font: 500 12px/1 ui-sans-serif, system-ui, sans-serif;
  color: #fafafa;
  background: #111114;
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 99px;
  transform-origin: center;
  animation: nuda-chip-in 0.25s ease both;
}

.nuda-chip-remove__chip--leaving {
  animation: nuda-chip-out 0.3s ease forwards;
}

.nuda-chip-remove__x {
  display: inline-grid;
  place-items: center;
  width: 18px;
  height: 18px;
  font-size: 14px;
  line-height: 1;
  color: #a0a0a8;
  background: transparent;
  border: 0;
  border-radius: 99px;
  cursor: pointer;
  transition: background 0.15s, color 0.15s;
}

.nuda-chip-remove__x:hover {
  background: rgba(255, 255, 255, 0.08);
  color: #fafafa;
}

@keyframes nuda-chip-in {
  from { opacity: 0; transform: scale(0.6); }
  to   { opacity: 1; transform: scale(1); }
}

@keyframes nuda-chip-out {
  to { opacity: 0; transform: scale(0.6); }
}

@media (prefers-reduced-motion: reduce) {
  .nuda-chip-remove__chip,
  .nuda-chip-remove__chip--leaving { animation: none; }
}

/* Chip Autocomplete Dropdown
   Suggests matching chips as you type.
   Customize: --auto-accent, --auto-surface */

.nuda-chip-auto {
  --auto-accent: #e4ff54;
  position: relative;
  width: 100%;
  max-width: 280px;
  font: 500 12px/1 ui-sans-serif, system-ui, sans-serif;
  color: #fafafa;
}

.nuda-chip-auto__field {
  display: flex;
  flex-wrap: wrap;
  align-items: center;
  gap: 6px;
  padding: 8px;
  background: #0c0c10;
  border: 1px solid var(--auto-accent);
  border-radius: 10px;
}

.nuda-chip-auto__chip {
  padding: 4px 10px;
  background: #111114;
  border: 1px solid rgba(255, 255, 255, 0.06);
  border-radius: 99px;
}

.nuda-chip-auto__input {
  flex: 1;
  min-width: 60px;
  padding: 4px;
  color: #fafafa;
  background: transparent;
  border: 0;
  outline: 0;
  caret-color: var(--auto-accent);
}

.nuda-chip-auto__list {
  margin: 4px 0 0;
  padding: 4px;
  list-style: none;
  background: #0c0c10;
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 10px;
  box-shadow: 0 12px 24px rgba(0, 0, 0, 0.4);
  animation: nuda-dropin 0.18s ease both;
}

.nuda-chip-auto__opt {
  padding: 8px 10px;
  color: #a0a0a8;
  border-radius: 6px;
  cursor: pointer;
}

.nuda-chip-auto__opt b { color: #fafafa; font-weight: 600; }

.nuda-chip-auto__opt:hover,
.nuda-chip-auto__opt--active {
  color: #fafafa;
  background: rgba(228, 255, 84, 0.08);
}

@keyframes nuda-dropin {
  from { opacity: 0; transform: translateY(-4px); }
  to   { opacity: 1; transform: translateY(0); }
}

@media (prefers-reduced-motion: reduce) {
  .nuda-chip-auto__list { animation: none; }
}

