/* Removable Filter Chips Bar
   Shows applied filters with one-click removal + clear all.
   Customize: --bar-surface, --bar-danger */

.nuda-chip-filterbar {
  --bar-danger: #fca5a5;
  display: flex;
  flex-wrap: wrap;
  align-items: center;
  gap: 6px;
  padding: 8px 10px;
  background: #0c0c10;
  border: 1px solid rgba(255, 255, 255, 0.06);
  border-radius: 10px;
  font: 500 12px/1 ui-sans-serif, system-ui, sans-serif;
}

.nuda-chip-filterbar__label {
  font-size: 11px;
  color: #63636e;
  margin-right: 2px;
}

.nuda-chip-filterbar__chip {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  padding: 4px 4px 4px 10px;
  color: #fafafa;
  background: #111114;
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 99px;
}

.nuda-chip-filterbar__x {
  display: inline-grid;
  place-items: center;
  width: 16px;
  height: 16px;
  font-size: 13px;
  color: #a0a0a8;
  background: transparent;
  border: 0;
  border-radius: 99px;
  cursor: pointer;
  transition: background 0.15s, color 0.15s;
}

.nuda-chip-filterbar__x:hover {
  color: var(--bar-danger);
  background: rgba(239, 68, 68, 0.12);
}

.nuda-chip-filterbar__clear {
  margin-left: auto;
  padding: 4px 10px;
  font: 600 11px/1 ui-sans-serif, system-ui, sans-serif;
  color: #a0a0a8;
  background: transparent;
  border: 0;
  border-radius: 99px;
  cursor: pointer;
  transition: color 0.2s, background 0.2s;
}

.nuda-chip-filterbar__clear:hover {
  color: #fafafa;
  background: rgba(255, 255, 255, 0.06);
}

/* Chip With Avatar
   Mention-style chip with a leading avatar circle.
   Customize: avatar gradient inline or per-variant */

.nuda-chip-avatar {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
}

.nuda-chip-avatar__chip {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  padding: 3px 6px 3px 3px;
  font: 500 12px/1 ui-sans-serif, system-ui, sans-serif;
  color: #fafafa;
  background: #111114;
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 99px;
  transition: border-color 0.2s;
}

.nuda-chip-avatar__chip:hover {
  border-color: rgba(255, 255, 255, 0.16);
}

.nuda-chip-avatar__img {
  display: inline-grid;
  place-items: center;
  width: 20px;
  height: 20px;
  font: 700 9px/1 ui-sans-serif, system-ui, sans-serif;
  color: #09090b;
  border-radius: 99px;
  letter-spacing: 0.02em;
}

.nuda-chip-avatar__x {
  display: inline-grid;
  place-items: center;
  width: 16px;
  height: 16px;
  font-size: 12px;
  color: #a0a0a8;
  background: transparent;
  border: 0;
  border-radius: 99px;
  cursor: pointer;
  transition: background 0.15s, color 0.15s;
}

.nuda-chip-avatar__x:hover {
  color: #fafafa;
  background: rgba(255, 255, 255, 0.08);
}

@media (prefers-reduced-motion: reduce) {
  .nuda-chip-avatar__chip { transition: none; }
}

/* Animated Chip Pop-in
   Springy scale/fade-in for newly added chips.
   Customize: --pop-duration, --pop-easing */

.nuda-chip-pop {
  --pop-duration: 0.35s;
  --pop-easing: cubic-bezier(0.34, 1.56, 0.64, 1);
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
}

.nuda-chip-pop__chip {
  display: inline-flex;
  align-items: center;
  padding: 4px 10px;
  font: 500 12px/1 ui-sans-serif, system-ui, sans-serif;
  color: #fafafa;
  background: #111114;
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 99px;
  opacity: 0;
  transform: scale(0.4);
  animation: nuda-chip-pop var(--pop-duration) var(--pop-easing) forwards;
}

@keyframes nuda-chip-pop {
  0%   { opacity: 0; transform: scale(0.4) translateY(8px); }
  100% { opacity: 1; transform: scale(1) translateY(0); }
}

@media (prefers-reduced-motion: reduce) {
  .nuda-chip-pop__chip {
    animation: none;
    opacity: 1;
    transform: none;
  }
}

/* Chip Validation Error
   Red border + shake when input is invalid.
   Customize: --err-color */

.nuda-chip-error {
  --err-color: #fca5a5;
  width: 100%;
  max-width: 300px;
  font: 500 12px/1 ui-sans-serif, system-ui, sans-serif;
  color: #fafafa;
}

.nuda-chip-error__field {
  display: flex;
  flex-wrap: wrap;
  align-items: center;
  gap: 6px;
  padding: 8px;
  background: #0c0c10;
  border: 1px solid var(--err-color);
  border-radius: 10px;
  animation: nuda-chip-shake 0.4s ease;
}

.nuda-chip-error__chip {
  padding: 4px 10px;
  color: #fafafa;
  background: #111114;
  border: 1px solid rgba(255, 255, 255, 0.08);
