/* Status Bar Mock
   iOS-style status row with time, signal, wifi and battery.
   Customize: --sb-accent */

.nuda-statusbar {
  --sb-accent: #e4ff54;
  position: relative;
  display: flex;
  align-items: center;
  justify-content: space-between;
  width: 280px;
  height: 40px;
  padding: 0 18px;
  background: #09090b;
  border: 1px solid rgba(255, 255, 255, 0.06);
  border-radius: 18px;
  font-family: system-ui;
  color: #fafafa;
}

.nuda-statusbar__time { font: 700 14px/1 system-ui; letter-spacing: -0.2px; }

.nuda-statusbar__notch {
  position: absolute;
  top: 0;
  left: 50%;
  transform: translateX(-50%);
  width: 80px;
  height: 18px;
  background: #000;
  border-radius: 0 0 14px 14px;
}

.nuda-statusbar__right {
  display: flex;
  align-items: center;
  gap: 6px;
}

.nuda-statusbar__signal {
  display: flex;
  align-items: flex-end;
  gap: 1.5px;
  height: 10px;
}

.nuda-statusbar__signal span {
  width: 2.5px;
  background: #fafafa;
  border-radius: 1px;
}

.nuda-statusbar__signal span:nth-child(1) { height: 30%; }
.nuda-statusbar__signal span:nth-child(2) { height: 55%; }
.nuda-statusbar__signal span:nth-child(3) { height: 80%; }
.nuda-statusbar__signal span:nth-child(4) { height: 100%; }

.nuda-statusbar__bat {
  position: relative;
  width: 22px;
  height: 10px;
  border: 1px solid rgba(255, 255, 255, 0.6);
  border-radius: 3px;
  padding: 1px;
}

.nuda-statusbar__bat::after {
  content: "";
  position: absolute;
  top: 50%;
  right: -3px;
  transform: translateY(-50%);
  width: 1.5px;
  height: 4px;
  background: rgba(255, 255, 255, 0.6);
  border-radius: 1px;
}

.nuda-statusbar__bat-fill {
  height: 100%;
  width: 78%;
  background: var(--sb-accent);
  border-radius: 1px;
  animation: nuda-bat-breathe 3s ease-in-out infinite;
}

@keyframes nuda-bat-breathe {
  0%, 100% { opacity: 0.85; }
  50% { opacity: 1; }
}

@media (prefers-reduced-motion: reduce) {
  .nuda-statusbar__bat-fill { animation: none; }
}

