.nuda-err-retry {
  display: flex;
  flex-direction: column;
  padding: 16px;
  background: #141414;
  border: 1px solid rgba(255,255,255,.08);
  border-radius: 14px;
  width: 100%;
  max-width: 260px;
  gap: 12px;
  font-family: ui-sans-serif,system-ui;
}

.nuda-err-retry__header {
  display: flex;
  align-items: center;
  gap: 8px;
}

.nuda-err-retry__pulse {
  position: relative;
  width: 8px;
  height: 8px;
  flex-shrink: 0;
}

.nuda-err-retry__pulse::before {
  content: "";
  position: absolute;
  inset: 0;
  border-radius: 50%;
  background: #ff6b6b;
}

.nuda-err-retry__pulse::after {
  content: "";
  position: absolute;
  inset: -3px;
  border-radius: 50%;
  border: 1.5px solid #ff6b6b;
  animation: _nuda-errretry-pulse 1.6s ease-out infinite;
}

.nuda-err-retry__status {
  color: #cfcfcf;
  font-size: 12px;
  font-weight: 600;
}

.nuda-err-retry__details {
  display: flex;
  flex-direction: column;
  gap: 4px;
  padding: 10px;
  background: #1a1a1a;
  border-radius: 8px;
  border: 1px solid rgba(255,255,255,.05);
}

.nuda-err-retry__row {
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.nuda-err-retry__key {
  font-size: 10px;
  color: #555;
}

.nuda-err-retry__val {
  font-size: 10px;
  color: #888;
  font-family: ui-monospace,monospace;
}

.nuda-err-retry__val--err {
  color: #ff6b6b;
}

.nuda-err-retry__progress {
  height: 3px;
  background: rgba(255,255,255,.06);
  border-radius: 2px;
  overflow: hidden;
}

.nuda-err-retry__progress-fill {
  height: 100%;
  width: 60%;
  background: linear-gradient(90deg,#ff6b6b,#ff9b6b);
  border-radius: 2px;
  animation: _nuda-errretry-prog 8s linear both;
}

.nuda-err-retry__btn {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 6px;
  padding: 8px 14px;
  background: rgba(228,255,84,.08);
  color: #e4ff54;
  border: 1px solid rgba(228,255,84,.25);
  border-radius: 8px;
  font-size: 11px;
  font-weight: 600;
  cursor: pointer;
  transition: background .2s;
}

.nuda-err-retry__btn svg {
  width: 13px;
  height: 13px;
}

.nuda-err-retry__btn:hover {
  background: rgba(228,255,84,.16);
}

@keyframes _nuda-errretry-pulse {
  0% {
    transform: scale(1);
    opacity: .8;
  }
  100% {
    transform: scale(2.5);
    opacity: 0;
  }
}

@keyframes _nuda-errretry-prog {
  from {
    width: 0;
  }
  to {
    width: 60%;
  }
}

@media (prefers-reduced-motion:reduce) {
  .nuda-err-retry__pulse::after {
    animation: none;
  }
  .nuda-err-retry__progress-fill {
    animation: none;
  }
}

